-- Poems batch 314
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('df063b43-f69e-4234-8cbb-382fb08e6350','次韻安止春詞十首  其二','郭祥正','宋','宋诗','song-poetry','','[]','池塘新水碧泱泱，楊柳牽風綠線長。',32,'全唐诗/poet.song.43000.json','["池塘新水碧泱泱，楊柳牽風綠線長。", "已信形骸隨野馬，不思功業到巖廊。"]'),
('50bafd29-ee37-47a8-98e8-60540472a437','次韻安止春詞十首  其三','郭祥正','宋','宋诗','song-poetry','','[]','一聽春聲只自悲，山山相應鷓鴣啼。',32,'全唐诗/poet.song.43000.json','["一聽春聲只自悲，山山相應鷓鴣啼。", "却尋花島看花處，水上紅雲數片低。"]'),
('9a3907a5-de20-4acd-b09f-aa64cbb813cc','次韻安止春詞十首  其四','郭祥正','宋','宋诗','song-poetry','','[]','一杯濁酒覽春光，人世紛紛任短長。',32,'全唐诗/poet.song.43000.json','["一杯濁酒覽春光，人世紛紛任短長。", "細草自勻新歲綠，落梅猶散去年香。"]'),
('bd5a93c3-bb65-4166-952d-b66047e03726','次韻安止春詞十首  其五','郭祥正','宋','宋诗','song-poetry','','[]','雲影暮時鶯語低，花枝深處蝶魂迷。',32,'全唐诗/poet.song.43000.json','["雲影暮時鶯語低，花枝深處蝶魂迷。", "青樓不遠要佳客，錦纜牽船更向西。"]'),
('0207a69c-09dc-4f22-b13a-189ca9b72db5','次韻安止春詞十首  其六','郭祥正','宋','宋诗','song-poetry','','[]','草色葱蒼遍冢丘，花枝紅白倚城頭。',32,'全唐诗/poet.song.43000.json','["草色葱蒼遍冢丘，花枝紅白倚城頭。", "憑誰喚取王摩詰，畫出傷春一段愁。"]'),
('488205af-2dff-4396-8c40-ef34f3f4de37','次韻安止春詞十首  其七','郭祥正','宋','宋诗','song-poetry','','[]','茸茸綠芷香先吐，點點緋桃萼半敷。',32,'全唐诗/poet.song.43000.json','["茸茸綠芷香先吐，點點緋桃萼半敷。", "却憶江南江水滿，一條晴練接天鋪。"]'),
('ffcfb0cf-5b82-4374-ac5b-57bcfcc1a713','次韻安止春詞十首  其八','郭祥正','宋','宋诗','song-poetry','','[]','數行徙倚迎風柳，幾樹參差照水花。',32,'全唐诗/poet.song.43000.json','["數行徙倚迎風柳，幾樹參差照水花。", "最惜去年梁上燕，會隨春色到貧家。"]'),
('27f3b0c1-3abd-4b41-bdb0-72edda798d0f','次韻安止春詞十首  其九','郭祥正','宋','宋诗','song-poetry','','[]','青春又送一年來，不道春霜兩鬢催。',32,'全唐诗/poet.song.43000.json','["青春又送一年來，不道春霜兩鬢催。", "春淺春深春自老，且將懷抱向春開。"]'),
('438f9d32-85a7-4952-9a3a-ff722d51d53c','次韻安止春詞十首  其一○','郭祥正','宋','宋诗','song-poetry','','[]','花開遊女鬭明妝，馬上誰憐白首郎。',32,'全唐诗/poet.song.43000.json','["花開遊女鬭明妝，馬上誰憐白首郎。", "社叟從今歌擊壤，詩人不用歎繁霜。"]'),
('f9d7a85e-a835-4af0-983d-bd701f30cea6','又和  其一','郭祥正','宋','宋诗','song-poetry','','[]','關關禽語弄輕風，决决田流上下通。',32,'全唐诗/poet.song.43000.json','["關關禽語弄輕風，决决田流上下通。", "行過小橋穿竹塢，山花時見一枝紅。"]'),
('87344033-2fab-4a10-8853-c881f54b88cf','又和  其二','郭祥正','宋','宋诗','song-poetry','','[]','無數幽花覆水香，一條輕素引烟長。',32,'全唐诗/poet.song.43000.json','["無數幽花覆水香，一條輕素引烟長。", "客情春恨都諳盡，把筆題詩獨遶廊。"]'),
('5692a74f-8737-454e-a651-7cd3121cdc37','又和  其三','郭祥正','宋','宋诗','song-poetry','','[]','新鶯求友出林飛，穀穀催耕着處啼。',32,'全唐诗/poet.song.43000.json','["新鶯求友出林飛，穀穀催耕着處啼。", "野渡無人芳草碧，前山欲雨暮雲低。"]'),
('d5b7bccc-7ceb-4f1b-a1f1-1e60973042c6','又和  其四','郭祥正','宋','宋诗','song-poetry','','[]','斜日會扶嵐氣暖，好風能送笛聲長。',32,'全唐诗/poet.song.43000.json','["斜日會扶嵐氣暖，好風能送笛聲長。", "倦投芳草人人醉，流出殘花澗澗香。"]'),
('9739c35f-0c22-467c-a0ff-c4c33080ea99','又和  其五','郭祥正','宋','宋诗','song-poetry','','[]','花枝自倚青春笑，客恨須憑濁酒迷。',32,'全唐诗/poet.song.43000.json','["花枝自倚青春笑，客恨須憑濁酒迷。", "望斷夕陽無問處，只今應照故園西。"]'),
('f78332d9-1207-47e2-877b-e0eb20382e14','又和  其六','郭祥正','宋','宋诗','song-poetry','','[]','春事須臾不可留，花枝爭上少年頭。',32,'全唐诗/poet.song.43000.json','["春事須臾不可留，花枝爭上少年頭。", "欲乘舴艋凌波去，何處佳人似莫愁。"]'),
('02270851-6a6e-4e83-9a63-7a4c9f2c7352','又和  其七','郭祥正','宋','宋诗','song-poetry','','[]','花笑鶯啼酒可沽，山光水影淡烟敷。',32,'全唐诗/poet.song.43000.json','["花笑鶯啼酒可沽，山光水影淡烟敷。", "垂楊欲礙春歸路，更放輕綿匝地鋪。"]'),
('6c4aa287-6704-4e84-9a7d-810cc2e13544','又和  其八','郭祥正','宋','宋诗','song-poetry','','[]','營巢新燕驚垂幙，採蕊嬌蜂避落花。',32,'全唐诗/poet.song.43000.json','["營巢新燕驚垂幙，採蕊嬌蜂避落花。", "着處風光濃似酒，行人何事苦思家。"]'),
('5c6749a0-a68a-49cc-9c08-9ebbcc3fca29','又和  其九','郭祥正','宋','宋诗','song-poetry','','[]','尋春眷眷惜春回，四序相新一氣催。',32,'全唐诗/poet.song.43000.json','["尋春眷眷惜春回，四序相新一氣催。", "桃李無言貪結子，野棠閒淡爲誰開。"]'),
('f8a2d9d1-6400-4fe7-9c72-a90450826039','又和  其一○','郭祥正','宋','宋诗','song-poetry','','[]','盈筐鬭草紅裙女，嚲袖香毬白面郎。',32,'全唐诗/poet.song.43000.json','["盈筐鬭草紅裙女，嚲袖香毬白面郎。", "歸去不嫌清夜冷，李花枝上月凝霜。"]'),
('f146ff47-0826-4678-af6f-fbd1c5574e98','訪隱者','郭祥正','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u751f\u6d3b", "\u9690\u5c45"]','一徑沿崖踏蒼壁，半塢寒雲抱泉石。',32,'全唐诗/poet.song.43000.json','["一徑沿崖踏蒼壁，半塢寒雲抱泉石。", "山翁酒熟不出門，殘花滿地無行跡。"]'),
('a271057f-9f72-4cbe-bdb6-4d8bd4ad90f2','題蘇紫霞選仙集後二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','六博成書意在仙，每要佳客造玄天。',32,'全唐诗/poet.song.43000.json','["六博成書意在仙，每要佳客造玄天。", "不由功行渾由彩，一局升沉亦偶然。"]'),
('42e5e248-6251-42fc-bac9-e7aff34a1955','題蘇紫霞選仙集後二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','知君本是紫霞仙，夢入瑤池泛酒船。',32,'全唐诗/poet.song.43000.json','["知君本是紫霞仙，夢入瑤池泛酒船。", "功行已成真馭遠，却嗟塵世閲遺篇。"]'),
('e3c65991-15e4-457c-8796-4e3591218a49','謝陳昌國惠酒二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','平生愛酒養天真，醉眼聊爲混俗人。',32,'全唐诗/poet.song.43000.json','["平生愛酒養天真，醉眼聊爲混俗人。", "玉斗貯來紅浪溢，感君添我海中春。"]'),
('44f39704-93c7-4d2f-8ed4-23ec7cb4f965','謝陳昌國惠酒二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','欲瀉瓊漿洗我憂，玉壺分送不知休。',32,'全唐诗/poet.song.43000.json','["欲瀉瓊漿洗我憂，玉壺分送不知休。", "醉來一覺還鄉夢，看盡江南二十州。"]'),
('0fe4f70e-e037-4bd8-8735-4849f30c446d','半漳亭','郭祥正','宋','宋诗','song-poetry','','[]','飛簷赤白壓層丘，見盡漳南一半州。',32,'全唐诗/poet.song.43000.json','["飛簷赤白壓層丘，見盡漳南一半州。", "倦步且來消午暑，穿雲此去徹鼇頭。"]'),
('206ab56f-5fd6-48e1-a986-0124b1f073e7','城東延福禪院避暑五首  其一','郭祥正','宋','宋诗','song-poetry','','[]','榕陰缺處見西山，步遍牆陰落照間。',32,'全唐诗/poet.song.43000.json','["榕陰缺處見西山，步遍牆陰落照間。", "誰信史君無一事，只知終日與僧閒。"]'),
('857c1d61-c3fd-4f1e-a37a-fbfa961ea711','城東延福禪院避暑五首  其二','郭祥正','宋','宋诗','song-poetry','','[]','暑雨霏微濕翠嵐，共投蕭寺解塵驂。',32,'全唐诗/poet.song.43000.json','["暑雨霏微濕翠嵐，共投蕭寺解塵驂。", "黄粱初熟鱘羮美，恰稱嵇家七不堪。"]'),
('47367748-9e5d-49a0-91af-0440b7f0da9d','城東延福禪院避暑五首  其三','郭祥正','宋','宋诗','song-poetry','','[]','急手輕調北苑茶，未收雲霧乳成花。',32,'全唐诗/poet.song.43000.json','["急手輕調北苑茶，未收雲霧乳成花。", "靈襟習習清風起，歸夢遙知不到家。"]'),
('f09c05fc-35bb-44f0-a040-b7e30d065364','城東延福禪院避暑五首  其四','郭祥正','宋','宋诗','song-poetry','','[]','碧玉枝柯柑橘林，開花結子未成金。',32,'全唐诗/poet.song.43000.json','["碧玉枝柯柑橘林，開花結子未成金。", "何當爛熟經霜露，更約提壺一訪尋。"]'),
('72b602fe-09b1-4a6b-a730-3a89e6a3043c','城東延福禪院避暑五首  其五','郭祥正','宋','宋诗','song-poetry','','[]','隔澗人家通小橋，家家沽酒可相邀。',32,'全唐诗/poet.song.43000.json','["隔澗人家通小橋，家家沽酒可相邀。", "深沈榕葉遮煩日，浩蕩風頭駕晚潮。"]'),
('a0955f92-8921-4dc2-b405-93f96c3edf85','荔枝二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','枝條相軋碧雲濃，襯出驪珠落照中。',32,'全唐诗/poet.song.43000.json','["枝條相軋碧雲濃，襯出驪珠落照中。", "未說甘香消酷熱，且看纖手擘輕紅。"]'),
('a4446f31-1a65-4266-b88a-a09f5f861f77','荔枝二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','暑館風沈睡眼醒，荔枝新熟暗香生。',32,'全唐诗/poet.song.43000.json','["暑館風沈睡眼醒，荔枝新熟暗香生。", "玉纖爲剥紅綃顆，甘露初凝濕水晶。"]'),
('41287b84-79ae-4d03-91c3-0613ec9a2c90','寄資深承事行營二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','縱横才略領千兵，鵰鶚羣飛戰艦輕。',32,'全唐诗/poet.song.43000.json','["縱横才略領千兵，鵰鶚羣飛戰艦輕。", "海浪掀天須破賊，始知名將是儒生。"]'),
('ed61234d-2ba8-4c56-b1b8-c8f04387ac0c','寄資深承事行營二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','黄梅欲落雨霏霏，想過重岡濕戰衣。',32,'全唐诗/poet.song.43000.json','["黄梅欲落雨霏霏，想過重岡濕戰衣。", "破賊有期先可喜，裂雲簫鼓待君歸。"]'),
('184e48e2-b95f-4215-944e-169e8bd17dcb','凈惠寺清軒二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','枯笻壞衲老清時，萬事紛紛久不知。',32,'全唐诗/poet.song.43000.json','["枯笻壞衲老清時，萬事紛紛久不知。", "隔屋荷香消午暑，紅薇花影在深池。"]'),
('57196220-16ff-467e-a49d-7a2ea2e2914d','凈惠寺清軒二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','一軒瀟灑靜無塵，萬柄荷花别是春。',32,'全唐诗/poet.song.43000.json','["一軒瀟灑靜無塵，萬柄荷花别是春。", "莫道南州無北客，壁間猶對洛陽人。"]'),
('97f5a6f3-010a-4d71-a680-f76a9dd31ac3','七夕不飲','郭祥正','宋','宋诗','song-poetry','','[]','明河初月靜涓涓，樓閣簾開鬭管弦。',32,'全唐诗/poet.song.43000.json','["明河初月靜涓涓，樓閣簾開鬭管弦。", "不飲一樽當此夕，我心于巧久無緣。"]'),
('f8a2f70a-df2d-4f1e-8b12-af161f4b6be7','和子中修撰石盆題壁二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','沉沉石室亂雲間，萬事都忘只有閒。',32,'全唐诗/poet.song.43000.json','["沉沉石室亂雲間，萬事都忘只有閒。", "暫輟玉堂揮翰手，一時吟遍謝家山。"]'),
('202b6e12-a543-4b69-a910-8d2a083614e7','和子中修撰石盆題壁二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','青山重複路逶迤，雖近州城俗客稀。',32,'全唐诗/poet.song.43000.json','["青山重複路逶迤，雖近州城俗客稀。", "只有史君頻得句，時時吟袖带雲歸。"]'),
('4f928c1b-2358-4a30-9559-aac70357f92e','和子中忘歸軒','郭祥正','宋','宋诗','song-poetry','','[]','忘歸歸去盡强名，山鳥山花任送迎。',32,'全唐诗/poet.song.43000.json','["忘歸歸去盡强名，山鳥山花任送迎。", "未信史君長戀此，馬頭將逐詔書行。"]'),
('b09bfe37-cb21-4724-ad94-0f4b0ede3206','和子中修撰石盆轉輪藏','郭祥正','宋','宋诗','song-poetry','','[]','棲函藏軸一輪中，種種難名寶網叢。',32,'全唐诗/poet.song.43000.json','["棲函藏軸一輪中，種種難名寶網叢。", "莫道石盆無大地，只今成就聖王宫。"]'),
('44a51aaf-6058-4c37-a4af-fc23f702b8e0','弔聖俞墳','郭祥正','宋','宋诗','song-poetry','','[]','平生懷抱只君知，想見音容涕泗垂。',32,'全唐诗/poet.song.43000.json','["平生懷抱只君知，想見音容涕泗垂。", "宅舍已荒兒女散，孤墳秋草自離離。"]'),
('65033a6e-05d4-4eea-b621-6cdfbd3ced93','太平天慶觀題壁五首  其一','郭祥正','宋','宋诗','song-poetry','','[]','縹緲朱樓浮絳烟，瀰漫碧酒汎金船。',32,'全唐诗/poet.song.43000.json','["縹緲朱樓浮絳烟，瀰漫碧酒汎金船。", "瓊花滿樹春長在，知是人間換幾年。"]'),
('ef839fbf-0da5-4edc-9998-a13fd5ecfd1c','太平天慶觀題壁五首  其二','郭祥正','宋','宋诗','song-poetry','','[]','琳宮緩步獨移時，世事紛紛不復知。',32,'全唐诗/poet.song.43000.json','["琳宮緩步獨移時，世事紛紛不復知。", "且看滿庭松上雨，碧瑤幢節覆青絲。"]'),
('e0bcac19-792a-47cc-87b4-7643704f5da4','太平天慶觀題壁五首  其三','郭祥正','宋','宋诗','song-poetry','','[]','一枰棋散復持盃，却遶長廊步懶回。',32,'全唐诗/poet.song.43000.json','["一枰棋散復持盃，却遶長廊步懶回。", "且看滿庭松下月，斷金斜玉間蒼苔。"]'),
('c67280c3-a546-4b78-adf0-f0d27c759ef0','太平天慶觀題壁五首  其四','郭祥正','宋','宋诗','song-poetry','','[]','風吹雲雨霽，入門松檜香。',24,'全唐诗/poet.song.43000.json','["風吹雲雨霽，入門松檜香。", "何處有煩暑，心官自清凉。"]'),
