('0e75ebb3-8ae3-477b-987e-ea0756f5ee49','山居絕句六首 秋','郭祥正','宋','宋诗','song-poetry','','[]','有酒看雲飲，無書寄雁回。',24,'全唐诗/poet.song.43000.json','["有酒看雲飲，無書寄雁回。", "數蛩鳴敗草，一葉落青苔。"]'),
('6a7f7aed-3d8e-4f63-9010-192590c24d58','山居絕句六首 冬','郭祥正','宋','宋诗','song-poetry','','[]','黄昏鳥飛絕，夜半猿啼切。',24,'全唐诗/poet.song.43000.json','["黄昏鳥飛絕，夜半猿啼切。", "紙帳寒不眠，開門見猛雪。"]'),
('eb61fd51-92f3-4883-8ae8-164940935f51','桃源行寄張兵部','郭祥正','宋','宋诗','song-poetry','','[]','武陵溪上青雲暮，昔人傳有桃源路。',145,'全唐诗/poet.song.43000.json','["武陵溪上青雲暮，昔人傳有桃源路。", "時見落花隨水流，咫尺神仙杳難遇。", "神仙有無何可量，但愛武陵山水強。", "松煙竹霧水村暗，鳥啼猿嘯花雨香。", "車輪不來塵坌絕，日月自與乾坤長。", "聞君取身欲長往，禾熟良田給春釀。", "陶然一醉萬事休，還我天真了無象。", "生胡爲榮死奚慼，爲笑紛紛避秦客。", "一身重要歲何足論，更向漁家寄消息。"]'),
('870eab16-a7dd-4f8b-8f58-f565cc0e6970','廣福禪寺','郭祥正','宋','宋诗','song-poetry','','[]','寺與人寰隔，西軒更遠瞻。',48,'全唐诗/poet.song.43000.json','["寺與人寰隔，西軒更遠瞻。", "雲煙生卷箔，星斗半垂簷。", "山對眉雙碧，江空鏡一匲。", "旅魂招不盡，愁向酒中添。"]'),
('f6e7ca0d-19a4-48eb-820a-32c5687212fa','馬仁山','郭祥正','宋','宋诗','song-poetry','','[]','崔嵬山下石，如馬亦如人。',48,'全唐诗/poet.song.43000.json','["崔嵬山下石，如馬亦如人。", "玉老龍蛇護，菴空歲月新。", "訪僧非舊識，覽壁但傷神。", "更恨無流水，難尋洞裏春。"]'),
('ecc5b043-d585-4b2a-9b5c-d0a3de911e4e','治平三年秋七月當塗郭功父招無爲楊次公會於環峰時五雲叟陳德孚以詩寄吾二人因聯句酬之','郭祥正','宋','宋诗','song-poetry','','[]','空山坐寥落，疋馬邀俊哲。',288,'全唐诗/poet.song.43000.json','["空山坐寥落，疋馬邀俊哲。", "入門肆高談，清風掃煩熱。", "憶昔治平年，姑熟溪上别。", "歲時激箭急，倐忽三十月。", "讀書非少銳，欲論先卷舌。", "歸田殊未成，累累逐羈紲。", "孰謂趙魏老，不能佐滕薛。", "由來歲大寒，松柏見孤節。", "朋心久愈至，忠規補殘缺。", "兒童喜父執，飣餖成羅列。", "壺有玉泉酒，庖有冰濃鱉。", "野芡剖珠璣，秋瓜咀霜雪。", "新粳刈且舂，香炊軟三淅。", "放匕聊醉飽，百憂旋磨滅。", "升平擊堯壤，險怪探禹穴。", "吐氣直虹霓，落筆淬金鐵。", "詞源河漢翻，俯視隄防決。", "文章貴天成，追琢譏竄竊。", "抵掌萬古事，高下争螘垤。", "挹酌華陽水，蕩滌塵土咽。", "吾心了何染，本理忘巧拙。", "聖賢久不作，情僞愈分别。", "竹陰卧片石，浩歌聲欲闋。", "山童倐及門，喜音屈高潔。"]'),
('5a8b1ffd-b3a2-40be-a638-5e8faaf2d7dc','寄東坡','郭祥正','宋','宋诗','song-poetry','','[]','平生才力信瑰奇，今在窮荒豈易歸。',32,'全唐诗/poet.song.43000.json','["平生才力信瑰奇，今在窮荒豈易歸。", "正似雪林枝上畫，羽翰雖好不能飛。"]'),
('19d5807a-6ca7-479b-ad69-90e553ab0748','用前韻寄東坡','郭祥正','宋','宋诗','song-poetry','','[]','秋霜春雨不同時，萬里今從海外歸。',32,'全唐诗/poet.song.43000.json','["秋霜春雨不同時，萬里今從海外歸。", "已出網羅毛羽在，卻尋雲跡帖天飛。"]'),
('643c9c4b-0959-4993-9617-c9c79f6170c1','詩一首','郭祥正','宋','宋诗','song-poetry','','[]','七十餘歲老朝郎，曾向元祐說文章。',32,'全唐诗/poet.song.43000.json','["七十餘歲老朝郎，曾向元祐說文章。", "如今白首歸田後，卻與楊姝洗杖瘡。"]'),
('9e963e56-251e-4680-9f0a-0c43540d1464','過蕪湖縣','郭祥正','宋','宋诗','song-poetry','','[]','詩中長愛杜池州，說著蕪城是勝遊。',32,'全唐诗/poet.song.43000.json','["詩中長愛杜池州，說著蕪城是勝遊。", "山掩縣城當北起，渡衝官道向南流。"]'),
('185522d5-251a-4888-899b-19b4e6c32348','重來桐城','郭祥正','宋','宋诗','song-poetry','','[]','碧水蒼山照眼青，始知朱邑愛桐城。',32,'全唐诗/poet.song.43000.json','["碧水蒼山照眼青，始知朱邑愛桐城。", "重來二十三年後，猶有斯民眷眷情。"]'),
('92ce098c-8da7-4972-a7e5-9abb72678e02','臨漳臺','郭祥正','宋','宋诗','song-poetry','','[]','道邊松，大義渡至漳城城東，問誰植之我蔡公。',53,'全唐诗/poet.song.43000.json','["道邊松，大義渡至漳城城東，問誰植之我蔡公。", "歲久廣陰如雲濃，甘棠蔽芾安可同。", "六月行人不知暑，千古萬古揚清風。"]'),
('27a3e79d-ae03-4d6a-b2ad-7411de2795a9','寄東坡','郭祥正','宋','宋诗','song-poetry','','[]','君恩浩蕩似陽春，海外移來住海濱。',32,'全唐诗/poet.song.43000.json','["君恩浩蕩似陽春，海外移來住海濱。", "莫向沙邊弄明月，夜深無數採珠人。"]'),
('2301df12-3ee7-4962-b427-7c17b5162ec7','五祖山拈香','郭祥正','宋','宋诗','song-poetry','','[]','白雲巖畔舊相逢，往日今朝事不同。',32,'全唐诗/poet.song.43000.json','["白雲巖畔舊相逢，往日今朝事不同。", "夜靜水寒魚不食，一爐香散白蓮峰。"]'),
('480cd479-3d31-4cfb-985b-2bbd35177255','雲居山拈香','郭祥正','宋','宋诗','song-poetry','','[]','覺地相逢一何早，鶻臭布衫今脫了。',32,'全唐诗/poet.song.43000.json','["覺地相逢一何早，鶻臭布衫今脫了。", "要識雲居一句玄，珍重後園驢喫草。"]'),
('54ed27bb-c321-4656-9a9a-e060e3ced1bb','西方院','郭祥正','宋','宋诗','song-poetry','','[]','欲出西方更少留，雲泉都占一巖幽。',32,'全唐诗/poet.song.43000.json','["欲出西方更少留，雲泉都占一巖幽。", "勸僧洗凈閣前竹，要看南山十里秋。"]'),
('c2ca6be6-dfea-4595-bf2a-6424e36004b6','羅漢院','郭祥正','宋','宋诗','song-poetry','','[]','蒼松夾徑二十丈，碧殿藏雲五百尊。',32,'全唐诗/poet.song.43000.json','["蒼松夾徑二十丈，碧殿藏雲五百尊。", "金鐘散響撼星斗，衆燈續焰移朝昏。"]'),
('014d90b4-d67c-4af9-ad0c-a86a89f51285','和郡守西峰院','郭祥正','宋','宋诗','song-poetry','','[]','寺占西山第一峰，與君高步躡雲蹤。',32,'全唐诗/poet.song.43000.json','["寺占西山第一峰，與君高步躡雲蹤。", "西風吹盡霜林葉，放出亭亭十丈松。"]'),
('9ed7111c-b560-42f6-ac37-3d72450041b8','詩一首','郭祥正','宋','宋诗','song-poetry','','[]','枯腸得酒芒角出，肝肺槎牙生竹石。',96,'全唐诗/poet.song.43000.json','["枯腸得酒芒角出，肝肺槎牙生竹石。", "森然欲作不可回，寫向君家雪色壁。", "平生好詩仍好畫，書墻涴壁長遭罵。", "不嗔不罵喜有餘，世間誰復如君者。", "一雙銅劍秋水光，兩首新詩爭劍芒。", "劍在床頭詩在手，不知誰作蛟龍吼。"]'),
('65c8b692-9404-47ad-a2a7-f1f56cee096a','高明軒','郭祥正','宋','宋诗','song-poetry','','[]','周也漳南釋，開軒瞰漳濱。',24,'全唐诗/poet.song.43000.json','["周也漳南釋，開軒瞰漳濱。", "山光並水色，一物長清新。"]'),
('1b796418-249a-4f26-badf-1b2785c9a7ed','南安巖','郭祥正','宋','宋诗','song-poetry','','[]','汀梅之間山萬重，南安巖竇何玲瓏。',64,'全唐诗/poet.song.43000.json','["汀梅之間山萬重，南安巖竇何玲瓏。", "青葱屹立敞四壁，巧匠縮手難爲工。", "嗟予俗縛未能往，願得結草與巖松。", "遂登彼岸達正覺，月落巖下松生風。"]'),
('f26291a9-e496-4594-acac-71314f20b937','玩鞭亭','郭祥正','宋','宋诗','song-poetry','','[]','平蕪春靜水彌天，甚壓危城駕廣椽。',64,'全唐诗/poet.song.43000.json','["平蕪春靜水彌天，甚壓危城駕廣椽。", "駿馬豈能追晚日，將軍莫悔玩遺鞭。", "高才共倚新亭賦，逸翰重尋舊曲鐫。", "千古英雄衹如此，黄花修竹付幽禪。"]'),
('2cd0beb8-3874-443c-9040-02247889a68a','句  其一','郭祥正','宋','宋诗','song-poetry','','[]','明月隨人渡流水。',8,'全唐诗/poet.song.43000.json','["明月隨人渡流水。"]'),
('a52c1677-1780-4522-9e49-1ffd37404234','句  其二','郭祥正','宋','宋诗','song-poetry','','[]','欲尋鐵索排橋處，只有楊花慘客愁。',16,'全唐诗/poet.song.43000.json','["欲尋鐵索排橋處，只有楊花慘客愁。"]'),
('361a7a77-3817-4e25-b30e-fc462556a944','句  其三','郭祥正','宋','宋诗','song-poetry','','[]','我愛臨漳郡，地兼山海秀。',12,'全唐诗/poet.song.43000.json','["我愛臨漳郡，地兼山海秀。"]'),
('1a7b0975-4ed9-41f8-9d2f-ee06b373e014','長風吹海作寒霧，往往六月披重袍。仙魚通印勝鴞炙，荔子丹艷疑蟠桃。  其一','郭祥正','宋','宋诗','song-poetry','','[]','神仙之府名雞籠，千尋翠玉擎寒空。',32,'全唐诗/poet.song.43000.json','["神仙之府名雞籠，千尋翠玉擎寒空。", "秀色凌風入城郭，半街曉日金濛濛。"]'),
('0dd263b1-ceb0-44bb-986a-4677bcdbc899','長風吹海作寒霧，往往六月披重袍。仙魚通印勝鴞炙，荔子丹艷疑蟠桃。  其二','郭祥正','宋','宋诗','song-poetry','','[]','老鶴唳風□□□。',8,'全唐诗/poet.song.43000.json','["老鶴唳風□□□。"]'),
('01366de4-a157-4615-a239-6ddd0636ce7c','長風吹海作寒霧，往往六月披重袍。仙魚通印勝鴞炙，荔子丹艷疑蟠桃。  其三','郭祥正','宋','宋诗','song-poetry','','[]','唯欠子瞻詩。',6,'全唐诗/poet.song.43000.json','["唯欠子瞻詩。"]'),
('854e4827-6e93-4686-8d7d-5ae185c0eda7','長風吹海作寒霧，往往六月披重袍。仙魚通印勝鴞炙，荔子丹艷疑蟠桃。  其四','郭祥正','宋','宋诗','song-poetry','','[]','落日疏雲催晚景，殘花美酒送閑心。',16,'全唐诗/poet.song.43000.json','["落日疏雲催晚景，殘花美酒送閑心。"]'),
('bf1fff55-42cb-47d0-9a96-ad44039a0ea0','句','陳伯育','宋','宋诗','song-poetry','','[]','與君分兩石。',6,'全唐诗/poet.song.43000.json','["與君分兩石。"]'),
('5dca6a71-2ff9-486a-bd09-5240af8c61a5','題阮希聖東湖  其一','劉浚','宋','宋诗','song-poetry','','[]','四面溪山列畫屏，一堂新創有餘清。',32,'全唐诗/poet.song.43000.json','["四面溪山列畫屏，一堂新創有餘清。", "湖光隔斷紅塵路，疑在金鼇頂上行。"]'),
('a674f0cb-afdf-4b51-a649-6ffc3903a1d7','題阮希聖東湖  其二','劉浚','宋','宋诗','song-poetry','','[]','輪啼白日競匆匆，誰向閑中靜養蒙。',32,'全唐诗/poet.song.43000.json','["輪啼白日競匆匆，誰向閑中靜養蒙。", "珍重先生高臥處，一窻黄卷是家風。"]'),
('b9ef679b-ccac-4f25-aca5-9115d42c0a83','題阮希聖東湖  其三','劉浚','宋','宋诗','song-poetry','','[]','兩堤楊柳先春綠，十里芙蓉入夏香。',32,'全唐诗/poet.song.43000.json','["兩堤楊柳先春綠，十里芙蓉入夏香。", "自得湖山供嘯傲，會稽何獨羨知章。"]'),
('6fb18742-cc7d-4034-b209-9d25021cf21c','示寂偈','釋真如','宋','宋诗','song-poetry','','[]','昨夜三更，風雷忽作。',20,'全唐诗/poet.song.43000.json','["昨夜三更，風雷忽作。", "雲散長空，前溪月落。"]'),
('8e16fd24-42a4-46ab-87ca-caa6aa7e218e','送程給事知越州','范子奇','宋','宋诗','song-poetry','','[]','寵命光輝出九重，夕郎捧詔未央宮。',64,'全唐诗/poet.song.43000.json','["寵命光輝出九重，夕郎捧詔未央宮。", "輟從近侍優耆德，暫殿名邦撫浙東。", "道過故鄉觀晝繡，政成載路播仁風。", "豈惟越俗欣漸惠，即看延登起茂功。"]'),
('5b54a789-8e5f-4f1e-8ff8-e5b1b9ed2fb6','承諸公酌別西郊分韻賦詩得戎字','范子奇','宋','宋诗','song-poetry','','[]','西戎未解嚴，置帥濫及蒙。',120,'全唐诗/poet.song.43000.json','["西戎未解嚴，置帥濫及蒙。", "自揣非長才，尚使制羌戎。", "仰賴廟堂算，庶幾或成功。", "此行春已晚，柳絲華正紅。", "聯轡向名圃，四筵皆鉅公。", "高韻薄虹霓，笑談生清風。", "顧予實何似，有愧參其中。", "遽然千里別，不辭一樽空。", "浮雲聚與散，臨歧西復東。", "無以報禮意，舉目攀飛鴻。"]'),
('8e9ca744-d069-4ddf-b026-277ebf05e1f4','寄蘇子瞻','章惇','宋','宋诗','song-poetry','','[]','君方陽羨卜新居，我亦吳門葺舊廬。',64,'全唐诗/poet.song.43000.json','["君方陽羨卜新居，我亦吳門葺舊廬。", "身外浮雲輕土苴，眼前陳跡付籧篨。", "澗聲山色蒼雲上，花影溪光罨畫餘。", "他日扁舟約來往，共將詩酒狎樵漁。"]'),
('510899dc-df46-4805-9238-80697fc6b92f','栽桐竹','章惇','宋','宋诗','song-poetry','','[]','種竹期龍至，栽桐待鳳來。',24,'全唐诗/poet.song.43000.json','["種竹期龍至，栽桐待鳳來。", "他年跨遼海，經此一徘徊。"]'),
('b02adf61-10b6-41c9-b97c-6791136e4f0a','謝劉子先贈酒','章惇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞霄宮裏一閑人，東府西樞老舊臣。',32,'全唐诗/poet.song.43000.json','["洞霄宮裏一閑人，東府西樞老舊臣。", "多謝姑蘇賢太守，殷勤分送洞庭春。"]'),
('0cd84dcd-f621-4a92-9a0f-5b4d3b85520f','題李邦直蒙江初雪圖','章惇','宋','宋诗','song-poetry','','[]','江頭微雪北風騙，憶泊武昌舟尾時。',32,'全唐诗/poet.song.43000.json','["江頭微雪北風騙，憶泊武昌舟尾時。", "潮來浪打船欲破，擁被醉眠人不知。"]'),
('37485e57-737f-4b31-83e1-98604b633654','清明日赴玉津園宴','章惇','宋','宋诗','song-poetry','','[]','南園高讌寵師臣，盛事仍隨節物新。',64,'全唐诗/poet.song.43000.json','["南園高讌寵師臣，盛事仍隨節物新。", "勸餞滿傾仙室酒，賜花分得漢宮春。", "三朝主眷優元弼，五福天教萃一身。", "自惜雲龍如此少，因公重感涕霑巾。"]'),
('d6587a5a-ff68-4fc6-a56e-445ab2ac5e82','遊虎丘次韻','章惇','宋','宋诗','song-poetry','','[]','闔閭城外小層巒，瘦竹寒松數里間。',64,'全唐诗/poet.song.43000.json','["闔閭城外小層巒，瘦竹寒松數里間。", "並岸逢僧知近寺，入門鑿石漸登山。", "純鉤劍化空池在，幽獨詩成白日閑。", "遊客幸無官事束，何須齋舫斂昏還。"]'),
('fd3bcc21-a2eb-4b09-a8e4-5f7ad590d500','和蒲宗孟遊虎丘因書錢塘舊遊','章惇','宋','宋诗','song-poetry','','[]','傳聞城角艤行舟，自擁笙歌選勝遊。',64,'全唐诗/poet.song.43000.json','["傳聞城角艤行舟，自擁笙歌選勝遊。", "偶爲寒江阻潮汐，再容清賞屬林丘。", "燕回吳苑風和雪，夢斷錢塘月滿樓。", "盡把蘇杭好煙景，醉吟將去詫東州。"]'),
('2d793440-91ea-4079-a6bf-8ed4d11e5a77','贈陶辰州  其一','章惇','宋','宋诗','song-poetry','','[]','善戰無如新息侯，漢兵才渡綠蘿洲。',32,'全唐诗/poet.song.43000.json','["善戰無如新息侯，漢兵才渡綠蘿洲。", "愛君挽我陶溪粟，直到牂牁水口頭。"]'),
('ba38055e-5fe1-47eb-b892-1cf0de00f5fb','贈陶辰州  其二','章惇','宋','宋诗','song-poetry','','[]','使介直登雙御閣，州符就領五蠻溪。',32,'全唐诗/poet.song.43000.json','["使介直登雙御閣，州符就領五蠻溪。", "爭雄白鵲臨崖鬬，憶子玄猿繞澗啼。"]'),
('c1b34c4d-3c5b-4ee8-8a43-1b41ed4cb157','過石醋鋪','章惇','宋','宋诗','song-poetry','','[]','瘴靄潛消瑞氣和，梅峰千里闊煙蘿。',64,'全唐诗/poet.song.43000.json','["瘴靄潛消瑞氣和，梅峰千里闊煙蘿。", "人逢雜堠雖云遠，路在好山寧厭多。", "啼鳥叢篁傳木杪，瀑泉碎玉激巖阿。", "欲留征馭遲遲云，公檄催人不奈何。"]'),
('73364ebf-f99c-4b87-9dfb-c130b41066a2','紫閣','章惇','宋','宋诗','song-poetry','','[]','我生山水鄉，習得山中樂。',120,'全唐诗/poet.song.43000.json','["我生山水鄉，習得山中樂。", "每觀唐人詩，夢寐思紫閣。", "欲爲秦山行，常苦道路邈。", "君言舊曾遊，使我心踴躍。", "我今既西來，而子滯天角。", "雲山空在眼，詩酒乖侑酢。", "誰題壁間詩，歲久墨色薄。", "人生定能幾，當此感離索。", "積靄浮青春，落日滿巖壑。", "驪龍儼將駕，顧我猶淹泊。"]'),
('4aeaaf2e-a8ba-4db8-9fcc-0e59ea1ce241','歲窮雨夜獨臥山齋','章惇','宋','宋诗','song-poetry','','[]','歲晏雲深誰與遊，巖房終夜雨如秋。',32,'全唐诗/poet.song.43000.json','["歲晏雲深誰與遊，巖房終夜雨如秋。", "不知海上三山夢，何似人間萬戶侯。"]'),
('04e9098b-7c43-4ff3-87ad-016fa3d30b83','梅山歌','章惇','宋','宋诗','song-poetry','','[]','開梅山，開梅山，梅山萬仞摩星躔。',227,'全唐诗/poet.song.43000.json','["開梅山，開梅山，梅山萬仞摩星躔。", "捫蘿鳥道十步九曲折，時有僵木橫崖巓。", "肩摩直下視南岳，迴首蜀道猶平川。", "人家迤邐見板屋，火耕磽多畬田。", "穿堂之鼓堂壁懸，兩頭擊鼓歌聲傳。", "長藤酌酒跪而飲，何物爽口鹽爲先。", "白巾裹髻衣錯結，野花山果青垂肩。", "如今丁口漸繁息，世界雖異如桃源。", "熙寧天子聖慮遠，命將傳檄令開邊。", "給牛貸種使開懇，植桑種稻輸緡錢。", "不持寸刃得地一千里，王道蕩蕩堯爲天。", "大開庠序明禮教，撫柔新俗威無專。", "小臣作詩備雅樂，梅山之崖詩可鐫。", "此詩可勒不可泯，頌聲千古長潺潺。"]'),
('691f710b-a13f-4137-8d60-bd7e4580641c','句  其一','章惇','宋','宋诗','song-poetry','','[]','天面長虹一鑒痕，直通南北兩山春。',16,'全唐诗/poet.song.43000.json','["天面長虹一鑒痕，直通南北兩山春。"]'),
('1a357796-34b3-4a92-b232-afb55f6f37d7','句  其二','章惇','宋','宋诗','song-poetry','','[]','每聞同列進，不覺寸心忙。',12,'全唐诗/poet.song.43000.json','["每聞同列進，不覺寸心忙。"]'),
('779bf013-e367-4852-9963-23786d802998','句  其三','章惇','宋','宋诗','song-poetry','','[]','自奉鸞臺直，叨隨陟降蹤。',24,'全唐诗/poet.song.43000.json','["自奉鸞臺直，叨隨陟降蹤。", "共陳尊聖嗣，屢請罷軍容。"]'),
('04f51cdc-2d32-44f0-8ad2-8cab9240f920','偈四首  其一','釋智本','宋','宋诗','song-poetry','','[]','滿口道不出，句句甚分明。',36,'全唐诗/poet.song.43000.json','["滿口道不出，句句甚分明。", "滿目覷不見，山山疊亂青。", "鼓聲猶不會，何況是鐘鳴。"]'),
('e4206976-096f-4d9d-922c-af39be941f98','偈四首  其二','釋智本','宋','宋诗','song-poetry','','[]','祖翁卓卓犖犖，兒孫齷齷齪齪。',34,'全唐诗/poet.song.43000.json','["祖翁卓卓犖犖，兒孫齷齷齪齪。", "有處藏頭，沒處露角。", "借問衲僧，如何摸索。"]'),
('8dbb774e-3109-4993-a265-abf8cf4330c4','偈四首  其三','釋智本','宋','宋诗','song-poetry','','[]','牙如刀劍面如鐵，眼放電光光不歇。',32,'全唐诗/poet.song.43000.json','["牙如刀劍面如鐵，眼放電光光不歇。", "手把蒺藜一萬斤，等閑敲落天邊月。"]'),
('e2c0087a-2037-4f5c-a285-2e6c2ce796f1','偈四首  其四','釋智本','宋','宋诗','song-poetry','','[]','頭戴須彌山，腳踏四大海。',36,'全唐诗/poet.song.43000.json','["頭戴須彌山，腳踏四大海。", "呼吸起風雷，動用生五彩。", "若能識得渠，一任歲月改。"]'),
('abb27e43-ab53-4942-a86b-aafd0d8782fd','偈','珙禪師','宋','宋诗','song-poetry','','[]','三十年來握箭弓，三平纔到擘開胸。',32,'全唐诗/poet.song.43000.json','["三十年來握箭弓，三平纔到擘開胸。", "半個聖人終不得，大顛弦外幾時逢。"]'),
('28406004-c57d-4d80-a9e9-5f6fbe699123','答大通偈','釋慈辯','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','黑相白相，擔枷過狀。',36,'全唐诗/poet.song.43000.json','["黑相白相，擔枷過狀。", "了不了兮，無風起浪。", "若問究竟事如何，洞庭山在太湖上。"]'),
('fb23e1a3-7186-4888-be66-6e6aa93e99f5','偈','釋應圓','宋','宋诗','song-poetry','','[]','寒氣將殘春日到，無索泥牛皆𨁝跳。',67,'全唐诗/poet.song.43000.json','["寒氣將殘春日到，無索泥牛皆𨁝跳。", "筑著崑崙鼻孔頭，觸倒須彌成糞掃。", "牧童兒，鞭棄了。", "懶吹無孔笛，拍手呵呵笑。", "歸來兮歸去來，煙霞深處和衣倒。"]'),
('8f08b7ee-3b20-4dcc-bbb5-42f2e1ac43a8','偈','釋仲易','宋','宋诗','song-poetry','','[]','一二三四五，陞堂擊法鼓。',48,'全唐诗/poet.song.43000.json','["一二三四五，陞堂擊法鼓。", "蔟蔟齊上來，一一面相睹。", "秋色滿虛庭，秋風動寰宇。", "更問祖師禪，雪峰到投子。"]'),
('0288f4ca-246e-4e79-814d-f948519c3fb0','偈','釋紹先','宋','宋诗','song-poetry','','[]','團不聚，撥不散，日曬不乾，水浸不爛。',34,'全唐诗/poet.song.43000.json','["團不聚，撥不散，日曬不乾，水浸不爛。", "等閑掛在太虛中，一任傍人冷眼看。"]'),
('c1b26264-7320-4970-a504-294428774961','偈','宗禪師','宋','宋诗','song-poetry','','[]','一不做，二不休。',66,'全唐诗/poet.song.43000.json','["一不做，二不休。", "捩轉鼻孔，捺下雲頭。", "禾山解打鹽官鼓，僧繇不寫戴嵩牛。", "廬陵米，投子油，雪峰依舊輥雙毬。", "夜來風送衡陽信，寒雁一聲霜月幽。"]'),
('121c8798-fcd2-4f3a-b547-1d9dd1390f63','詩一首','丁諷','宋','宋诗','song-poetry','','[]','我來自北幾千里，景陵一到心怡然。',32,'全唐诗/poet.song.43000.json','["我來自北幾千里，景陵一到心怡然。", "人淳訟簡公事少，屢遊星館時留連。"]'),
('f7dc9a7d-41ba-4bed-ad09-d3148117cd5d','游潛山','李師道','宋','宋诗','song-poetry','','[]','肩輿轉關隨俯仰，不憂弱水澄方丈。',64,'全唐诗/poet.song.43000.json','["肩輿轉關隨俯仰，不憂弱水澄方丈。", "細霧縈盤上白雲，剛風肅肅天森爽。", "夏木陰濃四月寒，澗流觸石鳴驚湍。", "到身已喜在福地，肯問玄都何處壇。"]'),
('c74dcf93-1df8-4bd0-aa02-32acca8cfb75','歸雲祠','杜符卿','宋','宋诗','song-poetry','','[]','寂照三乘法，冥通萬佛心。',48,'全唐诗/poet.song.43000.json','["寂照三乘法，冥通萬佛心。", "傳燈光祖印，演教茂禪林。", "蓮座華成雨，雲菴施側金。", "因懷會稽紱，蘭梵許登臨。"]'),
('a63800a8-6351-40b8-82a0-0979eb3bad18','句','林東喬','宋','宋诗','song-poetry','','[]','心愛民田遠，車行石徑中。',12,'全唐诗/poet.song.43000.json','["心愛民田遠，車行石徑中。"]'),
('84bae2e6-eed2-4e91-9069-e72498143fca','廣教院','趙植','宋','宋诗','song-poetry','','[]','列嶂倚天環佛界，亂流穿石度僧房。',32,'全唐诗/poet.song.43000.json','["列嶂倚天環佛界，亂流穿石度僧房。", "林泉盡日無窮趣，車馬長年有底忙。"]'),
('52dbd989-fc8c-4870-8ab5-2c3184dd8227','句','張微','宋','宋诗','song-poetry','','[]','人家橘柚間，鐘梵雲煙側。',12,'全唐诗/poet.song.43000.json','["人家橘柚間，鐘梵雲煙側。"]'),
('0c1b88a3-75e9-4597-8982-a050d401af68','伏波巖','崔靜','宋','宋诗','song-poetry','','[]','古木纏溪出亂根，四時香火廟空存。',64,'全唐诗/poet.song.43000.json','["古木纏溪出亂根，四時香火廟空存。", "人家曉聚鳬鴨亂，水怪夜翻星斗渾。", "靈洞仙游門自鎖，陰崖龍去石生痕。", "幸同軒從乘餘興，酣醉清時酒一樽。"]'),
('c00284f0-6276-4740-8783-586118ff1c4f','次逢原秋夜見寄','滿執中','宋','宋诗','song-poetry','','[]','病對園林萬事空，肯將寂寞感塗窮。',64,'全唐诗/poet.song.43000.json','["病對園林萬事空，肯將寂寞感塗窮。", "消磨壯憤詩書外，破碎閑愁笑傲中。", "霜苦亂蟲清叫夜，夢寒孤竹冷敲風。", "思君別有悲秋意，不爲南湖一釣篷。"]'),
('ed623fc4-1d16-462d-9cd1-9a0a8cb3db2f','石屏路','滿執中','宋','宋诗','song-poetry','','[]','石屏月如水，石壁雲不動。',24,'全唐诗/poet.song.43000.json','["石屏月如水，石壁雲不動。", "閑中攲枕臥，天地同一夢。"]'),
('e7d1a82c-94ab-45a1-bf17-b880032d4e19','明月溪','滿執中','宋','宋诗','song-poetry','','[]','月出溪水清，月落溪水黑。',24,'全唐诗/poet.song.43000.json','["月出溪水清，月落溪水黑。", "茫茫溪上人，笑與月爲客。"]'),
('307b70fa-4049-474e-b7a5-fedd04ee531c','了了堂','滿執中','宋','宋诗','song-poetry','','[]','虛堂跨雲巓，白雲在林杪。',24,'全唐诗/poet.song.43000.json','["虛堂跨雲巓，白雲在林杪。", "絕頂不可窮，了了非了了。"]'),
('47d1776d-526d-4cc3-940f-21ca57f4a3e3','瑯琊溪','滿執中','宋','宋诗','song-poetry','','[]','巖下桃花紅，溪流碧如玉。',24,'全唐诗/poet.song.43000.json','["巖下桃花紅，溪流碧如玉。", "逋翁隔雲歌，不是人間曲。"]'),
('a5f2fcd3-a153-486f-b1eb-680f6775dbf2','句','曾黯','宋','宋诗','song-poetry','','[]','水合雙江急，山逢百竅深。',12,'全唐诗/poet.song.43000.json','["水合雙江急，山逢百竅深。"]'),
('adb0c657-84f3-472d-9cb3-fdefd2646598','民謠','許醇','宋','宋诗','song-poetry','','[]','龍陽古昔惟荒野，石險山深甲天下。',96,'全唐诗/poet.song.44000.json','["龍陽古昔惟荒野，石險山深甲天下。", "始聞魏將征蜀時，閣道通行有來者。", "緣崖傍澗縈居止，風景寧將他郡比。", "地稀平陸少稻梁，菽麥蕎糜而已矣。", "此土瘠薄不出穀，稅廩不踰三百斛。", "我朝設官屯戍兵，供億常於左綿督。"]'),
('53b61741-60f2-43a2-855b-c978931abad8','送程給事知越州','張炎民','宋','宋诗','song-poetry','','[]','威名嘗使虜人驚，杖節還朝欲請纓。',96,'全唐诗/poet.song.44000.json','["威名嘗使虜人驚，杖節還朝欲請纓。", "三絕文章留麗正，一麾江海去承明。", "夕闈入對虛青瑣，晝錦行歸耀絳旌。", "秋雨鱸蓴廚膳美，曉風鐃鼓使船輕。", "鑑湖雲水關心久，蓬閣煙巒照眼清。", "西省自應論出守，未容全慰吏民情。"]'),
('f3b89be3-79a6-45e1-a93f-6e18d221ebf6','正覺寺清風軒','蔡覿','宋','宋诗','song-poetry','','[]','海風拍枕燈初暗，山雨打窻人正寒。',32,'全唐诗/poet.song.44000.json','["海風拍枕燈初暗，山雨打窻人正寒。", "料得此軒秋更好，怒濤推月上闌干。"]'),
('964f2d92-9752-46e6-b322-c15ea8c35043','將進酒歌','蕭介夫','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','勸君莫累黑山土，累得黑山竟何補。',141,'全唐诗/poet.song.44000.json','["勸君莫累黑山土，累得黑山竟何補。", "勸君莫勒燕然石，勒得燕然又何益。", "百年歲月能幾何，螢燭光中都瞬息。", "我今安得萬丈梯，騰騰直上天街墀。", "剪拆金烏翅，戳下玉兔蹄。", "使玉兔不能走，金烏不得飛。", "然後舉泰山爲肉林，東海爲酒池。", "君不見吳王臺下秋風悲，金谷園中春草衰。", "不如相逢且飲酒，齊聲拍掌大唱金縷衣。"]'),
('af6295fb-8495-47a4-a84a-05f9605a4ab0','句','廖平','宋','宋诗','song-poetry','','[]','豈是齊安無一事，自緣太守有餘才。',16,'全唐诗/poet.song.44000.json','["豈是齊安無一事，自緣太守有餘才。"]'),
('51c1656c-4c65-4ed7-8c3a-87207cfd1217','句  其一','郭知章','宋','宋诗','song-poetry','','[]','一門十捧鄉老書，四子五折東堂桂。',16,'全唐诗/poet.song.44000.json','["一門十捧鄉老書，四子五折東堂桂。"]'),
('523822b0-8591-4a8c-ba3b-7aa6e0ede188','句  其二','郭知章','宋','宋诗','song-poetry','','[]','去國二十年。',6,'全唐诗/poet.song.44000.json','["去國二十年。"]'),
('4f4947fb-d8b5-4001-925b-a437a5dd3e3a','和孫莘老題召伯斗野亭','張琬','宋','宋诗','song-poetry','','[]','維舟得古寺，望完多天四平。',121,'全唐诗/poet.song.44000.json','["維舟得古寺，望完多天四平。", "晴日暉暉散，晚風泠泠清。", "危亭下瞰野，層閣高連甍。", "起望斗與牛，淮海相奔傾。", "往來誰百年，今昔我平生。", "悠悠何所寓，臺上多化城。", "與其逐影死，寧似不鳴烹。", "咄哉應有止，老矣將安行。", "中庭柜子落，丈室霜月明。", "此意竟蕭條，猶然笑安榮。"]'),
('88961378-0a85-4cd8-8da7-7d2ab9d79b3c','南樓寺','張琬','宋','宋诗','song-poetry','','[]','仙去不留丹竈藥，詩成惟記御園柑。',64,'全唐诗/poet.song.44000.json','["仙去不留丹竈藥，詩成惟記御園柑。", "休誇巨鎮來天北，且得奇峰在嶺南。", "已見二樓開石路，可無雙鯉起龍潭。", "政當九月黄茅裏，喜作清商洗瘴嵐。"]'),
('c51cb911-7a53-467f-8b65-2436599a6cfd','讀唐中興頌','毛杭','宋','宋诗','song-poetry','','[]','周雅久不復，楚騷方獨鳴。',107,'全唐诗/poet.song.44000.json','["周雅久不復，楚騷方獨鳴。", "淫哇弄氣態，污我瀟湘清。", "二公好奇古，大節□時□。", "磨崖勒唐頌，字字瓊□英。", "雲借體勢，水石生光精。", "浯溪僻南地，自爾聞正聲。", "詩傳播夷夏，孰貴燕然銘。", "弦歌入商魯，永與人神聽。", "江流或可竭，此文如日星。"]'),
('c9645503-5081-4754-9ec1-1a5d8c757fb5','鳬山廟二首  其一','練毖','宋','宋诗','song-poetry','','[]','仙人丹成去不返，至今廟貌留名山。',32,'全唐诗/poet.song.44000.json','["仙人丹成去不返，至今廟貌留名山。", "嗟予俯仰隨繮鎖，塵土驅馳止汗顔。"]'),
('3062d6f2-ccc1-42b1-8d96-57f75b768519','鳬山廟二首  其二','練毖','宋','宋诗','song-poetry','','[]','雲煙深處路縈紆，元是真人舊隱居。',32,'全唐诗/poet.song.44000.json','["雲煙深處路縈紆，元是真人舊隱居。", "我亦放情丘壑者，官閑時得命籃輿。"]'),
('2e74b154-7c46-4048-a552-260419b52dc8','靖節祠堂','李亨伯','宋','宋诗','song-poetry','','[]','道出古柴桑，淵明祠有堂。',48,'全唐诗/poet.song.44000.json','["道出古柴桑，淵明祠有堂。", "春逢楊柳綠，秋及菊花黄。", "有酒尊居右，無弦琴在床。", "清名百世下，廬岳共存亡。"]'),
('30db5d2c-2033-4b59-9ac8-dc8c54362f30','句  其一','董乂','宋','宋诗','song-poetry','','[]','縹渺煙中漁父槳，坡陀山上使君衙。',16,'全唐诗/poet.song.44000.json','["縹渺煙中漁父槳，坡陀山上使君衙。"]'),
('f6a7b5ed-828d-4a62-9f33-423576bda435','句  其二','董乂','宋','宋诗','song-poetry','','[]','六月涼窻涼衽袖，二蘇辭翰照青冥。',16,'全唐诗/poet.song.44000.json','["六月涼窻涼衽袖，二蘇辭翰照青冥。"]'),
('43cc52c3-97fa-4dfb-8a8e-e3d04ba8c939','句  其三','董乂','宋','宋诗','song-poetry','','[]','使宇高連徐邈洞，人家都食武昌魚。',16,'全唐诗/poet.song.44000.json','["使宇高連徐邈洞，人家都食武昌魚。"]'),
('782ab00d-3288-4725-81c1-58fd8ed4e3bf','句  其四','董乂','宋','宋诗','song-poetry','','[]','雲影萬重連鄂渚，風帆一日到潯陽。',16,'全唐诗/poet.song.44000.json','["雲影萬重連鄂渚，風帆一日到潯陽。"]'),
('5abc031f-315a-46f6-91d7-e341eff2f8b3','句  其五','董乂','宋','宋诗','song-poetry','','[]','數封天子詔，兩代帝王師。',12,'全唐诗/poet.song.44000.json','["數封天子詔，兩代帝王師。"]'),
('28daa956-2836-4f2c-bfca-2b3975dab56e','令江夏時作','樓常','宋','宋诗','song-poetry','','[]','不老長生世所稀，要持陰德定鎡基。',64,'全唐诗/poet.song.44000.json','["不老長生世所稀，要持陰德定鎡基。", "能行方寸無欺處，方是平生踏道時。", "長以仁思登愷弟，莫教深刻失便宜。", "行年七十看將近，見盡人間事可知。"]'),
('b31e32b2-5d2c-45b7-908e-4dee63e57b1d','歸雲洞','陳毅','宋','宋诗','song-poetry','','[]','雲道無心亦愛山，雨餘時向此中還。',32,'全唐诗/poet.song.44000.json','["雲道無心亦愛山，雨餘時向此中還。", "而今天下焦枯甚，只恐蒼龍未放閑。"]'),
('c5e38cdb-06e7-441c-8a76-9c992ae736aa','決澗院','陳毅','宋','宋诗','song-poetry','','[]','遠歸滄海通舟楫，近洗山僧一片心。',32,'全唐诗/poet.song.44000.json','["遠歸滄海通舟楫，近洗山僧一片心。", "留與臥龍成窟穴，等閑飛去也爲霖。"]'),
('098a4c5e-bd48-43be-a44f-cb484459865a','題慧悟禪師上方','余弼','宋','宋诗','song-poetry','','[]','孤峰牢落幾何年，臺殿於今插半天。',64,'全唐诗/poet.song.44000.json','["孤峰牢落幾何年，臺殿於今插半天。", "已是精藍誇絕徼，更將寶塔在危巓。", "煙霞色任陰晴變，鐘磬聲隨上下傳。", "珍重老僧無別境，一生幽趣只山川。"]'),
('bed87fc9-0e3b-4513-94d5-f7d75dcc1a57','題竹軒','黄遠','宋','宋诗','song-poetry','','[]','隱隱招提地，幽軒無點埃。',48,'全唐诗/poet.song.44000.json','["隱隱招提地，幽軒無點埃。", "惟栽紫竹種，相伴白雲堆。", "疏影月移轉，清聲風送來。", "居常稀俗客，貝葉此勤開。"]'),
('e5c93a85-9b83-4afe-bcde-8bb282ccee6f','過華清宮','杜常','宋','宋诗','song-poetry','','[]','行盡江南數十程，曉風殘月入華清。',32,'全唐诗/poet.song.44000.json','["行盡江南數十程，曉風殘月入華清。", "朝元閣上西風急，都入長楊作雨聲。"]'),
('44463117-e98c-4177-b442-96a33dc4991c','夜雨晨霽','杜常','宋','宋诗','song-poetry','','[]','桕葉青青櫟葉紅，高低相倚弄秋風。',32,'全唐诗/poet.song.44000.json','["桕葉青青櫟葉紅，高低相倚弄秋風。", "夜來雨後輕塵斂，繡出驪山嶺上宮。"]'),
('e15c1503-1403-4377-87fb-baba6f5a788b','溫泉','杜常','宋','宋诗','song-poetry','','[]','已去開元四百年，此泉猶自響潺潺。',32,'全唐诗/poet.song.44000.json','["已去開元四百年，此泉猶自響潺潺。", "也知不憤當時事，長作悲聲恨祿山。"]'),
('8c37b359-8ddf-456a-af0d-f196328b2d04','驪山','杜常','宋','宋诗','song-poetry','','[]','漁陽烽燧起雲間，玉輦蒼黄下此山。',32,'全唐诗/poet.song.44000.json','["漁陽烽燧起雲間，玉輦蒼黄下此山。", "何事君王自神武，區區南渡鹿頭關。"]'),
('ef3fb519-2ae7-40b9-b718-808d5c9003b5','句','杜常','宋','宋诗','song-poetry','','[]','江聲聒破刺史眠。',8,'全唐诗/poet.song.44000.json','["江聲聒破刺史眠。"]'),
('a196722b-128f-4076-a6fa-42768947e3a0','贈僧道澄','孫諤','宋','宋诗','song-poetry','','[]','聞說虞山有道澄，白雲深處不聞扃。',32,'全唐诗/poet.song.44000.json','["聞說虞山有道澄，白雲深處不聞扃。", "自言古佛何爲者，只是無心一老僧。"]'),
('54059023-cfff-40ad-a4c8-f452cf28948c','句','孫諤','宋','宋诗','song-poetry','','[]','竹林藏月讀書家。',8,'全唐诗/poet.song.44000.json','["竹林藏月讀書家。"]'),
('27a304b9-22cc-4f4d-a405-3b4c1f4afd9c','昌國寺來景堂','張綬','宋','宋诗','song-poetry','','[]','青山曲轉抱寒溪，重磴躋攀鳥道危。',64,'全唐诗/poet.song.44000.json','["青山曲轉抱寒溪，重磴躋攀鳥道危。", "石竈未烹鴻漸茗，雲亭先紀長卿詩。", "千峰列坐生詞筆，萬象當空落酒巵。", "更約清宵共來宿，琵琶亭上月明時。"]'),
('096b6190-5137-4acb-a525-3a3641f92eeb','句','張綬','宋','宋诗','song-poetry','','[]','江山清絕冠吳頭。',8,'全唐诗/poet.song.44000.json','["江山清絕冠吳頭。"]'),
('80c88d77-c911-4af0-ae85-008b673f33f2','閑詠','查深','宋','宋诗','song-poetry','','[]','門外聲聲叫賣魚，囊空不問價何如。',32,'全唐诗/poet.song.44000.json','["門外聲聲叫賣魚，囊空不問價何如。", "磁盆昨夜黄虀熟，淡飯時光樂有餘。"]'),
('addf5490-49ff-45ec-bd15-d5192007e611','啄木','馬道','宋','宋诗','song-poetry','','[]','翠翎迎日動，紅觜響煙蘿。',48,'全唐诗/poet.song.44000.json','["翠翎迎日動，紅觜響煙蘿。", "不顧泥丸及，唯貪得食多。", "纔離枯朽木，又上最高柯。", "吳楚園林闊，忙忙爭奈何。"]'),
('aab26892-1347-4774-88c5-6a99f1261180','贈仙翁三首  其一','錢忠','宋','宋诗','song-poetry','','[]','八十清翁今釣客，一綸一艇一魚簑。',64,'全唐诗/poet.song.44000.json','["八十清翁今釣客，一綸一艇一魚簑。", "碧潭波底繫船臥，紅蓼香中對月歌。", "玉膾盈盤同美酒，錦鱗隨手出清波。", "風煙幽隱無人到，俗客如何願一過。"]'),
('34396f80-7032-4725-bcbc-4bceb6ab2da8','贈仙翁三首  其二','錢忠','宋','宋诗','song-poetry','','[]','小舟泛泛遊春水，竹笠團團覆敗簑。',64,'全唐诗/poet.song.44000.json','["小舟泛泛遊春水，竹笠團團覆敗簑。", "盈棹長風三尺浪，滿船明月一聲歌。", "非干奔走厭浮世，自是情懷慕素波。", "惟有仙翁爲密友，就魚攜酒每相過。"]'),
('2ec0554b-46b0-4caa-b60d-60e6f87f7530','贈仙翁三首  其三','錢忠','宋','宋诗','song-poetry','','[]','吳江高隱仙鄉客，衰鬢長髯白髪乾。',64,'全唐诗/poet.song.44000.json','["吳江高隱仙鄉客，衰鬢長髯白髪乾。", "滿目生涯千頃浪，全家衣食一綸竿。", "長橋水隱秋風軟，極浦煙浮夜釣寒。", "因笑區區名利者，是非榮辱苦相干。"]'),
('0dbef0ac-9929-4be0-9914-9b736e5bac89','贈姑子王師孟','錢忠','宋','宋诗','song-poetry','','[]','水國神仙宅，吾今過此中。',24,'全唐诗/poet.song.44000.json','["水國神仙宅，吾今過此中。", "長橋千古月，不復怨春風。"]'),
('6522ef83-2c79-4c26-9fd2-1bfe92a5382c','和錢忠','吳江老人','宋','宋诗','song-poetry','','[]','向晚雲晴無限好，船頭又見亂堆簑。',64,'全唐诗/poet.song.44000.json','["向晚雲晴無限好，船頭又見亂堆簑。", "卻無塵世利名厭，盡是市朝興廢歌。", "全宅合來居水澤，此身常得弄煙波。", "肥魚美酒尤豐足，自是幽人不願過。"]'),
('8a7bfc00-e31c-4323-802d-1f3d3f6d93c6','與錢忠','吳江女子','宋','宋诗','song-poetry','','[]','昨日相逢小木橋，風牽裙带纏郎腰。',32,'全唐诗/poet.song.44000.json','["昨日相逢小木橋，風牽裙带纏郎腰。", "此情不語無人覺，只恐猜疑眼動搖。"]'),
('745b95d0-b817-46a1-a4e3-aa2878be00c5','又與錢忠','吳江女子','宋','宋诗','song-poetry','','[]','輕橈直入湖心裏，渡人荷花窣窣鳴。',32,'全唐诗/poet.song.44000.json','["輕橈直入湖心裏，渡人荷花窣窣鳴。", "何處漁謠相調戲，住船側耳認郎聲。"]'),
('c81893ca-33d5-4ad8-b92c-c71030e9c9ab','題壁','戴敷','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','湖中煙水平天遠，波上佳人恨未休。',32,'全唐诗/poet.song.44000.json','["湖中煙水平天遠，波上佳人恨未休。", "收拾鴛鴦好歸去，滿船明月洞庭秋。"]'),
('bd5fad49-a1af-4ebc-b8a2-d54bdfa35ab5','贈王幼玉','柳富','宋','宋诗','song-poetry','','[]','紫府樓閣高相倚，金碧戶牖紅暉起。',384,'全唐诗/poet.song.44000.json','["紫府樓閣高相倚，金碧戶牖紅暉起。", "其間燕息皆仙子，絕世妖姿妙難比。", "偶然思念起塵心，幾年謫向衡陽市。", "阿嬌飛下九天來，長在娼家偶然耳。", "天姿才色擬絕倫，壓倒花衢衆羅綺。", "紺髪濃堆巫峽雲，翠眸橫剪秋江水。", "素手纖長細細圓，春筍脫向青雲裏。", "紋履鮮花窄窄弓，鳳頭翅起紅裙底。", "有時笑倚小欄桿，桃花無言亂紅委。", "王孫逆目似勞魂，東鄰一見還羞死。", "自此城中豪富兒，呼僮控馬相追隨。", "千金買得歌一曲，暮雨朝雲鎮相續。", "皇都年少是柳君，體段風流萬事足。", "幼玉一見苦留心，殷勤厚遣行人祝。", "青羽飛來洞戶前，惟郎苦恨多拘束。", "偷身不使父母知，江亭暗共才郎宿。", "猶恐恩情未甚堅，解開鬟髻對郎前。", "一縷雲隨金剪斷，兩心濃更密如綿。", "自古美事多磨隔，無時兩意空懸懸。", "清宵長嘆明月下，花時灑淚東風前。", "怨入朱弦危更斷，淚如珠顆自相連。", "危樓獨倚無人會，新書寫恨託誰傳。", "奈何幼玉家有母，知此端倪蓄嗔怒。", "千金買醉囑傭人，密約幽歡鎮相悮。"]'),
('a466aa96-fa1e-414c-860f-79f33a5266e9','又贈','柳富','宋','宋诗','song-poetry','','[]','臨流對月暗悲酸，瘦立東風自怯寒。',64,'全唐诗/poet.song.44000.json','["臨流對月暗悲酸，瘦立東風自怯寒。", "湘水佳人方告疾，帝都才子亦非安。", "春蠶到死絲方盡，蠟燭成灰淚始乾。", "萬里雲山無路去，虛勞魂夢過湘灘。"]'),
('a04aeea5-e976-44cf-b05d-e1fa1aea941d','詠海','劉大方','宋','宋诗','song-poetry','','[]','沌元初一判，天地此居漥。',48,'全唐诗/poet.song.44000.json','["沌元初一判，天地此居漥。", "今古乾坤腹，朝昏明月家。", "闊疑包地盡，勢欲極天涯。", "誓斬鯨鯢輩，臨風按鏌鋣。"]'),
('adecaa6d-5776-4fdf-8cdd-c6fdda1dbbcb','詠泰山','劉大方','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','萬古春之主，羣山孰可曹。',122,'全唐诗/poet.song.44000.json','["萬古春之主，羣山孰可曹。", "都因敦厚大，不是險⿱山虛高。", "頂襯天地愁，根盤野□牢。", "坎離分背面，明月轉周遭。", "仙館鸞朝舞，神亭鬼夜號。", "雲來諸夏雨，風去百川濤。", "東渭藏陰重，西秦抱勢豪。", "龍蛇藏隙穴，草木立毫毛。", "陝谷三升土，黄河五尺壕。", "暫登臨日觀，直下釣靈鼇。"]'),
('aa9eb59c-2ecd-4e43-b21c-9ae0d2c9387d','病虎行','劉大方','宋','宋诗','song-poetry','','[]','海北愁雲無從裂，風如追兵雪如撒。',128,'全唐诗/poet.song.44000.json','["海北愁雲無從裂，風如追兵雪如撒。", "哀者老虎病無力，百尺泉源都凍絕。", "山中牛羊竟不來，牙爪寂寂傷饑渴。", "萬里兵刃色慘悽，獐嬌鹿倨豺狼悅。", "安得肉食復如初，平地紛紛羽毛血。", "一吼千年白日寒，羣獸幽憂心骨折。", "如今纏病未能興，長戈硬弩無相殺。", "世上青山不敢生，青山盡是狐貍穴。"]'),
('49bf175d-6452-494f-a5a2-5208d4735248','玉華山','奚球','宋','宋诗','song-poetry','','[]','玉華山來自何處，巉巉拔立陵紫煙。',116,'全唐诗/poet.song.44000.json','["玉華山來自何處，巉巉拔立陵紫煙。", "上有干雲切霄之蒼松，下有迸崖潄壑之清泉。", "長河西來齧山足，燐火白日明峰巓。", "浮嵐暖翠入窻戶，六月殿閣風泠然。", "我來豈暇弔古蹟，俛仰但喜遺囂喧。", "心魂澄澈耳目醒，如脫世故游神仙。", "平明卻入俗塵去，回首煙蘿羞滿顔。"]'),
('52059951-071a-4f5b-81f1-69e28eaba1fa','鼎湖','張因','宋','宋诗','song-poetry','','[]','有唐天子天寶初，禮官學士披圖書。',256,'全唐诗/poet.song.44000.json','["有唐天子天寶初，禮官學士披圖書。", "推本黄帝九雲車，曾跨火龍昇天衢。", "世傳虢略留鼎湖，世傳橋山晏神輿。", "真人起滅不異塗，霓來吹落火龍鬚。", "一鬚落處生萬蕪，春風秋霜榮復枯。", "頂峰千丈金芙蕖，一葉金華落婺墟。", "天子聞之爲嗟吁，大封山川名仙都。", "姓劉天師半山居，修真自結草屠蘇。", "始嚴祠宇闢一區，至今名篆存碔砆。", "上下萬年變萬殊，水雲依舊本扶疏。", "事載咸通端不誣，世更五代跡不除。", "鉅宋興王握乾符，慶源尊祖禮何如。", "乃命天下嚴殿廬，治平天子榜玉虛。", "北客南來一字無，飄飄含蓼政如荼。", "崆峒童子真吾徒，心閑神應微囁嚅。", "盡收勝概賦歸歟，歸去山東作畫圖。"]'),
('9a3a15cc-d622-4a98-bd5b-c7dbfbae1a7a','詠沙','龍太初','宋','宋诗','song-poetry','','[]','茫茫黄出寒，漠漠白鋪汀。',24,'全唐诗/poet.song.44000.json','["茫茫黄出寒，漠漠白鋪汀。", "鳥去風平篆，潮回日射星。"]'),
('1de2776e-0ba0-493f-b731-967b8d93d9a7','四皓吟','釋智孜','宋','宋诗','song-poetry','','[]','忠義合時難，雲林共掩關。',48,'全唐诗/poet.song.44000.json','["忠義合時難，雲林共掩關。", "因秦生白髮，爲漢出青山。", "不顧金章貴，終披白氅還。", "如今明聖代，高躅更難攀。"]'),
('d848ad5f-c007-4d4a-8a85-8fa1695f6279','偈','釋智孜','宋','宋诗','song-poetry','','[]','五十春秋，如電如露。',20,'全唐诗/poet.song.44000.json','["五十春秋，如電如露。", "月映寒江，分明歸去。"]'),
('2b92bf43-07cc-4792-aa40-5219c7f603dc','寄子','洪浩父','宋','宋诗','song-poetry','','[]','太學何蕃且一歸，十年甘旨誤庭闈。',64,'全唐诗/poet.song.44000.json','["太學何蕃且一歸，十年甘旨誤庭闈。", "休辭客路三千遠，須念人生七十稀。", "腰下雖無蘇子印，篋中幸有老萊衣。", "歸期定約春前後，免使高堂賦式微。"]'),
('ce51c6a8-5bad-4cb9-822c-e9aa82e709d8','詩一首','王俊民','宋','宋诗','song-poetry','','[]','寒窻一夜雪，紛紛來朔風。',60,'全唐诗/poet.song.44000.json','["寒窻一夜雪，紛紛來朔風。", "之子動歸興，輕袂飄如蓬。", "問子何所之，家在濟水東。", "問子何所學，上庠教化宮。", "行將攜老母，寓居學其中。"]'),
('efc5e4f4-1d9f-414a-80e5-c27a007ffc3d','重九','邵睦','宋','宋诗','song-poetry','','[]','衣如當日白，花似昔年黄。',24,'全唐诗/poet.song.44000.json','["衣如當日白，花似昔年黄。", "擬問東籬事，寒香入杳茫。"]'),
('7b029a7b-aeab-4eca-ae47-ca9d94988457','偈','釋道全','宋','宋诗','song-poetry','','[]','一搥打透無盡藏，一切珍寶吾皆有。',32,'全唐诗/poet.song.44000.json','["一搥打透無盡藏，一切珍寶吾皆有。", "拈來普濟貧乏人，免使波吒路邊走。"]'),
('61a7d919-c1f9-4075-bf54-3932705376ba','秋曉','釋道全','宋','宋诗','song-poetry','','[]','飄飄楓葉草萋萋，雲壓天邊雁陣低。',32,'全唐诗/poet.song.44000.json','["飄飄楓葉草萋萋，雲壓天邊雁陣低。", "何處水村人起早，櫓聲搖月過橋西。"]'),
('81565e56-b6f2-4407-9bc5-ca6512782e39','題法安院','釋道全','宋','宋诗','song-poetry','','[]','半生夢想到山宮，此日殷勤興莫窮。',64,'全唐诗/poet.song.44000.json','["半生夢想到山宮，此日殷勤興莫窮。", "寺在煙霏空翠裏，人游水墨畫圖中。", "青松夾道曉雲合，黄葉滿山秋露濃。", "滿眼新詩酬未盡，再來寧愧錦囊空。"]'),
('9e777b31-6593-45f0-85d9-839007d144e0','題林景思權巢  其一','釋道全','宋','宋诗','song-poetry','','[]','不嫌茅把蓋頭低，爲愛平簷野雪迷。',32,'全唐诗/poet.song.44000.json','["不嫌茅把蓋頭低，爲愛平簷野雪迷。", "自與蘆花夢明月，夜寒空誤鶴來棲。"]'),
('2c79cdc5-5b4c-4603-870b-ef063c21d9b9','題林景思權巢  其二','釋道全','宋','宋诗','song-poetry','','[]','田地虛明不受塵，巢中人是箇中人。',32,'全唐诗/poet.song.44000.json','["田地虛明不受塵，巢中人是箇中人。", "勿言一色渾無跡，月到梅梢亦轉身。"]'),
('f763392c-3c1d-44c5-99a0-74712e72f095','題寶嚴寺','釋道全','宋','宋诗','song-poetry','','[]','出郭二十里，過山三用村。',48,'全唐诗/poet.song.44000.json','["出郭二十里，過山三用村。", "竹深疑有寺，路僻不知門。", "萬木辭窮臘，三峰佔落曛。", "靈源正脈在，慚愧有雲孫。"]'),
('c0e5b592-0cea-4613-8d9c-8017f077fb8c','登飛泉寺','吳革','宋','宋诗','song-poetry','','[]','石磴盤空逼漢槎，凭欄睇盼渺天涯。',64,'全唐诗/poet.song.44000.json','["石磴盤空逼漢槎，凭欄睇盼渺天涯。", "穹窿巧鑿三千界，瀑瀉狂飛百里家。", "歌鳥當簷喧麗日，薰風拂座舞巖花。", "不須更覓蓬萊勝，此地登臨亦足誇。"]'),
('ea4edb97-00af-42f0-a235-faf2b3e2411c','題李進士連雲玉山圖像','吳革','宋','宋诗','song-poetry','','[]','玉山嵯峨白雲裏，翠樓鴻濛插天起。',236,'全唐诗/poet.song.44000.json','["玉山嵯峨白雲裏，翠樓鴻濛插天起。", "千丈芙蓉雲作梯，玉龍翻然吼秋水。", "山中隱人雲錦袍，掉頭不受柯山招。", "玉手廣寒修月斧，躡雲每向雲間樵。", "朝采山花樹，暮拾古木枝。", "俯仰隘六合，間與白雲期。", "白雲飛來歸丹壑，山人攬之不盈握。", "袖懷五色朝天門，捧日絪緼散寥廓。", "左挾丹鳳翱，右驂青龍翔。", "搜材盡作廟廊具，紫極出入生輝光。", "懶逐芻蕘人，局促涅塵土。", "白衣蒼狗徒紛紜，萬變目前何足數。", "舒展豈無心，秪在深山處。", "四海蒼生望太平，濟旱終須靄霖雨。", "我亦巢雲廬雲山，看花早種東華蓮。", "南歸何日分半榻，撫掌一笑三千年。"]'),
('c3911653-67e8-4c55-9782-48772011474d','游碧落洞','李兟','宋','宋诗','song-poetry','','[]','遐邇開勝概，憧憧往來侵。',48,'全唐诗/poet.song.44000.json','["遐邇開勝概，憧憧往來侵。", "共認融結意，獨符仁智心。", "得侶賞清塵，彌日窮幽深。", "奇哉周羽皇，雄文無古今。"]'),
('b14d7e04-5e2f-4c66-b7cf-a2b92305e8c7','遊碧落洞同李兟諸公','馮慜','宋','宋诗','song-poetry','','[]','絕景塵不到，暫遊神已清。',48,'全唐诗/poet.song.44000.json','["絕景塵不到，暫遊神已清。", "雲岫斂晴色，風桂含秋聲。", "自得泉石興，誰貪軒冕榮。", "巢由值茲室，必無箕潁名。"]'),
('bfa277d5-cd69-400b-88d6-e83e48ea7e54','偈','釋子鴻','宋','宋诗','song-poetry','','[]','一不守，二不向，上下四維無等量。',62,'全唐诗/poet.song.44000.json','["一不守，二不向，上下四維無等量。", "大洋海裏泛鐵船，須彌頂上翻鯨浪。", "臨濟縮卻舌頭，德山閣卻拄杖。", "千古萬古獨巍巍，留與人間作榜樣。"]'),
('10904301-b057-48ac-aaff-f1cb82aa888b','村老','馬存','宋','宋诗','song-poetry','','[]','肉死皮乾垂鬢絲，尋暄扶杖向東籬。',32,'全唐诗/poet.song.44000.json','["肉死皮乾垂鬢絲，尋暄扶杖向東籬。", "文王沒後無人問，直至而今大半饑。"]'),
('3fdddbab-55a4-4f4c-81cd-e8009890c816','長淮謠爲徐先生詠','馬存','宋','宋诗','song-poetry','','[]','長淮之水青如苔，行人但覺心眼開。',122,'全唐诗/poet.song.44000.json','["長淮之水青如苔，行人但覺心眼開。", "湘江豈無水，魚腹忠魂埋，但見愁雲結雨猿聲哀。", "浙江豈無水，鴟革漂胥骸，但見潮頭怒氣如山來。", "孤臣詞客到江上，何以寬心懷。", "長淮之水遶楚流，先生家住淮上頭。", "黄金萬斛浴明月，碧玉一片含清秋。", "酒花入面歌一曲，淮上百物無閑愁。"]'),
('3131adb0-2929-4928-83ea-c404d26a4b11','題釣臺','馬存','宋','宋诗','song-poetry','','[]','子陵臺下山層層，奇峰壯氣橫雲生。',80,'全唐诗/poet.song.44000.json','["子陵臺下山層層，奇峰壯氣橫雲生。", "處士溪邊水泚泚，碧波明月涵天清。", "老松偃蹇傲世態，綠竹蕭灑吟風聲。", "潮頭百仞出海門，飄吳擊越如毛輕。", "飛來灘下不敢過，變作平浪歸滄溟。"]'),
('01c9878e-c572-4401-ae12-7dd0fa64946e','題梅仙觀','馬存','宋','宋诗','song-poetry','','[]','漢綱解宏紐，國命移權臣。',288,'全唐诗/poet.song.44000.json','["漢綱解宏紐，國命移權臣。", "太阿有神鋒，顛倒柄在人。", "公卿雖滿前，有語各自吞。", "張禹爲帝師，此是禍亂根。", "天子辟左右，決機在一言。", "不爲社稷計，祇乞兒女恩。", "上方斬馬劍，當時負朱雲。", "谷永對直言，天庭策災氛。", "陰謀助元惡，歸咎昭陽嬪。", "豺狼自此縱，白晝當路蹲。", "先生當是時，上書叩帝閽。", "耿耿禍福語，皎皎星與辰。", "天門鎖九重，一門萬夫屯。", "小臣江湖心，何由達至尊。", "賊莽果盜國，忠烈遭烹焚。", "先生變名姓，爲卒吳市門。", "浮雲去無蹤，世人以爲仙。", "蓬山在何處，此事且勿論。", "但愛清風高，凜凜久益新。", "我來拜遺像，舊宅荒基存。", "元豐發新詔，玉牒對壽春。", "老松益勁色，歲飽霜雪痕。", "直上絕頂壇，天風吹衣巾。", "細讀壁間書，頗喜羅隱文。"]'),
('c8d424d3-1709-47b0-a1f6-a767f33c1d1b','邀月亭','馬存','宋','宋诗','song-poetry','','[]','亭上十分綠醑酒，盤中一筯黄金雞。',152,'全唐诗/poet.song.44000.json','["亭上十分綠醑酒，盤中一筯黄金雞。", "滄溟東角邀姮娥，水輪碾上青琉璃。", "天風灑掃浮雲沒，千巖萬壑瓊瑤窟。", "桂花飛影入盞來，傾下胸中照清骨。", "玉兔擣藥與誰餐，且與豪客留朱顔。", "朱顔如可留，恩重如丘山。", "爲君殺卻蝦蟆精，腰間老劍光芒寒。", "舉酒勸明月，聽我歌聲發。", "照見古人多少愁，更與今人照離別。", "我曹自是高陽徒，肯學羣兒嘆圓缺。"]'),
('497ab4a8-d292-4153-a0a4-a81cd1583d4c','燕思亭','馬存','宋','宋诗','song-poetry','','[]','李白騎鯨飛上天，江南風月閑多年。',160,'全唐诗/poet.song.44000.json','["李白騎鯨飛上天，江南風月閑多年。", "縱有高亭與美酒，何人一斗詩百篇。", "主人定是金龜老，未到亭中名已好。", "紫蟹肥時晚稻香，黄雞啄處秋風早。", "我憶金鑾殿上人，醉著宮錦烏角巾。", "巨靈摩山洪河竭，長鯨吸海萬壑貧。", "如傾元氣入胸腹，須臾百媚生陽春。", "讀書不必破萬卷，筆下自有鬼與神。", "我曹本是狂吟客，寄語溪山莫相憶。", "他年須使襄陽兒，再唱銅鞮滿街陌。"]'),
('d982a0cd-c6e5-402c-9cb5-53ad73cc50dc','寄范安道','馬存','宋','宋诗','song-poetry','','[]','西山石腳盤如城，芙蓉峰插龍泉精。',139,'全唐诗/poet.song.44000.json','["西山石腳盤如城，芙蓉峰插龍泉精。", "有客高臥青雲層，孤吟自作太古聲。", "古聲無味淡如水，今人有耳甜如餳。", "君不見登高山，泛流水，子期已沒不復生。", "幾世幾年無此耳。", "恨君不到蒼巖陰，不見此客搖頭吟。", "千崖萬壑羣動息，相知唯有清泉音。", "春風捲野濃如波，着人如醉將奈何。", "幾時見我銅鞮陌，爲唱襄陽拍手歌。"]'),
('caf3a5bb-bfc8-4b91-b1ed-39360b917980','浩浩歌','馬存','宋','宋诗','song-poetry','','[]','浩浩歌，天地萬物如吾何。',250,'全唐诗/poet.song.44000.json','["浩浩歌，天地萬物如吾何。", "用之解带食太倉，不用拂枕歸山阿。", "君不見渭川漁父一竿竹，莘野耕叟數畝禾。", "喜來起作商家霖，怒後便把周王戈。", "又不見子陵橫足加帝腹，帝不敢動豈敢訶。", "皇天爲忙逼，星辰相繫摩。", "可憐相府癡，邀請先經過。", "浩浩歌，天地萬物如吾何。", "屈原枉死汩羅水，夷齊空臥西山坡。", "丈夫犖犖不可羈，有身何用自滅磨。", "吾觀聖賢心，自樂豈有他。", "蒼生如命窮，吾道成蹉跎。", "直須爲吊天下人，何必嫌恨傷邱阿。", "浩浩歌，天地萬物如吾何。", "玉堂金馬在何處，雲山石室高嵯峨。", "低頭欲耕地雖少，仰面長笑天何多。", "請君醉我一斗酒，紅光一面春風和。"]'),
('47a3bda3-bfe3-41c0-a3bc-888febc5e07d','句','馬存','宋','宋诗','song-poetry','','[]','可憐一覺登天夢，不夢商巖夢鄧郎。',16,'全唐诗/poet.song.44000.json','["可憐一覺登天夢，不夢商巖夢鄧郎。"]'),
('8b7261fa-8b75-44d0-82b7-02e7f8c2217c','神宗皇帝挽詞  其一','王子韶','宋','宋诗','song-poetry','','[]','寶餌方嘰玉，金盤忽造冰。',48,'全唐诗/poet.song.44000.json','["寶餌方嘰玉，金盤忽造冰。", "周人悲地坼，杞國怨天崩。", "杳霧霾陰月，鯢膏耿夜燈。", "傷心歌舞妓，灑血望西陵。"]'),
('c0a05e5f-ce83-4b0d-a095-5f8d78e17de7','神宗皇帝挽詞  其二','王子韶','宋','宋诗','song-poetry','','[]','脫屣人寰忽上天，投淵果熟會羣仙。',64,'全唐诗/poet.song.44000.json','["脫屣人寰忽上天，投淵果熟會羣仙。", "帳宮雲暝龍爲駕，綴幄天寒鶴記年。", "萬里出師輕衛霍，一朝行事付談遷。", "功名半古昇遐早，獨抱遺弓涕泫然。"]'),
('4c74b48a-3bf6-4b2d-9040-08a49e2f28a2','句','王子韶','宋','宋诗','song-poetry','','[]','孤雲兩角，去天一握。',10,'全唐诗/poet.song.44000.json','["孤雲兩角，去天一握。"]'),
('321d4c5e-74fb-479a-a1c9-72c688a88562','二月','曾布','宋','宋诗','song-poetry','','[]','二月春華已半歸，江天況值雨垂垂。',32,'全唐诗/poet.song.44000.json','["二月春華已半歸，江天況值雨垂垂。", "山梅倏忽花經眼，園杏須臾子滿枝。"]'),
('9c9582c2-0395-44c2-b73d-edb44733ec58','詩一首','曾布','宋','宋诗','song-poetry','','[]','曉出東郊信馬蹄，青梅墻角兩三枝。',64,'全唐诗/poet.song.44000.json','["曉出東郊信馬蹄，青梅墻角兩三枝。", "竹雞啼罷雨來急，杜宇聲乾月落遲。", "山店煮煙繅絲日，野田鋤水插秧時。", "農桑勸課非無力，爲報新安太守知。"]'),
('8cfdb7df-929c-4fc7-b6a3-b92ff3357cb1','表海亭','曾布','宋','宋诗','song-poetry','','[]','表海風流舊所聞，青冥飛觀一番新。',64,'全唐诗/poet.song.44000.json','["表海風流舊所聞，青冥飛觀一番新。", "山河十二名空在，簪履三千跡已陳。", "極目煙嵐九霄近，滿州樓閣萬家春。", "由來興廢南柯夢，且喜登臨屬後人。"]'),
('69642966-5239-476f-b91c-f7ebef9b5d49','布作高陽臺衆樂園成被命與金陵易地兄弟待罪侍從對更方面實爲私門之慶走筆記子開弟','曾布','宋','宋诗','song-poetry','','[]','樓臺丹碧照天涯，塞北江南未足誇。',64,'全唐诗/poet.song.44000.json','["樓臺丹碧照天涯，塞北江南未足誇。", "十里煙波新種柳，萬株桃李未開花。", "一麾同下西清路，兩鎮高迎上將牙。", "回首林塘莫留戀，風光還屬阿連家。"]'),
('b8b4e6d7-c0ab-479a-a65c-d6fc15eb9c64','靈泉寺','曾布','宋','宋诗','song-poetry','','[]','一掬寒泉照眼明，冰霜凜凜坐中清。',64,'全唐诗/poet.song.44000.json','["一掬寒泉照眼明，冰霜凜凜坐中清。", "生芻想見當時客，華屋空留後世名。", "曉日凈涵金碧影，秋風暗動佩環聲。", "他年卜筑南山下，白首何人共濯纓。"]'),
('c83a8102-0fdd-4f45-90df-0abb4bd57165','盱江','曾布','宋','宋诗','song-poetry','','[]','軍山流泉初濫觴，繚繞東山爲盱江。',64,'全唐诗/poet.song.44000.json','["軍山流泉初濫觴，繚繞東山爲盱江。", "峰巒隱映淵源長，地靈物秀雄吾邦。", "麻源三谷神仙鄉，高林遠岫長相望。", "巋然飛觀臨滄浪，凝嵐凈練羅軒窻。"]'),
('dbae39c7-a393-4099-95dd-36dc55aaf970','和陳倩遊曾公巖韻','曾布','宋','宋诗','song-poetry','','[]','從事區區厭獨賢，尋幽深入翠微間。',64,'全唐诗/poet.song.44000.json','["從事區區厭獨賢，尋幽深入翠微間。", "旋開榛莽東郊路，偶得神仙舊隱山。", "都嶠三天臨瘴水，靈巖十里接溪蠻。", "何如咫尺鄰風穴，杖履時時一往還。"]'),
('6c2c097d-9cf9-4cf1-b52e-08789167b89e','和劉誼留題融州老君巖  其一','曾布','宋','宋诗','song-poetry','','[]','神仙遺像出天真，造化胚渾豈易言。',32,'全唐诗/poet.song.44000.json','["神仙遺像出天真，造化胚渾豈易言。", "訪古尋幽空有意，白頭軒冕感君恩。"]'),
('85a3d737-4a52-40f2-a92a-eef37b9447eb','和劉誼留題融州老君巖  其二','曾布','宋','宋诗','song-poetry','','[]','鹿龍高躡九霄難，共駕仙車去不還。',32,'全唐诗/poet.song.44000.json','["鹿龍高躡九霄難，共駕仙車去不還。", "遺跡至今空有檜，不知蟬蛻此山間。"]'),
('1072e8f5-9dc0-42bc-9d5c-f601bb62dcfd','真仙巖','曾布','宋','宋诗','song-poetry','','[]','鑿成巖穴鬼工難，中有神仙自往還。',32,'全唐诗/poet.song.44000.json','["鑿成巖穴鬼工難，中有神仙自往還。", "不見桃花開落處，祗隨流水到人間。"]'),
('34ec8ec2-b7b8-4f9c-bcd7-71d18e78a9f1','句  其一','曾布','宋','宋诗','song-poetry','','[]','驚嗟怪怪文人奇，縞衣藍縷冰斷肌。',48,'全唐诗/poet.song.44000.json','["驚嗟怪怪文人奇，縞衣藍縷冰斷肌。", "莓苔雪片凍不飛，玉飾其末璣衡欹。", "藐姑之仙下縹緲，蒼虬爲駕羽荷希。"]'),
('a7ec4d77-525a-48c0-a1f1-11b4576ae71f','句  其二','曾布','宋','宋诗','song-poetry','','[]','海邊憔悴多情客，想見一枝寒玉色。',32,'全唐诗/poet.song.44000.json','["海邊憔悴多情客，想見一枝寒玉色。", "願君攀折贈餘香，勿使隨風自狼籍。"]'),
('fb912ec2-6d5d-4039-97f8-c9df89d5bf9b','句  其三','曾布','宋','宋诗','song-poetry','','[]','天際林巒壓壽邱，夾江旁瞰兩三州。',16,'全唐诗/poet.song.44000.json','["天際林巒壓壽邱，夾江旁瞰兩三州。"]'),
('05b8384b-e42f-4fe3-b2f5-d59906f24cf4','句  其四','曾布','宋','宋诗','song-poetry','','[]','海門西北起崇邱，極目參差見五州。',16,'全唐诗/poet.song.44000.json','["海門西北起崇邱，極目參差見五州。"]'),
('ab63d3c1-1638-4c1a-9802-056dfd0b04ec','句  其五','曾布','宋','宋诗','song-poetry','','[]','自慚太守非何武，得向河陽見兩龔。',16,'全唐诗/poet.song.44000.json','["自慚太守非何武，得向河陽見兩龔。"]'),
('6191ce2d-ba3c-4712-90c4-efb8bbe90654','句  其六','曾布','宋','宋诗','song-poetry','','[]','家住城南千石泉。',8,'全唐诗/poet.song.44000.json','["家住城南千石泉。"]'),
('42248122-39ca-43ee-bc03-86c56c3bb933','句','魏夫人','宋','宋诗','song-poetry','','[]','使君自爲君恩厚，不是區區愛華山。',16,'全唐诗/poet.song.44000.json','["使君自爲君恩厚，不是區區愛華山。"]'),
('401f275b-1bd0-4680-b206-800c9213635f','龍興仁王佛舍攜酒肴納涼聯句十六韻','魏泰','宋','宋诗','song-poetry','','[]','宿雨且初霽，微涼吹廣庭。',192,'全唐诗/poet.song.44000.json','["宿雨且初霽，微涼吹廣庭。", "嘉賓忽相遇，午夢驚扣扃。", "長松森翠影，修竹參青冥。", "飄雲度空急，殘日穿林明。", "幽墻隔江浦，遠嶼定風舲。", "城市厭煩暑，山樊念伶俜。", "角巾代公紱，草具踰侯鯖。", "園實摘的皪，廚醖斟晶熒。", "烹鮮縮頸大，海錯著器腥。", "笑談得真樂，採擷逢幽馨。", "雲陰剝初霽，夕嵐收遠青。", "窻臥憶元亮，詩成懷景升。", "日須河朔飲，當解高陽酲。", "煩襟頓忘釋，嘉詠不少停。", "闉闍發嚴鼓，穹碧垂繁星。", "一笑跨鞍去，奚論楚人醒。"]'),
('114cade0-499c-4553-9a7c-fee747290c82','挽王平甫二首  其一','魏泰','宋','宋诗','song-poetry','','[]','海內文章傑，朝廷亮直聞。',48,'全唐诗/poet.song.44000.json','["海內文章傑，朝廷亮直聞。", "黄瓊起處士，子夏遽修文。", "貝錦生遷怒，江湖久離羣。", "傷心王佐略，不得致華勳。"]'),
('5de20619-9c7a-40aa-93af-b432f8c2ee72','挽王平甫二首  其二','魏泰','宋','宋诗','song-poetry','','[]','今日臨風淚，蕭蕭似綆縻。',48,'全唐诗/poet.song.44000.json','["今日臨風淚，蕭蕭似綆縻。", "空懷徐穉絮，誰立鄭玄碑。", "無力酬推轂，平時憤抵巇。", "何人令枉狀，路粹豈能爲。"]'),
('f6953970-6b74-47e4-b0c9-fc1356a41e45','題黄魯直集','魏泰','宋','宋诗','song-poetry','','[]','端求古人遺，琢抉手不停。',24,'全唐诗/poet.song.44000.json','["端求古人遺，琢抉手不停。", "方其拾機羽，往往失鵬鯨。"]'),
('ad2f3412-2b45-4c78-9a0c-b136406c38e6','荆門別張天覺','魏泰','宋','宋诗','song-poetry','','[]','秋風十驛望台星，想見冰壺照坐清。',64,'全唐诗/poet.song.44000.json','["秋風十驛望台星，想見冰壺照坐清。", "零雨已回公旦駕，挽鬚聊聽野王箏。", "三朝元老心方壯，四海蒼生耳已傾。", "白髮故人來一別，卻歸林下看昇平。"]'),
('a4291a96-3a6d-4a20-8cfe-50a0737544f9','詩一首','魏泰','宋','宋诗','song-poetry','','[]','博山燒沉水，煙燼氣不滅。',24,'全唐诗/poet.song.44000.json','["博山燒沉水，煙燼氣不滅。", "日暮白門前，楊花散成雪。"]'),
('5d130a14-51eb-4f6f-9de5-80fc6dbed849','贈韋公','魏泰','宋','宋诗','song-poetry','','[]','韋公八十餘，位至六尚書。',36,'全唐诗/poet.song.44000.json','["韋公八十餘，位至六尚書。", "五福惟無富，一生誰得如。", "桂枝攀最久，蘭省出仍初。"]'),
('8f6dd663-9c11-438e-90bc-d879a7cdd585','朝陽洞','魏泰','宋','宋诗','song-poetry','','[]','七鑿混沌死，萬變從此生。',36,'全唐诗/poet.song.44000.json','["七鑿混沌死，萬變從此生。", "海水能幾何，呿口下混鯨。", "歸期不可晚，霜日背林明。"]'),
('a0cdcd51-e704-42b4-8191-401525546da1','寄米元章','魏泰','宋','宋诗','song-poetry','','[]','綠野風回草偃波，方塘疏雨凈傾荷。',64,'全唐诗/poet.song.44000.json','["綠野風回草偃波，方塘疏雨凈傾荷。", "幾年蕭寺書紅葉，一日山陰換白鵝。", "湘浦夕同要月醉，泂湖還憶扣舷歌。", "緇衣化盡故山去，白髮相思一倍多。"]'),
('b1316599-dd8b-453e-8f31-2d1b7b373283','句  其一','魏泰','宋','宋诗','song-poetry','','[]','麻源山壓盱江水，高樓迥對江山起。',16,'全唐诗/poet.song.44000.json','["麻源山壓盱江水，高樓迥對江山起。"]'),
('94c1d72a-c0d5-4929-b1d9-ffc2a9c54638','句  其二','魏泰','宋','宋诗','song-poetry','','[]','蘭汀蕙浦入平蕪，天遠孤帆望中滅。',32,'全唐诗/poet.song.44000.json','["蘭汀蕙浦入平蕪，天遠孤帆望中滅。", "屈平宋玉情不盡，千古依然在風月。"]'),
('5b40650d-d125-458e-8089-0cdb7bc324c0','句  其三','魏泰','宋','宋诗','song-poetry','','[]','石城同學斷空殘照，白雪非人只麗譙。',17,'全唐诗/poet.song.44000.json','["石城同學斷空殘照，白雪非人只麗譙。"]'),
('d0269676-2748-4fbe-bbae-e7a71d2c71b5','句  其四','魏泰','宋','宋诗','song-poetry','','[]','白雪樓高壓曉霓，樓下波光數毛髪。',32,'全唐诗/poet.song.44000.json','["白雪樓高壓曉霓，樓下波光數毛髪。", "邦君登樓賦萬景，景與清吟相皎潔。"]'),
('a611e8c7-12cb-425e-b614-4a01e465667e','黄鶴樓','王得臣','宋','宋诗','song-poetry','','[]','昔人已乘白雲去，舊國連天不知處。',48,'全唐诗/poet.song.44000.json','["昔人已乘白雲去，舊國連天不知處。", "思量費子真仙子，從他浮世悲生死。", "黄鶴一去不復返，光陰流轉忽已晚。"]'),
('555b6772-3e2e-4a40-b8af-91fc231c0aea','柴皇洗腳石','王得臣','宋','宋诗','song-poetry','','[]','柴皇徒步奔埃塵，風雲未至時方屯。',32,'全唐诗/poet.song.44000.json','["柴皇徒步奔埃塵，風雲未至時方屯。", "石上無聊謾濯足，泥蟠留此潛其神。"]'),
('695fa355-bf11-43ea-b611-91bcbe532c4c','詩三首  其一','王得臣','宋','宋诗','song-poetry','','[]','大別山前拍湖水，坐覺煙波幾千里。',48,'全唐诗/poet.song.44000.json','["大別山前拍湖水，坐覺煙波幾千里。", "碧山亭上秋興多，四時清景森雲羅。", "故人領麾江沔口，公暇登臨頻入手。"]'),
('73f7d5d5-0335-47cb-9721-56f880262e30','詩三首  其二','王得臣','宋','宋诗','song-poetry','','[]','忽來漢陽稱刺史，又值魚肥酒偏美。',48,'全唐诗/poet.song.44000.json','["忽來漢陽稱刺史，又值魚肥酒偏美。", "酒給公廚不用酤，朝吟暮醉醉復醒。", "郎官湖上秋興亭，江山四向盡可眺。"]'),
('e9ecde84-6731-451d-a642-98e3d95eefee','詩三首  其三','王得臣','宋','宋诗','song-poetry','','[]','故人隔闊在東州，煙波渺漫使人愁。',32,'全唐诗/poet.song.44000.json','["故人隔闊在東州，煙波渺漫使人愁。", "朝朝眼望頭陀寺，夜夜魂飛黄鶴樓。"]'),
('7600edb4-841f-4af1-a9a2-3e367701ace9','過少林輒書四韻兼詒長老慶禾士','王得臣','宋','宋诗','song-poetry','','[]','天入千巖碧，林收曼古春。',48,'全唐诗/poet.song.44000.json','["天入千巖碧，林收曼古春。", "靜中深有境，險外絕無鄰。", "宦牒嬰汙色，禪關脫世塵。", "安心無覓處，斷臂爲何人。"]'),
('b480862f-e23e-4ca0-9aec-734130aca90c','句  其一','王得臣','宋','宋诗','song-poetry','','[]','春風三月暮，寂寞大椿庭。',12,'全唐诗/poet.song.44000.json','["春風三月暮，寂寞大椿庭。"]'),
('cfaf6fd3-b268-4561-a3d0-4bc6348eb7ac','句  其二','王得臣','宋','宋诗','song-poetry','','[]','高高蒼蒼高不極，黄鶴樓中吹玉笛。',16,'全唐诗/poet.song.44000.json','["高高蒼蒼高不極，黄鶴樓中吹玉笛。"]'),
