('db5b4b6b-c077-46b5-a1ac-436a5cb13c8b','句','張頌','宋','宋诗','song-poetry','','[]','人散鞦韆閑掛月，露零蝴蝶冷眠風。',16,'全唐诗/poet.song.44000.json','["人散鞦韆閑掛月，露零蝴蝶冷眠風。"]'),
('c1beec4d-58d5-446c-b881-4773c78b8484','偈二首  其一','釋圓璣','宋','宋诗','song-poetry','','[]','不學文章不讀書，頹然終日自如愚。',32,'全唐诗/poet.song.44000.json','["不學文章不讀書，頹然終日自如愚。", "雖然百事不通曉，是馬何曾喚作驢。"]'),
('b7896fe2-f9f5-4857-9893-23f96c88eff4','偈二首  其二','釋圓璣','宋','宋诗','song-poetry','','[]','無學庵中老，平生百不能。',24,'全唐诗/poet.song.44000.json','["無學庵中老，平生百不能。", "忖思多幸處，至老得爲僧。"]'),
('87529ebf-359f-4203-b620-6ceb355baa7a','答張無盡因續成詩','釋圓璣','宋','宋诗','song-poetry','','[]','野僧窿客下煙嵐，試問如何是翠巖。',32,'全唐诗/poet.song.44000.json','["野僧窿客下煙嵐，試問如何是翠巖。", "門近洪崖千尺井，石橋分水繞松杉。"]'),
('7f662399-d32f-4935-8607-fdf64c715728','棲賢開先寺','孫直言','宋','宋诗','song-poetry','','[]','三峽飛梁如臥龍，蒼藤碧蔓掛長松。',32,'全唐诗/poet.song.44000.json','["三峽飛梁如臥龍，蒼藤碧蔓掛長松。", "煮茗窻前清衆會，讀書巖下古人蹤。"]'),
('cff45287-7d2e-4286-b858-ab0525a46317','澹山巖','樂咸','宋','宋诗','song-poetry','','[]','門開巖底洞沈沈，竇乳雲泉矢路深。',64,'全唐诗/poet.song.44000.json','["門開巖底洞沈沈，竇乳雲泉矢路深。", "香石峭峰千載異，龍潭幽穴四時陰。", "僧居筑室隨高下，客到留小見古今。", "南出零陵一舍地，清瀟堤上好追尋。"]'),
('cb7c976b-d398-41f6-b2b5-f2f938120578','示寂偈','釋慧元','宋','宋诗','song-poetry','','[]','五十五年夢幻身，東西南北孰爲親。',32,'全唐诗/poet.song.44000.json','["五十五年夢幻身，東西南北孰爲親。", "白雲散盡千山外，萬里秋空片月新。"]'),
('e9647cac-abd7-41cc-8c40-350997ef651d','悼侍兒','蔡確','宋','宋诗','song-poetry','','[]','鸚鵡言猶在，琵琶事已非。',24,'全唐诗/poet.song.44000.json','["鸚鵡言猶在，琵琶事已非。", "傷心瘴江水，同渡不同歸。"]'),
('7d09ae18-9863-4347-8689-003074541c7f','書舍竹','蔡確','宋','宋诗','song-poetry','','[]','窻前翠竹兩三竿，瀟灑風吹滿院寒。',32,'全唐诗/poet.song.44000.json','["窻前翠竹兩三竿，瀟灑風吹滿院寒。", "常在眼前君莫厭，化成龍去見應難。"]'),
('d9123b96-653f-4b4d-97e5-be852df07dc9','清明日赴玉津園宴','蔡確','宋','宋诗','song-poetry','','[]','春風盎盎水濺濺，南苑清明雨後天。',64,'全唐诗/poet.song.44000.json','["春風盎盎水濺濺，南苑清明雨後天。", "門外游人聽玉管，席間使者勸金船。", "定須歸路燒紅燭，還有新詩上采牋。", "舊老戀恩方燕喜，看花應不憶伊川。"]'),
('2c1aa0f2-3fe6-4545-a398-3ddfd8eaa92e','題王維江行初雪畫','蔡確','宋','宋诗','song-poetry','','[]','吳兒龜手網寒川，急雪鳴蓑浪拍船。',32,'全唐诗/poet.song.44000.json','["吳兒龜手網寒川，急雪鳴蓑浪拍船。", "青弋渡頭曾臥看，令人卻憶十年前。"]'),
('2b855042-a674-4e4d-bd0d-c1758f68102d','觀燕公山水畫後有王荆公題詩','蔡確','宋','宋诗','song-poetry','','[]','相君開卷憶江東，彷彿鍾山與此同。',32,'全唐诗/poet.song.44000.json','["相君開卷憶江東，彷彿鍾山與此同。", "今日還爲一居士，翛然身在畫圖中。"]'),
('4a6019a1-e847-487b-acd3-b19aea63a7e1','春','蔡確','宋','宋诗','song-poetry','','[]','十二天街雨壓沙，鞦韆咿喔響人家。',64,'全唐诗/poet.song.44000.json','["十二天街雨壓沙，鞦韆咿喔響人家。", "東風會勸十分酒，寒食初開百玉花。", "年少斬新金絡馬，柳蔭無數畫輪車。", "春來誰道遲遲日，尤覺春來日易斜。"]'),
('ac9a716c-8453-4a9b-a061-b2c7f9e3fede','崇政殿放榜','蔡確','宋','宋诗','song-poetry','','[]','黄帕開封出奏篇，銀袍二百玉階前。',64,'全唐诗/poet.song.44000.json','["黄帕開封出奏篇，銀袍二百玉階前。", "威顔咫尺瞻中扆，名姓傳呼下九天。", "宮筆旋題黄甲字，禁門已簇杏花韉。", "孤臣拜賜交悲喜，相望先分五十年。"]'),
('acfe583c-6fbb-4866-8288-7da66c3d1ad0','夏日登車蓋亭十絕  其一','蔡確','宋','宋诗','song-poetry','','[]','公事無多客亦稀，朱衣小吏不須隨。',32,'全唐诗/poet.song.44000.json','["公事無多客亦稀，朱衣小吏不須隨。", "溪潭直上虛亭裏，臥展柴桑處士詩。"]'),
('611dbc59-6c4c-4c46-baa9-4f6d4f4655a9','夏日登車蓋亭十絕  其二','蔡確','宋','宋诗','song-poetry','','[]','一川佳景疏簾外，四面涼風曲檻頭。',32,'全唐诗/poet.song.44000.json','["一川佳景疏簾外，四面涼風曲檻頭。", "綠野平流來遠棹，青天白雨起靈湫。"]'),
('1551e064-3052-41b4-acac-23fd217080f1','夏日登車蓋亭十絕  其三','蔡確','宋','宋诗','song-poetry','','[]','靜中自足勝炎蒸，入眼兼無俗物憎。',32,'全唐诗/poet.song.44000.json','["靜中自足勝炎蒸，入眼兼無俗物憎。", "何處機心驚白鳥，誰人怒劍逐青蠅。"]'),
('77c6fde3-a84e-457a-8d62-0adcff4ef9fb','夏日登車蓋亭十絕  其四','蔡確','宋','宋诗','song-poetry','','["\u5411\u5f80", "\u5f52\u9690", "\u590f\u5929", "\u95f2\u9002"]','紙屏石枕竹方床，手倦拋書午夢長。',32,'全唐诗/poet.song.44000.json','["紙屏石枕竹方床，手倦拋書午夢長。", "睡起莞然成獨笑，數聲漁笛在滄浪。"]'),
('d9d4e76e-7a5b-440c-b484-15c94c05ff26','夏日登車蓋亭十絕  其五','蔡確','宋','宋诗','song-poetry','','[]','西山彷彿見松筠，日日來看色轉新。',32,'全唐诗/poet.song.44000.json','["西山彷彿見松筠，日日來看色轉新。", "聞說桃花巖石畔，讀書曾有謫仙人。"]'),
('2bf3f691-b7d1-41c4-b98a-fa2f64de140b','夏日登車蓋亭十絕  其六','蔡確','宋','宋诗','song-poetry','','[]','風搖熟果時聞落，雨滴餘花亦自香。',32,'全唐诗/poet.song.44000.json','["風搖熟果時聞落，雨滴餘花亦自香。", "葉底出巢黄口鬧，波間逐隊小魚忙。"]'),
('bf4edb9c-87c1-4634-b5bb-d0e5d2f565c3','夏日登車蓋亭十絕  其七','蔡確','宋','宋诗','song-poetry','','[]','來結芳廬向翠微，自持杯酒對清暉。',32,'全唐诗/poet.song.44000.json','["來結芳廬向翠微，自持杯酒對清暉。", "水趨夢澤悠悠過，雲抱西山冉冉飛。"]'),
('04c512c3-5ac8-44a7-87f1-3009a386cb21','夏日登車蓋亭十絕  其八','蔡確','宋','宋诗','song-poetry','','[]','矯矯名臣郝甑山，忠言直節上元間。',32,'全唐诗/poet.song.44000.json','["矯矯名臣郝甑山，忠言直節上元間。", "古人不見清風在，嘆息思公俯碧灣。"]'),
('e95f5584-fedd-44ef-b662-af9748197feb','夏日登車蓋亭十絕  其九','蔡確','宋','宋诗','song-poetry','','[]','溪中曾有戈船士，溪上今無佩犢人。',32,'全唐诗/poet.song.44000.json','["溪中曾有戈船士，溪上今無佩犢人。", "病守翛然唯坐嘯，白鷗紅鶴伴閑身。"]'),
('2a7eff02-5c52-40fd-9a80-06a880d3d853','夏日登車蓋亭十絕  其一○','蔡確','宋','宋诗','song-poetry','','[]','喧豗六月浩無津，行見沙州束兩濱。',32,'全唐诗/poet.song.44000.json','["喧豗六月浩無津，行見沙州束兩濱。", "如带溪流何足道，沈沈滄海會揚塵。"]'),
('558c7d64-b063-4db4-9a2e-ab0d9cb11ed4','新興即事','蔡確','宋','宋诗','song-poetry','','[]','仁義橋邊楊柳斜，洗亭崗畔種桑麻。',48,'全唐诗/poet.song.44000.json','["仁義橋邊楊柳斜，洗亭崗畔種桑麻。", "龍山水遶祖師塔，夏院雲埋宰相家。", "十仙園裏尋常到，恰似桃源一洞花。"]'),
('972b758e-1792-4809-9215-05b419ba3897','楊花','蔡確','宋','宋诗','song-poetry','','[]','楊花三月暮，撩亂送春歸。',48,'全唐诗/poet.song.44000.json','["楊花三月暮，撩亂送春歸。", "盡日閑相逐，無風亦自飛。", "輕輕攔乳燕，故故撲征衣。", "莫上高樓望，徘徊滿落暉。"]'),
('b7c8a5de-c727-4031-adba-ff40de0ced30','攬秀','蔡確','宋','宋诗','song-poetry','','[]','秉興登茲亭，朱檻臨曲洲。',108,'全唐诗/poet.song.44000.json','["秉興登茲亭，朱檻臨曲洲。", "俯仰一寓目，高風振衣裘。", "新陽力尚微，冰雪浩未收。", "出沒林間翮，飛鳴各有求。", "緬彼北山岑，翛翛雲氣游。", "聞有兩高士，茹芝臥巖幽。", "長離在青冥，燕雀安得謀。", "伊子世味薄，坐感歲且流。", "願言從之子，相與物外遊。"]'),
('ef0e436b-42da-4994-8a9d-b057e3e5337b','句  其一','蔡確','宋','宋诗','song-poetry','','[]','儒苑昔推唐吏部，將壇今拜漢將軍。',16,'全唐诗/poet.song.44000.json','["儒苑昔推唐吏部，將壇今拜漢將軍。"]'),
('120b695f-c93b-465c-8c7d-ff03e11c4da6','句  其二','蔡確','宋','宋诗','song-poetry','','[]','焚香再拜穿華綫，候得神光白氣飛。',16,'全唐诗/poet.song.44000.json','["焚香再拜穿華綫，候得神光白氣飛。"]'),
('72f83569-1377-4688-8e51-7dc19767bb21','存目','蔡確','宋','宋诗','song-poetry','','[]','詩題：皇子生獻詩首句：昨夜熏風入舜韶。',19,'全唐诗/poet.song.44000.json','["詩題：皇子生獻詩首句：昨夜熏風入舜韶。"]'),
('3b4c79cb-0220-4896-8668-023515ae63ed','題福昌寺南軒東壁','朱光庭','宋','宋诗','song-poetry','','[]','節候偶當桐始華，遍尋蕭寺喜煙霞。',64,'全唐诗/poet.song.44000.json','["節候偶當桐始華，遍尋蕭寺喜煙霞。", "勝遊今幸同三友，仁惠將推及萬家。", "綠滿田疇齊種麥，紅藏村塢爛開花。", "愛民若副賢侯意，共入聲詩與衆誇。"]'),
('ae9f2b01-52e9-4d5c-ba72-50e2e02220aa','華清偶成','朱光庭','宋','宋诗','song-poetry','','[]','驪山秀色古今同，盡入詩人感慨中。',32,'全唐诗/poet.song.44000.json','["驪山秀色古今同，盡入詩人感慨中。", "只徇霓裳一曲樂，不知天下樂無窮。"]'),
('affd6750-9293-4eb7-956a-8328a9a4cc8b','送程給事知越州  其一','崔公度','宋','宋诗','song-poetry','','[]','江吳士氣久凋摧，比見高牙擁詔回。',64,'全唐诗/poet.song.44000.json','["江吳士氣久凋摧，比見高牙擁詔回。", "共喜識兵侔漢相，果聞持節過燕臺。", "馳驅中禮戎心服，顧眄生威虜使猜。", "所惜聖朝恩好重，未容儒將盡餘才。"]'),
('58418a42-492d-4149-ae15-b32cbcb0e252','送程給事知越州  其二','崔公度','宋','宋诗','song-poetry','','[]','朱轓所至藹徽音，談笑金城億萬尋。',64,'全唐诗/poet.song.44000.json','["朱轓所至藹徽音，談笑金城億萬尋。", "計壓南夷豗狡文，官崇東省秀儒林。", "過家鼓吹新儀盛，拜寵朝廷此意深。", "聞說錢塘連得守，非公誰慰粵人心。"]'),
('185c654b-d551-401e-9a2f-c3d3c55e7f1e','送程給事知越州','杜紘','宋','宋诗','song-poetry','','[]','大旆高牙不爲榮，錦衣過鄉無可喜。',320,'全唐诗/poet.song.44000.json','["大旆高牙不爲榮，錦衣過鄉無可喜。", "長安久客厭塵土，得見青山與流水。", "高帆大檝駕吳艘，直指東南不留止。", "昔人蓴鱸有高興，乍到江國真快耳。", "蓬萊危閣切蒼霞，湖面百頃秋光裏。", "野鳬江鷗點白煙，紅蕖蓼花照清泚。", "星辰影動落簷前，鼓角聲雄來地底。", "越國強大今尚富，海陸百貨填井里。", "我公才高出人頭，人所爲難公則易。", "暫辭青瑣擁朱轓，飽得閑暇窮勝地。", "高情灑落白雲中，日從賓筵二三子。", "薄余曾得侍公顔，喜見仙骨清照几。", "稽山千古鍾秀氣，四明五雲有幽致。", "朝浥沆瀣食倉精，暮襲鴻濛餐氣蘂。", "可以養公之長生，可以輔公之高思。", "富貴儻來可奈何，經濟未施聊自寄。", "相如歲晚更倦遊，客路崎嶇勞馬箠。", "麤官無補官家事，冗食徒索太倉米。", "五湖七澤不得到，惆悵浮生輕自棄。", "得公旌旗先入吳，願從此去爲公吏。"]'),
('9a19672b-691e-4dc5-892f-bc8b87dd7572','郭綸','蘇軾','宋','宋诗','song-poetry','','[]','河西猛士無人識，日暮津亭閱過船。',64,'全唐诗/poet.song.44000.json','["河西猛士無人識，日暮津亭閱過船。", "路人但覺驄馬瘦，不知鐵槊大如椽。", "因言西方久不戰，截髮願作萬騎先。", "我當憑軾與寓目，看君飛矢集蠻氈。"]'),
('2539a3e8-cd22-4edf-940e-844f1c59708c','初發嘉州','蘇軾','宋','宋诗','song-poetry','','[]','朝發鼓闐闐，西風獵畫旃。',72,'全唐诗/poet.song.44000.json','["朝發鼓闐闐，西風獵畫旃。", "故鄉飄已遠，往意浩無邊。", "錦水細不見，蠻江清可憐。", "奔騰過佛脚，曠蕩造平川。", "野市有禪客，釣臺尋暮煙。", "相期定先到，久立水潺潺。"]'),
('e5b5ee81-45ed-4604-a84d-c2cff34e6f84','犍爲王氏書樓','蘇軾','宋','宋诗','song-poetry','','[]','樹林幽翠滿山谷，樓觀突兀起江濱。',128,'全唐诗/poet.song.44000.json','["樹林幽翠滿山谷，樓觀突兀起江濱。", "云是昔人藏書處，磊落萬卷今生塵。", "江邊日出紅霧散，綺窗畫閣青氛氳。", "山猿悲嘯谷泉響，野鳥嘐戛巌花春。", "借問主人今何在，被甲遠戍長苦辛。", "先登搏戰事斬級，區區何者爲三墳。", "書生古亦有戰陣，葛巾羽扇揮三軍。", "古人不見悲世俗，回首蒼山空白雲。"]'),
('e9874fc6-e493-45f1-9353-4e5c35c47fdf','過宜賓見夷中亂山','蘇軾','宋','宋诗','song-poetry','','[]','江寒晴不知，遠見山上日。',84,'全唐诗/poet.song.44000.json','["江寒晴不知，遠見山上日。", "朦朧含高峰，晃蕩射峭壁。", "橫雲忽飄散，翠樹紛歷歷。", "行人挹孤光，飛鳥投遠碧。", "蠻荒誰復愛，穠秀安可適。", "豈無避世士，高隠鍊精魄。", "誰能從之游，路有豺虎跡。"]'),
('0a1eb875-7d2a-432e-89fa-69c3e951e3b7','夜泊牛口','蘇軾','宋','宋诗','song-poetry','','[]','日落紅霧生，繫舟宿牛口。',132,'全唐诗/poet.song.44000.json','["日落紅霧生，繫舟宿牛口。", "居民偶相聚，三四依古柳。", "負薪出深谷，見客喜且售。", "煮蔬爲夜飧，安識肉與酒。", "朔風吹茅屋，破壁見星斗。", "兒女自咿嚘，亦足樂且久。", "人生本無事，苦爲世味誘。", "富貴耀吾前，貧賤獨難守。", "誰知深山子，甘與麋鹿友。", "置身落蠻荒，生意不自陋。", "今予獨何者，汲汲强奔走。"]'),
('a49df92f-1db5-4c7b-ad54-976895e4ce7a','牛口見月','蘇軾','宋','宋诗','song-poetry','','[]','掩窗寂已睡，月脚垂孤光。',156,'全唐诗/poet.song.44000.json','["掩窗寂已睡，月脚垂孤光。", "披衣起周覽，飛露灑我裳。", "山川同一色，浩若涉大荒。", "幽懷耿不寐，四顧獨徬徨。", "忽憶丙申年，京邑大雨霶。", "蔡河中夜决，橫浸國南方。", "車馬無復見，紛紛操栰郎。", "新秋忽已晴，九陌尚汪洋。", "龍津觀夜市，燈火亦煌煌。", "新月皎如晝，疏星弄寒芒。", "不知京國喧，謂是江湖鄉。", "今來牛口渚，見月重淒涼。", "却思舊遊處，滿陌沙塵黄。"]'),
('99b47a6e-0ca3-43d5-a3fe-447c02d74c84','戎州','蘇軾','宋','宋诗','song-poetry','','[]','亂山圍古郡，市易带群蠻。',72,'全唐诗/poet.song.44000.json','["亂山圍古郡，市易带群蠻。", "瘦嶺春耕少，孤城夜漏閑。", "往時邊有警，征馬去無還。", "自頃方從化，年來亦款關。", "頗能貪漢布，但未脫金鐶。", "何足爭强弱，吾民盡玉顔。"]'),
('7fb10c1e-c780-46cd-86a0-3e8da75a135c','舟中聽大人彈琴','蘇軾','宋','宋诗','song-poetry','','[]','彈琴江浦夜漏永，歛衽竊聽獨激昂。',130,'全唐诗/poet.song.44000.json','["彈琴江浦夜漏永，歛衽竊聽獨激昂。", "風松瀑布已清絕，更愛玉珮聲琅璫。", "自從鄭衛亂雅樂，古器殘缺世已忘。", "千家寥落獨琴在，有如老仙不死閱興亡。", "世人不容獨反古，强以新曲求鏗鏘。", "微音淡弄忽變轉，數聲浮脆如笙簧。", "無情枯木今尚爾，何况古意墮渺茫。", "江空月出人響絕，夜闌更請彈文王。"]'),
('1f8da595-ec8d-4636-8ff9-1d476dea283c','泊南井口期任遵聖長官到晚不及見復來','蘇軾','宋','宋诗','song-poetry','','[]','江上有微徑，深榛煙雨埋。',48,'全唐诗/poet.song.44000.json','["江上有微徑，深榛煙雨埋。", "崎嶇欲取別，不見又重來。", "下馬未及語，固已慰長懷。", "江湖涉浩渺，安得與之偕。"]'),
('1a65b643-b233-40dc-b90d-fd65969fa9ea','過安樂山聞山上木葉有文如道士篆符云此山乃張道陵所寓二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','天師化去知何在，玉印相傳世共珍。',32,'全唐诗/poet.song.44000.json','["天師化去知何在，玉印相傳世共珍。", "故國子孫今尚死，滿山秋葉豈能神。"]'),
('84833f68-5e9f-4c6f-8573-08f0b661b386','過安樂山聞山上木葉有文如道士篆符云此山乃張道陵所寓二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','真人已不死，外慕墮空虛。',24,'全唐诗/poet.song.44000.json','["真人已不死，外慕墮空虛。", "猶餘好名意，滿樹寫天書。"]'),
('1d41aa2b-adea-4e88-8ff8-0d53926ad621','渝州寄王道矩','蘇軾','宋','宋诗','song-poetry','','[]','曾聞五月到渝州，水拍長亭砌下流。',64,'全唐诗/poet.song.44000.json','["曾聞五月到渝州，水拍長亭砌下流。", "惟有夢魂長繚繞，共論唐史更綢繆。", "舟經故國歲時改，霜落寒江波浪收。", "歸夢不成冬夜永，厭聞船上報更籌。"]'),
('ec5f0262-a710-479d-afff-e3ffa20322fc','江上看山','蘇軾','宋','宋诗','song-poetry','','[]','船上看山如走馬，倏忽過去數百群。',64,'全唐诗/poet.song.44000.json','["船上看山如走馬，倏忽過去數百群。", "前山槎牙忽變態，後嶺雜沓如驚奔。", "仰看微徑斜繚繞，上有行人高縹緲。", "舟中舉手欲與言，孤帆南去如飛鳥。"]'),
('f7f0b7f5-e3d5-49c1-afe3-cd1d736e797e','涪州得山胡次子由韵','蘇軾','宋','宋诗','song-poetry','','[]','終日鎖筠籠，回頭惜翠茸。',48,'全唐诗/poet.song.44000.json','["終日鎖筠籠，回頭惜翠茸。", "誰知聲㗲㗲，亦自意重重。", "夜宿煙生浦，朝鳴日上峰。", "故巢何足戀，鷹隼豈能容。"]'),
('347eb4e2-9e03-47eb-9d65-d6993b04b56d','留題仙都觀','蘇軾','宋','宋诗','song-poetry','','[]','山前江水流浩浩，山上蒼蒼松柏老。',136,'全唐诗/poet.song.44000.json','["山前江水流浩浩，山上蒼蒼松柏老。", "舟中行客去紛紛，古今換易如秋草。", "空山樓觀何崢嶸，真人王遠陰長生。", "飛符御氣朝百靈，悟道不復誦黄庭。", "龍車虎駕來下迎，去如旋風摶紫清。", "真人厭世不回顧，世間生死如朝暮。", "學仙度世豈無人，餐霞絕粒長苦辛。", "安得獨從逍遥君，泠然乘風駕浮雲，超世無有我獨存。"]'),
('77ab7915-2afd-4f7e-94a3-725ecbafb4b9','仙都山鹿','蘇軾','宋','宋诗','song-poetry','','[]','日月何促促，塵世苦局束。',88,'全唐诗/poet.song.44000.json','["日月何促促，塵世苦局束。", "仙子去無蹤，故山遺白鹿。", "仙人已去鹿無家，孤棲悵望層城霞。", "至今聞有遊洞客，夜來江市叫平沙。", "長松千樹風蕭瑟，仙宮去人無咫尺。", "夜鳴白鹿安在哉，滿山秋草無行迹。"]'),
('f16b63bb-b378-4578-801b-ff092e08d85e','江上值雪效歐陽體限不以鹽玉鶴鷺絮蝶飛舞之類爲比仍不使皓白潔素等字次子由韵','蘇軾','宋','宋诗','song-poetry','','[]','縮頸夜眠如凍龜，雪來惟有客先知。',320,'全唐诗/poet.song.44000.json','["縮頸夜眠如凍龜，雪來惟有客先知。", "江邊曉起浩無際，樹杪風多寒更吹。", "青山有似少年子，一夕變盡滄浪髭。", "方知陽氣在流水，沙上盈尺江無澌。", "隨風顛倒紛不擇，下滿坑谷高陵危。", "江空野闊落不見，入戶但覺輕絲絲。", "沾裳細看若刻鏤，豈有一一天工爲。", "霍然一揮遍九野，吁此權柄誰執持。", "世間苦樂知有幾，今我幸免沾膚肌。", "山夫只見壓樵擔，豈知带酒飄歌兒。", "天王臨軒喜有麥，宰相獻壽嘉及時。", "凍吟書生筆欲折，夜織貧女寒無幃。", "高人著屐踏冷冽，飄拂巾帽真仙姿。", "野僧斫路出門去，寒液滿鼻清淋漓。", "灑袍入袖濕靴底，亦有執板趨階墀。", "舟中行客何所愛，願得獵騎當風披。", "草中咻咻有寒兔，孤隼下擊千夫馳。", "敲冰煮鹿最可樂，我雖不飲强倒卮。", "楚人自古好弋獵，誰能往者我欲隨。", "紛紜旋轉從滿面，馬上操筆爲賦之。"]'),
('597bb4dc-59e9-4e81-a9ac-84350d734937','屈原塔','蘇軾','宋','宋诗','song-poetry','','["\u6000\u53e4", "\u7aef\u5348\u8282", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143", "\u98ce\u4fd7"]','楚人悲屈原，千載意未歇。',144,'全唐诗/poet.song.44000.json','["楚人悲屈原，千載意未歇。", "精魂飄何處，父老空哽咽。", "至今滄江上，投飯救饑渴。", "遺風成競渡，哀叫楚山裂。", "屈原古壯士，就死意甚烈。", "世俗安得知，眷眷不忍决。", "南賓舊屬楚，山上有遺塔。", "應是奉佛人，恐子就淪滅。", "此事雖無憑，此意固已切。", "古人誰不死，何必較考折。", "名聲實無窮，富貴亦暫熱。", "大夫知此理，所以持死節。"]'),
('cc38137c-e2a4-444b-935e-543d8ccd9f23','望夫臺','蘇軾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山頭孤石遠亭亭，江轉船回石似屏。',64,'全唐诗/poet.song.44000.json','["山頭孤石遠亭亭，江轉船回石似屏。", "可憐千古長如昨，船去船來自不停。", "浩浩長江赴滄海，紛紛過客似浮萍。", "誰能坐待山月出，照見寒影高伶俜。"]'),
('a45e907c-7239-4edc-919c-c12b7adfba8a','竹枝歌','蘇軾','宋','宋诗','song-poetry','','[]','蒼梧山高湘水深，中原北望度千岑。',288,'全唐诗/poet.song.44000.json','["蒼梧山高湘水深，中原北望度千岑。", "帝子南遊飄不返，惟有蒼蒼楓桂林。", "楓葉蕭蕭桂葉碧，萬里遠來超莫及。", "乘龍上天去無蹤，草木無情空寄泣。", "水濱擊鼓何喧闐，相將扣水求屈原。", "屈原已死今千載，滿船哀唱似當年。", "海濱長鯨徑千尺，食人爲糧安可入。", "招君不歸海水深，海魚豈解哀忠直。", "吁嗟忠直死無人，可憐懷王西入秦。", "秦關已閉無歸日，章華不復見車輪。", "君王去時簫鼓咽，父老送君車軸折。", "千里逃歸迷故鄉，南公哀痛彈長鋏。", "三戶亡秦信不虛，一朝兵起盡讙呼。", "當時項羽年最少，提劍本是耕田夫。", "橫行天下竟何事，棄馬烏江馬垂涕。", "項王已死無故人，首入漢庭身委地。", "富貴榮華豈足多，至今惟有冢嵯峨。", "故國淒涼人事改，楚鄉千古爲悲歌。"]'),
('3fa1effe-3c86-4974-abaa-901eb2136a62','過木櫪觀','蘇軾','宋','宋诗','song-poetry','','[]','石壁高千尺，微蹤遠欲無。',96,'全唐诗/poet.song.44000.json','["石壁高千尺，微蹤遠欲無。", "飛檐如劍寺，古柏似仙都。", "許子嘗高遯，行舟悔不迂。", "斬蛟聞猛烈，提劍想崎嶇。", "寂寞棺猶在，修崇世已愚。", "隠居人不識，化去俗爭吁。", "洞府煙霞遠，人間爪髮枯。", "飄飄乘倒景，誰復顧遺軀。"]'),
('14396a49-23b1-4e9f-a330-cefb24e93be9','八陣磧','蘇軾','宋','宋诗','song-poetry','','[]','平沙何茫茫，彷彿見石蕝。',180,'全唐诗/poet.song.44000.json','["平沙何茫茫，彷彿見石蕝。", "縱橫滿江上，歲歲沙水齧。", "孔明死已久，誰復辨行列。", "神兵非學到，自古不留訣。", "至人已心悟，後世徒妄說。", "自從漢道衰，蜂起盡姦傑。", "英雄不相下，禍難久連結。", "驅民市無烟，戰野江流血。", "萬人賭一擲，殺盡如沃雪。", "不爲久遠計，草草常無法。", "孔明最後起，意欲掃群孽。", "崎嶇事節制，隠忍久不决。", "志大遂成迂，歲月去如瞥。", "六師紛未整，一旦英氣折。", "惟餘八陣圖，千古壯夔峽。"]'),
('ace98c84-4f01-4130-940c-2bd8c2681324','諸葛鹽井','蘇軾','宋','宋诗','song-poetry','','[]','五行水本鹹，安擇江與井。',48,'全唐诗/poet.song.44000.json','["五行水本鹹，安擇江與井。", "如何不相入，此意誰復省。", "人心固難足，物理偶相逞。", "猶嫌取未多，井上無閑綆。"]'),
('8b569c5e-41fc-4908-b036-477e776cc4f2','白帝廟','蘇軾','宋','宋诗','song-poetry','','[]','朔風催入峽，慘慘去何之。',156,'全唐诗/poet.song.44000.json','["朔風催入峽，慘慘去何之。", "共指蒼山路，來朝白帝祠。", "荒城秋草滿，古樹野藤垂。", "浩蕩荆江遠，淒涼蜀客悲。", "遲回問風俗，涕泗憫興衰。", "故國依然在，遺民豈復知。", "一方稱警蹕，萬乘擁旌旂。", "遠略初吞漢，雄心豈在夔。", "崎嶇來野廟，閔默愧常時。", "破甑蒸山麥，長歌唱竹枝。", "荆邯真壯士，吳柱本經師。", "失計雖無及，圖王固已奇。", "猶餘帝王號，皎皎在門楣。"]'),
('e0a3ce99-5d71-411d-9742-d736a09dbcf4','入峽','蘇軾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','自昔懷幽賞，今茲得縱探。',288,'全唐诗/poet.song.44000.json','["自昔懷幽賞，今茲得縱探。", "長江連楚蜀，萬派瀉東南。", "合水來如電，黔波綠似藍。", "餘流細不數，遠勢競相參。", "入峽初無路，連山忽似龕。", "縈紆收浩渺，蹙縮作淵潭。", "風過如呼吸，雲生似吐含。", "墜崖鳴窣窣，垂蔓綠毿毿。", "冷翠多崖竹，孤生有石楠。", "飛泉飄亂雪，怪石走驚驂。", "絕澗知深淺，樵童忽兩三。", "人煙偶逢郭，沙岸可乘籃。", "野戍荒州縣，邦君古子男。", "放衙鳴晚鼓，留客薦霜柑。", "聞道黄精草，叢生綠玉篸。", "盡應充食飲，不見有彭聃。", "氣候冬猶暖，星河夜半涵。", "遺民悲昶衍，舊俗接魚蠶。", "板屋漫無瓦，巌居窄似庵。", "伐薪常冒險，得米不盈甔。", "歎息生何陋，劬勞不自慚。", "葉舟輕遠泝，大浪固嘗諳。", "矍鑠空相視，嘔啞莫與談。", "蠻荒安可住，幽邃信難妉。"]'),
('3117213e-b3fa-413f-83f8-60c1fcd012ef','巫山','蘇軾','宋','宋诗','song-poetry','','[]','瞿塘迤邐盡，巫峽崢嶸起。',288,'全唐诗/poet.song.44000.json','["瞿塘迤邐盡，巫峽崢嶸起。", "連峰稍可怪，石色變蒼翠。", "天工運神巧，漸欲作奇偉。", "坱軋勢方深，結搆意未遂。", "旁觀不暇瞬，步步造幽邃。", "蒼崖忽相逼，絕壁凜可悸。", "仰觀八九頂，俊爽淩顥氣。", "晃蕩天宇高，奔騰江水沸。", "孤超兀不讓，直拔勇無畏。", "攀緣見神宇，憩坐就石位。", "巉巉隔江波，一一問廟吏。", "遥觀神女石，綽約誠有以。", "俯首見斜鬟，拖霞弄修帔。", "人心隨物變，遠覺含深意。", "野老笑我旁，少年嘗屢至。", "去隨猿猱上，反以繩索試。", "石筍倚孤峰，突兀殊不類。", "世人喜神怪，論說驚幼穉。", "楚賦亦虛傳，神仙安有是。", "次問掃壇竹，云此今尚爾。", "翠葉紛下垂，婆娑綠鳳尾。", "風來自偃仰，若爲神物使。", "絕頂有三碑，詰曲古篆字。", "老人那解讀，偶見不能記。"]'),
('b96ef652-2613-433c-b535-a9bd13ab3383','巫山廟上下數十里有烏鳶無數取食於行舟之上舟人以神之故亦不敢害','蘇軾','宋','宋诗','song-poetry','','[]','群飛來去噪行人，得食無憂便可馴。',32,'全唐诗/poet.song.44000.json','["群飛來去噪行人，得食無憂便可馴。", "江上饑烏無足怪，野鷹何事亦頻頻。"]'),
('efe653ff-3823-47c5-a155-48058272df73','神女廟','蘇軾','宋','宋诗','song-poetry','','[]','大江從西來，上有千仞山。',180,'全唐诗/poet.song.44000.json','["大江從西來，上有千仞山。", "江山自環擁，恢詭富神姦。", "深淵鼉鱉橫，巨壑蛇龍頑。", "旌陽斬長蛟，雷雨移滄灣。", "蜀守降老蹇，至今带連環。", "縱橫若無主，蕩逸侵人寰。", "上帝降瑶姬，來處荆巫間。", "神仙豈在猛，玉座幽且閑。", "飄蕭駕風馭，弭節朝天關。", "倏忽巡四方，不知道里艱。", "古粧具法服，邃殿羅煙鬟。", "百神自奔走，雜沓來趨班。", "雲興靈怪聚，雲散鬼神還。", "茫茫夜潭靜，皎皎秋月彎。", "還應摇玉佩，來聽水潺潺。"]'),
('bcbeb7ae-2ec1-4ee1-9f5b-54ce26b4e75d','過巴東縣不泊聞頗有萊公遺迹','蘇軾','宋','宋诗','song-poetry','','[]','萊公昔未遇，寂寞在巴東。',60,'全唐诗/poet.song.44000.json','["萊公昔未遇，寂寞在巴東。", "聞道山中樹，猶餘手種松。", "江山養豪俊，禮數困英雄。", "執板迎官長，趨塵拜下風。", "當年誰刺史，應未識三公。"]'),
('92b7c774-c6d9-4ea8-9de0-e342d9e5372c','昭君村','蘇軾','宋','宋诗','song-poetry','','[]','昭君本楚人，艷色照江水。',68,'全唐诗/poet.song.44000.json','["昭君本楚人，艷色照江水。", "楚人不敢娶，謂是漢妃子。", "誰知去鄉國，萬里爲胡鬼。", "人言生女作門楣，昭君當時憂色衰。", "古來人事盡如此，反覆縱橫安可知。"]'),
('37a6a2d0-34fc-491a-bced-0b91e79e36bb','新灘','蘇軾','宋','宋诗','song-poetry','','[]','扁舟轉山曲，未至已先驚。',108,'全唐诗/poet.song.44000.json','["扁舟轉山曲，未至已先驚。", "白浪橫江起，槎牙似雪城。", "番番從高來，一一投澗坑。", "大魚不能上，暴鬣灘下橫。", "小魚散復合，瀺灂如遭烹。", "鸕鷀不敢下，飛過兩翅輕。", "白鷺誇瘦捷，插脚還敧傾。", "區區舟上人，薄技安敢呈。", "只應灘頭廟，頼此牛酒盈。"]'),
('96436c37-9d9e-4740-aaac-5e3ce737eebe','新灘阻風','蘇軾','宋','宋诗','song-poetry','','[]','北風吹寒江，來自兩山口。',96,'全唐诗/poet.song.44000.json','["北風吹寒江，來自兩山口。", "初聞似摇扇，漸覺平沙走。", "飛雲滿巌谷，舞雪穿窗牖。", "灘下三日留，識盡灘前叟。", "孤舟倦鴉軋，短纜困牽揉。", "嘗聞不終朝，今此獨何久。", "只應留遠人，此意固亦厚。", "吾今幸無事，閉戶爲飲酒。"]'),
('d527392d-9927-4afb-ac46-c59adf47be81','黄牛廟','蘇軾','宋','宋诗','song-poetry','','[]','江邊石壁高無路，上有黄牛不服箱。',64,'全唐诗/poet.song.44000.json','["江邊石壁高無路，上有黄牛不服箱。", "廟前行客拜且舞，擊鼓吹簫屠白羊。", "山下耕牛苦磽确，兩角磨崖四蹄濕。", "青芻半束長苦饑，仰看黄牛安可及。"]'),
('78a0357c-dc58-4555-8490-60113563e565','蝦蟆培','蘇軾','宋','宋诗','song-poetry','','[]','蟆背似覆盂，蟆頤似偃月。',84,'全唐诗/poet.song.44000.json','["蟆背似覆盂，蟆頤似偃月。", "謂是月中蟆，開口吐月液。", "根源來甚遠，百尺蒼崖裂。", "當時龍破山，此水隨龍出。", "入江江水濁，猶作深碧色。", "稟受苦潔清，獨與凡水隔。", "豈惟煮茶好，釀酒應無敵。"]'),
('98b8930c-94ac-40b3-9137-531869182e91','出峽','蘇軾','宋','宋诗','song-poetry','','[]','入峽喜巉巌，出峽愛平曠。',264,'全唐诗/poet.song.44000.json','["入峽喜巉巌，出峽愛平曠。", "吾心淡無累，遇境即安暢。", "東西徑千里，勝處頗屢訪。", "幽尋遠無厭，高絕每先上。", "前詩尚遺略，不錄久恐忘。", "憶從巫廟回，中路寒泉漲。", "汲歸真可愛，翠碧光滿盎。", "忽驚巫峽尾，巌腹有穿壙。", "仰見天蒼蒼，石室開南向。", "宣尼古廟宇，叢木作幃帳。", "鐵楯橫半空，俯瞰不計丈。", "古人誰架構，下有不測浪。", "石竇見天囷，瓦棺悲古葬。", "新灘阻風雪，村落去携杖。", "亦到龍馬溪，茅屋沽村釀。", "玉虛悔不至，實爲舟人誑。", "聞道石最奇，寤寐見怪狀。", "峽山富奇偉，得一知幾喪。", "苦恨不知名，歷歷但想像。", "今朝脫重險，楚水渺平蕩。", "魚多客庖足，風順行意王。", "追思偶成篇，聊助舟人唱。"]'),
('18f17f17-d2c0-4521-a4e4-7452551f611d','遊三游洞','蘇軾','宋','宋诗','song-poetry','','[]','凍雨霏霏半成雪，游人屨凍蒼苔滑。',32,'全唐诗/poet.song.44000.json','["凍雨霏霏半成雪，游人屨凍蒼苔滑。", "不辭携被巌底眠，洞口雲深夜無月。"]'),
('813c8c94-f7a4-4ac6-afbd-1d37aabd228c','遊洞之日有亭吏乞詩既爲留三絕句於洞之石壁明日至峽州吏又至意若未足乃復以此詩授之','蘇軾','宋','宋诗','song-poetry','','[]','一徑繞山翠，縈紆去似蛇。',144,'全唐诗/poet.song.44000.json','["一徑繞山翠，縈紆去似蛇。", "忽驚溪水急，爭看洞門呀。", "滑磴攀秋蔓，飛橋踏古槎。", "三扉迎北吹，一穴向西斜。", "歎息烟雲老，追思歲月遐。", "唐人昔未到，古俗此爲家。", "洞暖無風雪，山深富鹿豭。", "相逢衣盡草，環坐髻應髽。", "竈突依巌黑，樽罍就石漥。", "洪荒無傳記，想像在羲媧。", "此事今安有，遺蹤我獨嗟。", "山翁勸留句，强爲寫槎牙。"]'),
('51a41c19-efde-4c7b-873f-c204551d3a54','寄題清溪寺','蘇軾','宋','宋诗','song-poetry','','[]','口舌安足恃，韓非死說難。',96,'全唐诗/poet.song.44000.json','["口舌安足恃，韓非死說難。", "自知不可用，鬼谷乃真姦。", "遺書今未亡，小數不足觀。", "秦儀固新學，見利不知患。", "嗟時無桓文，使彼二子顛。", "死敗無足怪，夫子固使然。", "君看巧更窮，不若愚自安。", "遺宮若有神，頷首然吾言。"]'),
('e47ca49a-31ed-4c35-8ddb-3662f3c1a552','留題峽州甘泉寺','蘇軾','宋','宋诗','song-poetry','','[]','輕舟橫江來，弔古悲純孝。',96,'全唐诗/poet.song.44000.json','["輕舟橫江來，弔古悲純孝。", "逶迤尋遠跡，婉孌見遺貌。", "清泉不可挹，涸盡空石窖。", "古人飄何之，惟有風竹鬧。", "行行翫村落，戶戶懸網罩。", "民風坦和平，開戶夜無鈔。", "叢林富筍茹，平野絕虎豹。", "嗟哉此樂鄉，毋乃姜子教。"]'),
('4a63e3e9-8261-4244-820d-3b3cee3af333','夷陵縣歐陽永叔至喜堂','蘇軾','宋','宋诗','song-poetry','','[]','夷陵雖小邑，自古控荆吳。',120,'全唐诗/poet.song.44000.json','["夷陵雖小邑，自古控荆吳。", "形勢今無用，英雄久已無。", "誰知有文伯，遠謫自王都。", "人去年年改，堂傾歲歲扶。", "追思猶咎呂，感歎亦憐朱。", "舊種孤楠老，新霜一橘枯。", "清篇留峽洞，醉墨寫邦圖。", "故老問行客，長官今白鬚。", "著書多念慮，許國減歡娛。", "寄語公知否，還須數倒壺。"]'),
('8b9ea479-99c2-4d0f-96d9-7c6edc9968d8','息壤詩','蘇軾','宋','宋诗','song-poetry','','[]','帝息此壤，以藩幽臺。',100,'全唐诗/poet.song.44000.json','["帝息此壤，以藩幽臺。", "有神司之，隨取而培。", "帝勅下民，無敢或開。", "惟帝不言，以雷以雨。", "惟民知之，幸帝之怒。", "帝茫不知，誰敢以告。", "帝怒不常，下土是震。", "使民前知，是役於民。", "無是墳者，誰取誰干。", "惟其的之，是以射之。"]'),
('05827b6d-7df2-47d1-89e1-3bab86ccbcb1','渚宮','蘇軾','宋','宋诗','song-poetry','','[]','渚宮寂寞依古郢，楚地荒茫非故基。',272,'全唐诗/poet.song.44000.json','["渚宮寂寞依古郢，楚地荒茫非故基。", "二王臺閣已鹵莽，何況遠問縱橫時。", "楚王獵罷擊靈鼓，猛士操舟張水嬉。", "釣魚不復數魚鱉，大鼎千石烹蛟螭。", "當時郢人架宮殿，意思絕妙般與倕。", "飛樓百尺照湖水，上有燕趙千蛾眉。", "臨風揚揚意自得，長使宋玉作楚辭。", "秦兵西來取鐘簴，故宮禾黍秋離離。", "千年壯觀不可復，今之存者蓋已卑。", "池空野迥樓閣小，惟有深竹藏狐狸。", "臺中絳帳誰復見，臺下野水浮清漪。", "綠窗朱戶春晝閉，想見深屋彈朱絲。", "腐儒亦解愛聲色，何用白首談孔姬。", "沙泉半涸草堂在，破窗無紙風颸颸。", "陳公蹤迹最未遠，七瑞寥落今何之。", "百年人事知幾變，直恐荒廢成空陂。", "誰能爲我訪遺迹，草間應有湘東碑。"]'),
('fb6124b9-e9f8-4602-bece-7d9e6ee429c3','荆州十首  其一','蘇軾','宋','宋诗','song-poetry','','[]','游人出三峽，楚地盡平川。',48,'全唐诗/poet.song.44000.json','["游人出三峽，楚地盡平川。", "北客隨南賈，吳檣間蜀船。", "江侵平野斷，風捲白沙旋。", "欲問興亡意，重城自古堅。"]'),
('916b4279-6445-4fa3-8578-621a7898f04e','荆州十首  其二','蘇軾','宋','宋诗','song-poetry','','[]','南方舊戰國，慘澹意猶存。',48,'全唐诗/poet.song.44000.json','["南方舊戰國，慘澹意猶存。", "慷慨因劉表，淒涼爲屈原。", "廢城猶带井，古姓聚成村。", "亦解觀形勝，昇平不敢論。"]'),
('cc2bcc30-2b67-4fbc-9d12-6563258d655d','荆州十首  其三','蘇軾','宋','宋诗','song-poetry','','[]','楚地闊無邊，蒼茫萬頃連。',48,'全唐诗/poet.song.44000.json','["楚地闊無邊，蒼茫萬頃連。", "耕牛未嘗汗，投種去如捐。", "農事誰當勸，民愚亦可憐。", "平生事遊惰，那得怨凶年。"]'),
('1602afcd-2fa2-4b59-ad2a-74b983acf4f9','荆州十首  其四','蘇軾','宋','宋诗','song-poetry','','[]','朱檻城東角，高王此望沙。',48,'全唐诗/poet.song.44000.json','["朱檻城東角，高王此望沙。", "江山非一國，烽火畏三巴。", "戰骨淪秋草，危樓倚斷霞。", "百年豪傑盡，擾擾見魚蝦。"]'),
('ca58018b-a2a2-450d-8ba2-b2d58cc36bb0','荆州十首  其五','蘇軾','宋','宋诗','song-poetry','','[]','沙頭烟漠漠，來往厭喧卑。',48,'全唐诗/poet.song.44000.json','["沙頭烟漠漠，來往厭喧卑。", "野市分麞鬧，官船過渡遲。", "遊人多問卜，傖叟盡携龜。", "日暮江天靜，無人唱楚辭。"]'),
('b061a6f6-375d-4aa0-8e5e-8a89ad6e9165','荆州十首  其六','蘇軾','宋','宋诗','song-poetry','','[]','太守王夫子，山東老俊髦。',48,'全唐诗/poet.song.44000.json','["太守王夫子，山東老俊髦。", "壯年聞猛烈，白首見雄豪。", "食雁君應厭，驅車我正勞。", "中書有安石，慎勿賦離騷。"]'),
('72c4826b-a879-4b9c-adf2-a62339d18e51','荆州十首  其七','蘇軾','宋','宋诗','song-poetry','','[]','殘臘多風雪，荆人重歲時。',48,'全唐诗/poet.song.44000.json','["殘臘多風雪，荆人重歲時。", "客心何草草，里巷自嬉嬉。", "爆竹驚鄰鬼，驅儺聚小兒。", "故人應念我，相望各天涯。"]'),
('a6204d7d-c437-43ec-a502-ec04935a9114','荆州十首  其八','蘇軾','宋','宋诗','song-poetry','','[]','江水深成窟，潛魚大似犀。',48,'全唐诗/poet.song.44000.json','["江水深成窟，潛魚大似犀。", "赤鱗如琥珀，老枕勝玻璃。", "上客舉雕俎，佳人摇翠篦。", "登庖更作器，何以免屠刲。"]'),
('cc98963d-4e30-448f-a4c2-308487d2f8f6','荆州十首  其九','蘇軾','宋','宋诗','song-poetry','','[]','北雁來南國，依依似旅人。',48,'全唐诗/poet.song.44000.json','["北雁來南國，依依似旅人。", "縱橫遭折翼，感惻爲沾巾。", "平日誰能挹，高飛不可馴。", "故人持贈我，三嗅若爲珍。"]'),
('9ca68eb7-08ff-4987-9a8c-c89c89c2eacc','荆州十首  其一○','蘇軾','宋','宋诗','song-poetry','','[]','柳門京國道，驅馬及春陽。',48,'全唐诗/poet.song.44000.json','["柳門京國道，驅馬及春陽。", "野火燒枯草，東風動綠芒。", "北行連許鄧，南去極衡湘。", "楚境橫天下，懷王信弱王。"]'),
('66e8a6cc-410b-4f14-9b08-2beba411f845','荆門惠泉','蘇軾','宋','宋诗','song-poetry','','[]','泉源從高來，走下隨石脈。',96,'全唐诗/poet.song.44000.json','["泉源從高來，走下隨石脈。", "紛紛白沫亂，隠隠蒼崖坼。", "縈回成曲沼，清澈見肝膈。", "潀瀉爲長溪，奔駛蕩蛙蟈。", "初開不容椀，漸去已如帛。", "傳聞此山中，神物懶遭謫。", "不能致雷雨，灧灧吐寒碧。", "遂令山前人，千古灌稻麥。"]'),
('9da3e5c9-bac0-4373-95c0-aaa7ad7ddb01','次韵答荆門張都官維見和惠泉詩','蘇軾','宋','宋诗','song-poetry','','[]','楚人少井飲，地氣常不洩。',120,'全唐诗/poet.song.44000.json','["楚人少井飲，地氣常不洩。", "蓄之爲惠泉，坌若有所折。", "泉源本無情，豈問濁與澈。", "貪愚彼二水，終古恥莫雪。", "只應所處然，遂使語異別。", "泉傍地平衍，泉上山嵽嵲。", "君子慎所居，此義安可缺。", "古人貴言贈，敢用況高節。", "不爲冬霜乾，肯畏夏日烈。", "泠泠但不已，海遠要當徹。"]'),
('7e9a831a-020d-4c5b-8f2f-274224f35e7c','浰陽早發','蘇軾','宋','宋诗','song-poetry','','[]','富貴本無定，世人自榮枯。',96,'全唐诗/poet.song.44000.json','["富貴本無定，世人自榮枯。", "囂囂好名心，嗟我豈獨無。", "不能便退縮，但使進少徐。", "我行念西國，已分田園蕪。", "南來竟何事，碌碌隨商車。", "自進苟無補，乃是懶且愚。", "人生重意氣，出處夫豈徒。", "永懷江陽叟，種藕春滿湖。"]'),
('0a585d87-189a-490e-a674-4ffa09b74c4d','夜行觀星','蘇軾','宋','宋诗','song-poetry','','[]','天高夜氣嚴，列宿森就位。',96,'全唐诗/poet.song.44000.json','["天高夜氣嚴，列宿森就位。", "大星光相射，小星鬧若沸。", "天人不相干，嗟彼本何事。", "世俗强指摘，一一立名字。", "南箕與北斗，乃是家人器。", "天亦豈有之，無乃遂自謂。", "迫觀知何如，遠想偶有似。", "茫茫不可曉，使我長歎喟。"]'),
('d135790b-8a1d-4397-9583-b6b5a7e49723','漢水','蘇軾','宋','宋诗','song-poetry','','[]','捨棹忽逾月，沙塵困遠行。',96,'全唐诗/poet.song.44000.json','["捨棹忽逾月，沙塵困遠行。", "襄陽逢漢水，偶似蜀江清。", "蜀江固浩蕩，中有蛟與鯨。", "漢水亦云廣，欲涉安敢輕。", "文王化南國，遊女儼如卿。", "洲中浣紗子，環珮鏘鏘鳴。", "古風隨世變，寒水空泠泠。", "過之不敢慢，佇立整冠纓。"]'),
('4171b5a7-1fb1-45cb-b8da-2d587ac5f0b0','襄陽古樂府三首 野鷹來','蘇軾','宋','宋诗','song-poetry','','[]','野鷹來，萬山下，荒山無食鷹苦饑，飛來爲爾繫綵絲。',116,'全唐诗/poet.song.44000.json','["野鷹來，萬山下，荒山無食鷹苦饑，飛來爲爾繫綵絲。", "北原有兔老且白，年年養子秋食菽。", "我欲擊之不可得，年深兔老鷹力弱。", "野鷹來，城東有臺高崔巍。", "臺中公子著皮袖，東望萬里心悠哉。", "心悠哉，鷹何在。", "嗟爾公子歸無勞，使鷹可呼亦凡曹，天陰月黑狐夜嗥。"]'),
('956ca514-047d-43a2-a784-66e35da38341','襄陽古樂府三首 上堵吟','蘇軾','宋','宋诗','song-poetry','','[]','臺上有客吟秋風，悲聲蕭散飄入空。',96,'全唐诗/poet.song.44000.json','["臺上有客吟秋風，悲聲蕭散飄入空。", "臺邊游女來竊聽，欲學聲同意不同。", "君悲竟何事，千里金城兩稚子。", "白馬爲塞鳳爲關，山川無人空自閑。", "我悲亦何苦，江水冬更深，鯿魚冷難捕。", "悠悠江上聽歌人，不知我意徒悲辛。"]'),
('c30f5ac4-b723-45df-ace2-4fc53d55190a','襄陽古樂府三首 襄陽樂','蘇軾','宋','宋诗','song-poetry','','[]','使君未來襄陽愁，提戈入市裹氈裘。',96,'全唐诗/poet.song.44000.json','["使君未來襄陽愁，提戈入市裹氈裘。", "自從氈裘南渡沔，襄陽無事多春遊。", "襄陽春遊樂何許，峴山之陽漢江浦。", "使君朱旆來翻翻，人道使君似羊杜。", "道邊逢人問洛陽，中原苦戰春田荒。", "北人聞道襄陽樂，目送飛鴻應斷腸。"]'),
('f7226a54-9ea9-4220-aaf9-78a318317a63','峴山','蘇軾','宋','宋诗','song-poetry','','[]','遠客來自南，游塵昏峴首。',96,'全唐诗/poet.song.44000.json','["遠客來自南，游塵昏峴首。", "過關無百步，曠蕩吞楚藪。", "登高忽惆悵，千載意有偶。", "所憂誰復知，嗟我生苦後。", "團團山上檜，歲歲閱榆柳。", "大才固已殊，安得同永久。", "可憐山前客，倏忽星過罶。", "賢愚未及分，來者當自剖。"]'),
('1b306525-ef73-4c10-8eab-6712f0472fcb','萬山','蘇軾','宋','宋诗','song-poetry','','[]','西行度連山，北出臨漢水。',120,'全唐诗/poet.song.44000.json','["西行度連山，北出臨漢水。", "漢水蹙成潭，旋轉山之趾。", "禪房久已壞，古甃含清泚。", "下有仲宣欄，綆刻深容指。", "回頭望西北，隠隠龜背起。", "傳云古隆中，萬樹桑柘美。", "月炯轉山曲，山上見洲尾。", "綠水带平沙，盤盤如抱珥。", "山川近且秀，不到懶成恥。", "問之安能詳，畫地費簪箠。"]'),
('4d933f7d-f726-40fe-9603-18c83b47e895','隆中','蘇軾','宋','宋诗','song-poetry','','[]','諸葛來西國，千年愛未衰。',72,'全唐诗/poet.song.44000.json','["諸葛來西國，千年愛未衰。", "今朝游故里，蜀客不勝悲。", "誰言襄陽野，生此萬乘師。", "山中有遺貌，矯矯龍之姿。", "龍蟠山水秀，龍去淵潭移。", "空餘蜿蜒迹，使我寒涕垂。"]'),
('d1cad101-3249-45bc-853c-c81d56534e3c','竹葉酒','蘇軾','宋','宋诗','song-poetry','','[]','楚人汲漢水，釀酒古宜城。',48,'全唐诗/poet.song.44000.json','["楚人汲漢水，釀酒古宜城。", "春風吹酒熟，猶似漢江清。", "耆舊人何在，丘墳應已平。", "惟餘竹葉在，留此千古情。"]'),
('da39f2a9-e9f6-477a-94d5-3fe2daff1fd0','鯿魚','蘇軾','宋','宋诗','song-poetry','','[]','曉日照江水，遊鱼似玉瓶。',48,'全唐诗/poet.song.44000.json','["曉日照江水，遊鱼似玉瓶。", "誰言解縮項，貪餌每遭烹。", "杜老當年意，臨流憶孟生。", "吾今又悲子，輟筯涕縱橫。"]'),
('6661c3c0-054f-479f-86ea-902c297b2d02','食雉','蘇軾','宋','宋诗','song-poetry','','[]','雄雉曳修尾，驚飛向日斜。',72,'全唐诗/poet.song.44000.json','["雄雉曳修尾，驚飛向日斜。", "空中紛格鬬，綵羽落如花。", "喧呼勇不顧，投網誰復嗟。", "百錢得一雙，新味時所佳。", "烹煎雜鷄鶩，爪距漫槎牙。", "誰知化爲蜃，海上落飛鴉。"]'),
('b6365835-432a-4ea6-9a67-0a77a0f73fb1','新渠詩  其一','蘇軾','宋','宋诗','song-poetry','','[]','新渠之水，其來舒舒。',40,'全唐诗/poet.song.44000.json','["新渠之水，其來舒舒。", "溢流於野，至於通衢。", "渠成如神，民始不知。", "問誰爲之，邦君趙侯。"]'),
('6df7191f-1cbb-4839-bd92-eb7cc1d50ec6','新渠詩  其二','蘇軾','宋','宋诗','song-poetry','','[]','新渠之田，在渠左右。',40,'全唐诗/poet.song.44000.json','["新渠之田，在渠左右。", "渠來奕奕，如赴如湊。", "如雲斯積，如屋斯溜。", "嗟唐之人，始識秔稌。"]'),
('d6c7ca3a-9b86-4656-b76b-75cf967cf4e1','新渠詩  其三','蘇軾','宋','宋诗','song-poetry','','[]','新渠之民，自淮及潭。',40,'全唐诗/poet.song.44000.json','["新渠之民，自淮及潭。", "挈其婦姑，或走而顛。", "王命趙侯，宥我新民。", "無與王事，以訖七年。"]'),
('a9671237-1b22-4314-af4d-5f771dfddae7','新渠詩  其四','蘇軾','宋','宋诗','song-poetry','','[]','侯謂新民，爾既來止。',40,'全唐诗/poet.song.44000.json','["侯謂新民，爾既來止。", "其歸爾邑，告爾鄰里。", "良田千萬，爾擇爾取。", "爾耕爾食，遂爲爾有。"]'),
('dd3fbbd1-bcb3-4671-8e22-044079cb3a70','新渠詩  其五','蘇軾','宋','宋诗','song-poetry','','[]','築室於唐，孔碩且堅。',40,'全唐诗/poet.song.44000.json','["築室於唐，孔碩且堅。", "生爲唐民，飽粥與饘。", "死葬於唐，祭有雞豚。", "天子有命，我惟爾安。"]'),
('5c6294e3-fee1-4a4e-b0d3-8d81d33fa289','許州西湖','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖小雨晴，灧灧春渠長。',144,'全唐诗/poet.song.44000.json','["西湖小雨晴，灧灧春渠長。", "來從古城角，夜半轉新響。", "使君欲春游，浚沼役千掌。", "紛紜具畚鍤，鬧若蟻運壤。", "夭桃弄春色，生意寒猶怏。", "惟有落殘梅，標格若矜爽。", "游人坌已集，挈榼三且兩。", "醉客卧道傍，扶起尚偃仰。", "池臺信宏麗，貴與民同賞。", "但恐城市歡，不知田野愴。", "潁川七不登，野氣長蒼莽。", "誰知萬里客，湖上獨長想。"]'),
('db1c2e17-4867-40ea-bebb-e0fa68a3fcd9','雙鳬觀','蘇軾','宋','宋诗','song-poetry','','[]','王喬古仙子，時出觀人寰。',72,'全唐诗/poet.song.44000.json','["王喬古仙子，時出觀人寰。", "常爲漢郎吏，厭世去無還。", "雙鳬偶爲戲，聊以驚世頑。", "不然神仙迹，羅網安能攀。", "紛紛塵埃中，銅印紆青綸。", "安知無隠者，竊笑彼愚姦。"]'),
('f5e8753d-fb35-4859-ba78-57498228ee3e','潁大夫廟','蘇軾','宋','宋诗','song-poetry','','[]','人情難强回，天性可微感。',72,'全唐诗/poet.song.44000.json','["人情難强回，天性可微感。", "世人爭曲直，苦語費摇撼。", "大夫言何柔，暴主意自慘。", "荒祠傍孤冢，古隧有殘坎。", "千年惟茅焦，世亦貴其膽。", "不解此微言，脫衣徒勇敢。"]'),
('09f8595c-9a42-4376-88bc-7b67e06d40c7','阮籍嘯臺','蘇軾','宋','宋诗','song-poetry','','[]','阮生古狂達，遁世默無言。',72,'全唐诗/poet.song.44000.json','["阮生古狂達，遁世默無言。", "猶餘胸中氣，長嘯獨軒軒。", "高情遺萬物，不與世俗論。", "登臨偶自寫，激越蕩乾坤。", "醒爲嘯所發，飲爲醉所昏。", "誰能與之較，亂世足自存。"]'),
('52090beb-7733-4457-86a5-66ecab93411b','大雪獨留尉氏有客入驛呼與飲至醉詰旦客南去竟不知其誰','蘇軾','宋','宋诗','song-poetry','','[]','古驛無人雪滿庭，有客冒雪來自北。',96,'全唐诗/poet.song.44000.json','["古驛無人雪滿庭，有客冒雪來自北。", "紛紛笠上已盈寸，下馬登堂面蒼黑。", "苦寒有酒不能飲，見之何必問相識。", "我酌徐徐不滿觥，看客倒盡不留澀。", "千門晝閉行路絕，相與笑語不知夕。", "醉中不復問姓名，上馬忽去橫短策。"]'),
('9f07148a-f752-4953-a4e2-d49f7c05ae81','朱亥墓','蘇軾','宋','宋诗','song-poetry','','[]','昔日朱公子，雄豪不可追。',72,'全唐诗/poet.song.44000.json','["昔日朱公子，雄豪不可追。", "今來遊故國，大冢屈稱兒。", "平日輕公相，千金棄若遺。", "梁人不好事，名姓寄當時。", "魯史盜齊豹，求名誰復知。", "慎無怨世俗，猶不遭仲尼。"]'),
('b773dac9-e84b-4496-8cbe-17fc36a454c3','次韵水官詩','蘇軾','宋','宋诗','song-poetry','','[]','高人豈學畫，用筆乃其天。',240,'全唐诗/poet.song.44000.json','["高人豈學畫，用筆乃其天。", "譬如善游人，一一能操船。", "閻子本縫掖，疇昔慕雲淵。", "丹青偶爲戲，染指初嘗黿。", "愛之不自已，筆勢如風翻。", "傳聞貞觀中，左衽解椎鬟。", "南夷羞白雉，佛國貢青蓮。", "詔令擬王會，別殿寫戎蠻。", "熊冠金絡額，豹袖擁旛旜。", "傳入應門內，俯伏脫劍弮。", "天姿儼龍鳳，雜沓朝鵬鱣。", "神功與絕迹，後世兩莫扳。", "自從李氏亡，群盜竊山川。", "長安三日火，至寶隨飛烟。", "尚有脫身者，漂流出東關。", "三官豈容獨，得此今已編。", "吁嗟至神物，會合當有年。", "京城諸權貴，欲取百計難。", "贈以玉如意，豈能動高禪。", "惟應一篇詩，皎若畫在前。"]'),
('f807f01c-e09c-41f4-91d1-5d6789977a4d','辛丑十一月十九日既與子由別於鄭州西門之外馬上賦詩一篇寄之','蘇軾','宋','宋诗','song-poetry','','[]','不飲胡爲醉兀兀，此心已逐歸鞍發。',128,'全唐诗/poet.song.44000.json','["不飲胡爲醉兀兀，此心已逐歸鞍發。", "歸人猶自念庭闈，今我何以慰寂寞。", "登高回首坡壠隔，但見烏帽出復沒。", "苦寒念爾衣裘薄，獨騎瘦馬踏殘月。", "路人行歌居人樂，童僕怪我苦悽惻。", "亦知人生要有別，但恐歲月去飄忽。", "寒燈相對記疇昔，夜雨何時聽蕭瑟。", "君知此意不可忘，慎勿苦愛高官職。"]'),
('7277fc57-e102-4465-bbc1-ea40716a7f40','和子由澠池懷舊','蘇軾','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u4eba\u751f", "\u5b8b\u8bd7", "\u611f\u4f24"]','人生到處知何似，應似飛鴻踏雪泥。',64,'全唐诗/poet.song.44000.json','["人生到處知何似，應似飛鴻踏雪泥。", "泥上偶然留指爪，鴻飛那復計東西。", "老僧已死成新塔，壞壁無由見舊題。", "往日崎嶇還記否，路長人困蹇馿嘶。"]'),
('9ab65ba7-55bc-40b4-9edd-61efdf08c209','次韵劉京兆石林亭之作石本唐苑中物散流民間劉購得之','蘇軾','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','都城日荒廢，往事不可還。',144,'全唐诗/poet.song.44000.json','["都城日荒廢，往事不可還。", "惟餘古苑石，漂散尚人間。", "公來始購蓄，不憚道里艱。", "忽從塵埃中，來對冰雪顔。", "瘦骨拔凜凜，蒼根漱潺潺。", "唐人惟奇章，好石古莫攀。", "盡令屬牛氏，刻鑿紛斑斑。", "嗟此本何常，聚散實循環。", "人失亦人得，要不出區寰。", "君看劉李末，不能保河關。", "況此百株石，鴻毛於泰山。", "但當對石飲，萬事付等閑。"]'),
('372b3025-7dc2-4212-910e-8603623f8654','鳳翔八觀 石鼓歌','蘇軾','宋','宋诗','song-poetry','','["\u5199\u7269", "\u6292\u60c5", "\u5386\u53f2", "\u653f\u6cbb"]','冬十二月歲辛丑，我初從政見魯叟。',384,'全唐诗/poet.song.44000.json','["冬十二月歲辛丑，我初從政見魯叟。", "舊聞石鼓今見之，文字鬰律蛟蛇走。", "細觀初以指畫肚，欲讀嗟如箝在口。", "韓公好古生已遲，我今況又百年後。", "强尋偏傍推點畫，時得一二遺八九。", "我車既攻馬亦同，其魚維鱮貫之柳。", "古器縱橫猶識鼎，衆星錯落僅名斗。", "模糊半已隠瘢胝，詰曲猶能辨跟肘。", "娟娟缺月隠雲霧，濯濯嘉禾秀稂莠。", "漂流百戰偶然存，獨立千載誰與友。", "上追軒頡相唯諾，下揖冰斯同鷇㝅。", "憶昔周宣歌鴻雁，當時籀史變蝌蚪。", "厭亂人方思聖賢，中興天爲生耆耈。", "東征徐虜闞虓虎，北伏犬戎隨指嗾。", "象胥雜沓貢狼鹿，方召聯翩賜圭卣。", "遂因鼓鼙思將帥，豈爲考擊煩矇瞍。", "何人作頌比嵩高，萬古斯文齊岣嶁。", "勳勞至大不矜伐，文武未遠猶忠厚。", "欲尋年歲無甲乙，豈有名字記誰某。", "自從周衰更七國，竟使秦人有九有。", "埽除詩書誦法律，投棄俎豆陳鞭杻。", "當年何人佐祖龍，上蔡公子牽黄狗。", "登山刻石頌功烈，後者無繼前無偶。", "皆云皇帝巡四國，烹滅强暴救黔首。"]'),
('b174e4b8-419c-4154-9a94-6d5b5f472551','鳳翔八觀 詛楚文','蘇軾','宋','宋诗','song-poetry','','[]','崢嶸開元寺，彷彿祈年觀。',144,'全唐诗/poet.song.44000.json','["崢嶸開元寺，彷彿祈年觀。", "舊築掃成空，古碑埋不爛。", "詛書雖可讀，字法嗟久換。", "詞云秦嗣王，敢使祝用瓚。", "先君穆公世，與楚約相捍。", "質之於巫咸，萬葉期不叛。", "今其後嗣王，乃敢搆多難。", "刳胎殺無罪，親族遭圉絆。", "計其所稱訴，何啻桀紂亂。", "吾聞古秦俗，面詐背不汗。", "豈惟公子卬，社鬼亦遭謾。", "遼哉千載後，發我一笑粲。"]'),
('47f8faa0-e2c5-4349-b248-d12ba3f280ee','鳳翔八觀 王維吳道子畫','蘇軾','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','何處訪吳畫，普門與開元。',226,'全唐诗/poet.song.44000.json','["何處訪吳畫，普門與開元。", "開元有東塔，摩詰留手痕。", "吾觀畫品中，莫如二子尊。", "道子實雄放，浩如海波翻。", "當其下手風雨快，筆所未到氣已吞。", "亭亭雙林間，彩暈扶桑暾。", "中有至人談寂滅，悟者悲涕迷者手自捫。", "蠻君鬼伯千萬萬，相排競進頭如黿。", "摩詰本詩老，佩芷襲芳蓀。", "今觀此壁畫，亦若其詩清且敦。", "祇園弟子盡鶴骨，心如死灰不復溫。", "門前兩叢竹，雪節貫霜根。", "交柯亂葉動無數，一一皆可尋其源。", "吳生雖妙絕，猶以畫工論。", "摩詰得之於象外，有如仙翮謝籠樊。", "吾觀二子皆神俊，又於維也斂衽無間言。"]'),
('7a59d27b-920c-4ae2-88a6-02deed7e1d08','鳳翔八觀 維摩像唐楊惠之塑在天柱寺','蘇軾','宋','宋诗','song-poetry','','[]','昔者子輿病且死，其友子祀往問之。',160,'全唐诗/poet.song.44000.json','["昔者子輿病且死，其友子祀往問之。", "跰𨇤鑒井自歎息，造物將安以我爲。", "今觀古塑維摩像，病骨磊嵬如枯龜。", "乃知至人外生死，此身變化浮雲隨。", "世人豈不碩且好，身雖未病心已疲。", "此叟神完中有恃，談笑可却千熊羆。", "當其在時或問法，俯首無言心自知。", "至今遺像兀不語，與昔未死無增虧。", "田翁里婦那肯顧，時有野鼠銜其髭。", "見之使人每自失，誰能與詰無言師。"]'),
('fb99d336-8fc5-4132-95b9-8cfd62575d0e','鳳翔八觀 東湖','蘇軾','宋','宋诗','song-poetry','','[]','吾家蜀江上，江水清如藍。',288,'全唐诗/poet.song.44000.json','["吾家蜀江上，江水清如藍。", "爾來走塵土，意思殊不堪。", "況當岐山下，風物尤可慚。", "有山禿如赭，有水濁如泔。", "不謂郡城東，數步見湖潭。", "入門便清奧，怳如夢西南。", "泉源從高來，隨波走涵涵。", "東去觸重阜，盡爲湖所貪。", "但見蒼石螭，開口吐清甘。", "借汝腹中過，胡爲目眈眈。", "新荷弄晚凉，輕棹極幽探。", "飄颻忘遠近，偃息遺珮篸。", "深有龜與魚，淺有螺與蚶。", "曝晴復戲雨，戢戢多於蠶。", "浮沉無停餌，倏忽遽滿籃。", "絲緡雖强致，瑣細安足戡。", "聞昔周道興，翠鳳棲孤嵐。", "飛鳴飲此水，照影弄毿毿。", "至今多梧桐，合抱如彭聃。", "彩羽無復見，上有鸇搏鵪。", "嗟予生雖晚，好古意所妉。", "圖書已漫漶，猶復訪僑郯。", "卷阿詩可繼，此意久已含。", "扶風古三輔，政事豈汝諳。"]'),
('4016bdcd-132d-4b3b-9bc9-06fe6d5d0bed','鳳翔八觀 真興寺閣','蘇軾','宋','宋诗','song-poetry','','["\u53d9\u4e8b", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','山川與城郭，漠漠同一形。',120,'全唐诗/poet.song.44000.json','["山川與城郭，漠漠同一形。", "市人與鴉鵲，浩浩同一聲。", "此閣幾何高，何人之所營。", "側身送落日，引手攀飛星。", "當年王中令，斫木南山頳。", "寫真留閣下，鐵面眼有稜。", "身强八九尺，與閣兩崢嶸。", "古人雖暴恣，作事今世驚。", "登者尚呀喘，作者何以勝。", "曷不觀此閣，其人勇且英。"]'),
('5fabcae0-b194-4911-9a90-8dff9245db98','鳳翔八觀 李氏園','蘇軾','宋','宋诗','song-poetry','','[]','朝遊北城東，回首見修竹。',288,'全唐诗/poet.song.44000.json','["朝遊北城東，回首見修竹。", "下有朱門家，破牆圍古屋。", "舉鞭叩其戶，幽響答空谷。", "入門所見夥，十步九移目。", "異花兼四方，野鳥喧百族。", "其西引溪水，活活轉牆曲。", "東注入深林，林深窗戶綠。", "水光兼竹浄，時有獨立鵠。", "林中百尺松，歲久蒼鱗蹙。", "豈惟此地少，意恐關中獨。", "小橋過南浦，夾道多喬木。", "隠如城百雉，挺若舟千斛。", "陰陰日光淡，黯黯秋氣蓄。", "盡東爲方池，野雁雜家鶩。", "紅梨驚合抱，映島孤雲馥。", "春光水溶漾，雪陣風翻撲。", "其北臨長溪，波聲卷平陸。", "北山卧可見，蒼翠間磽禿。", "我時來周覽，問此誰所築。", "云昔李將軍，負險乘衰叔。", "抽錢算間口，但未榷羹粥。", "當時奪民田，失業安敢哭。", "誰家美園囿，籍沒不容贖。", "此亭破千家，鬰鬰城之麓。"]'),
('4a60afdb-8745-4d5a-8290-37d6b990e993','鳳翔八觀 秦穆公墓','蘇軾','宋','宋诗','song-poetry','','[]','橐泉在城東，墓在城中無百步。',107,'全唐诗/poet.song.44000.json','["橐泉在城東，墓在城中無百步。", "乃知昔未有此城，秦人以泉識公墓。", "昔公生不誅孟明，豈有死之日而忍用其良。", "乃知三子徇公意，亦如齊之二子從田橫。", "古人感一飯，尚能殺其身。", "今人不復見此等，乃以所見疑古人。", "古人不可望，今人益可傷。"]'),
('2c109ef4-652a-43a1-af4f-9b041bad909b','次韵子由辛丑除日見寄','蘇軾','宋','宋诗','song-poetry','','[]','薄宦驅我西，遠別不容惜。',264,'全唐诗/poet.song.44000.json','["薄宦驅我西，遠別不容惜。", "方愁後會遠，未暇憂歲夕。", "强歡雖有酒，冷酌不成席。", "秦烹惟羊羹，隴饌有熊腊。", "念爲兒童歲，屈指已成昔。", "往事今何追，忽若箭已釋。", "感時嗟事變，所得不償失。", "府卒來驅儺，矍鑠驚遠客。", "愁來豈有魔，煩汝爲攘磔。", "寒梅與凍杏，嫩萼初似麥。", "攀條爲惆悵，玉蕊何時折。", "不憂春艷晚，行見棄夏覈。", "人生行樂耳，安用聲名籍。", "胡爲獨多感，不見膏自炙。", "詩來苦相寬，子意遠可射。", "依依見其面，疑子在咫尺。", "兄今雖小官，幸忝佐方伯。", "北池近所鑿，中有汧水碧。", "臨池飲美酒，尚可消永日。", "但恐詩力弱，鬬健未免馘。", "詩成十日到，誰謂千里隔。", "一月寄一篇，憂愁何足擲。"]'),
('7914b31e-414f-4269-a6fc-d33a36a04cbf','新葺小園二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','短竹蕭蕭倚北牆，斬茅披棘見幽芳。',64,'全唐诗/poet.song.44000.json','["短竹蕭蕭倚北牆，斬茅披棘見幽芳。", "使君尚許分池綠，鄰舍何妨借樹凉。", "亦有杏花充窈窕，更煩鶑舌奏鏗鏘。", "身閑酒美誰來勸，坐看花光照水光。"]'),
('29b7f2b4-6edf-4233-a296-cbc01fd0259b','新葺小園二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','三年輒去豈無鄉，種樹穿池亦漫忙。',64,'全唐诗/poet.song.44000.json','["三年輒去豈無鄉，種樹穿池亦漫忙。", "暫賞不須心汲汲，再來惟恐鬢蒼蒼。", "應成庾信吟枯柳，誰記山公醉夕陽。", "去後莫憂人剪伐，西鄰幸許庇甘棠。"]'),
('7bd422d1-0abf-41d8-86a5-6e2f50709dbb','壬寅二月有詔令郡吏分往屬縣減决囚禁自十三日受命出府至寶雞虢郿盩厔四縣既畢事因朝謁太平宮而宿於南溪溪堂遂並南山而西至樓觀大秦寺延生觀仙遊潭十九日乃歸作詩五百言以記凡所經歷者寄子由','蘇軾','宋','宋诗','song-poetry','','[]','遠人罹水旱，王命釋俘囚。',288,'全唐诗/poet.song.44000.json','["遠人罹水旱，王命釋俘囚。", "分縣傳明詔，尋山得勝遊。", "蕭條初出郭，曠蕩實消憂。", "薄暮來孤鎮，登臨憶武侯。", "崢嶸依絕壁，蒼茫瞰奔流。", "半夜人呼急，橫空火氣浮。", "天遥殊不辨，風急已難收。", "曉入陳倉縣，猶餘賣酒樓。", "烟煤已狼藉，吏卒尚呀咻。", "雞嶺雲霞古，龍宮殿宇幽。", "南山連大散，歸路走吾州。", "欲往安能遂，將還爲少留。", "回趨西虢道，却渡小河洲。", "聞道磻溪石，猶存渭水頭。", "蒼崖雖有迹，大釣本無鈎。", "東去過郿塢，孤城象漢劉。", "誰言董公健，竟復伍孚仇。", "白刃俄生肘，黄金謾似丘。", "平生聞太白，一見駐行騶。", "鼓角誰能試，風雷果致不。", "巌崖已奇絕，冰雪更琱鎪。", "春旱憂無麥，山靈喜有湫。", "蛟龍懶方睡，瓶罐小容偷。", "二曲林泉勝，三川氣象侔。"]'),
('2f52ae40-c864-4d43-8f34-04b8fbfa863e','太白山下早行至橫渠鎮書崇壽院壁','蘇軾','宋','宋诗','song-poetry','','[]','馬上續殘夢，不知朝日昇。',48,'全唐诗/poet.song.44000.json','["馬上續殘夢，不知朝日昇。", "亂山橫翠幛，落月澹孤燈。", "奔走煩郵吏，安閑愧老僧。", "再遊應眷眷，聊亦記吾曾。"]'),
('32ba7134-ee8c-43cd-9f60-30797137ce11','留題延生觀後山上小堂','蘇軾','宋','宋诗','song-poetry','','[]','溪山愈好意無厭，上到巉巉第幾尖。',64,'全唐诗/poet.song.44000.json','["溪山愈好意無厭，上到巉巉第幾尖。", "深谷野禽毛羽怪，上方仙子鬢眉纖。", "不慚弄玉騎丹鳳，應逐嫦娥駕老蟾。", "澗草巌花自無主，晚來蝴蝶入疏簾。"]'),
('0b4b5fad-c06d-4502-8dd2-5b6f98c0e214','留題仙遊潭中興寺寺東有玉女洞洞南有馬融讀書石室過潭而南山石益奇潭上有橋畏其險不敢渡','蘇軾','宋','宋诗','song-poetry','','[]','清潭百尺皎無泥，山木陰陰谷鳥啼。',64,'全唐诗/poet.song.44000.json','["清潭百尺皎無泥，山木陰陰谷鳥啼。", "蜀客曾遊明月峽，秦人今在武陵溪。", "獨攀書室窺巌竇，還訪仙姝款石閨。", "猶有愛山心未至，不將雙脚踏飛梯。"]'),
('4f0a996c-07a8-4370-9b63-78abbe45ee8e','樓觀','蘇軾','宋','宋诗','song-poetry','','[]','門前古碣卧斜陽，閱世如流事可傷。',64,'全唐诗/poet.song.44000.json','["門前古碣卧斜陽，閱世如流事可傷。", "長有幽人悲晉惠，强修遺廟學秦皇。", "丹砂久窖井水赤，白朮誰燒厨竈香。", "聞道神仙亦相過，只疑田叟是庚桑。"]'),
('7b4aeda7-b1e5-4e46-9113-f58cb3ef36c7','郿塢','蘇軾','宋','宋诗','song-poetry','','[]','衣中甲厚行何懼，塢裏金多退足憑。',32,'全唐诗/poet.song.44000.json','["衣中甲厚行何懼，塢裏金多退足憑。", "畢竟英雄誰得似，臍脂自照不須燈。"]'),
('743e2417-3654-41c7-9526-3f909fd9ea2c','磻溪石','蘇軾','宋','宋诗','song-poetry','','[]','墨突不暇黔，孔席未嘗暖。',48,'全唐诗/poet.song.44000.json','["墨突不暇黔，孔席未嘗暖。", "安知渭上叟，跪石留雙骭。", "一朝嬰世故，辛苦平多難。", "亦欲就安眠，旅人譏客懶。"]'),
('80019ebb-d0f6-44fe-937c-2ffc5676a38e','石鼻城','蘇軾','宋','宋诗','song-poetry','','[]','平時戰國今無在，陌上征夫自不閑。',64,'全唐诗/poet.song.44000.json','["平時戰國今無在，陌上征夫自不閑。", "北客初來試新險，蜀人從此送殘山。", "獨穿暗月朦朧裏，愁渡奔河蒼茫間。", "漸入西南風景變，道邊修竹水潺潺。"]'),
('4487c1b8-dc6d-4ee9-8b99-298a1c420e42','次韵子由岐下詩 北亭','蘇軾','宋','宋诗','song-poetry','','[]','誰人築短牆，橫絕擁吾堂。',24,'全唐诗/poet.song.44000.json','["誰人築短牆，橫絕擁吾堂。", "不作新亭檻，幽花爲誰香。"]'),
('7c2225f9-ec0f-4e58-a714-a5174f8a452b','次韵子由岐下詩 橫池','蘇軾','宋','宋诗','song-poetry','','[]','明月入我池，皎皎鋪紵縞。',24,'全唐诗/poet.song.44000.json','["明月入我池，皎皎鋪紵縞。", "何日變成緇，太玄吾懶草。"]'),
('193f8cd0-9169-4f59-9981-79aa48f1dd24','次韵子由岐下詩 短橋','蘇軾','宋','宋诗','song-poetry','','[]','誰能鋪白簟，永日卧朱橋。',24,'全唐诗/poet.song.44000.json','["誰能鋪白簟，永日卧朱橋。", "樹影欄邊轉，波光版底摇。"]'),
('0c8b8026-1625-4677-8a6a-ce26794ec366','次韵子由岐下詩 軒窗','蘇軾','宋','宋诗','song-poetry','','[]','東鄰多白楊，夜作雨聲急。',24,'全唐诗/poet.song.44000.json','["東鄰多白楊，夜作雨聲急。", "窗下獨無眠，秋蟲見燈入。"]'),
('2464f04d-1b04-499e-a08c-6b819c22a65a','次韵子由岐下詩 曲檻','蘇軾','宋','宋诗','song-poetry','','[]','流水照朱欄，浮萍亂明鑑。',24,'全唐诗/poet.song.44000.json','["流水照朱欄，浮萍亂明鑑。", "誰見檻上人，無言觀物泛。"]'),
('4b102f2b-e80e-4356-8f2b-3046a46c42d0','次韵子由岐下詩 雙池','蘇軾','宋','宋诗','song-poetry','','[]','汧流入城郭，亹亹渡千家。',24,'全唐诗/poet.song.44000.json','["汧流入城郭，亹亹渡千家。", "不見雙池水，長漂十里花。"]'),
('e963afea-2e3a-4be6-bce1-ff5452971527','次韵子由岐下詩 荷葉','蘇軾','宋','宋诗','song-poetry','','[]','田田抗朝陽，節節卧春水。',24,'全唐诗/poet.song.44000.json','["田田抗朝陽，節節卧春水。", "平鋪亂萍葉，屢動報魚子。"]'),
('58ef5b22-b111-465d-9c63-b9212b6299c1','次韵子由岐下詩 魚','蘇軾','宋','宋诗','song-poetry','','[]','湖上移魚子，初生不畏人。',24,'全唐诗/poet.song.44000.json','["湖上移魚子，初生不畏人。", "自從識鈎餌，欲見更無因。"]'),
('f923b6e7-eaab-458f-9277-ccaef2b9857b','次韵子由岐下詩 牡丹','蘇軾','宋','宋诗','song-poetry','','[]','花好長患稀，花多信佳否。',24,'全唐诗/poet.song.44000.json','["花好長患稀，花多信佳否。", "未有四十枝，枝枝大如斗。"]'),
('76af1254-80ef-416f-8c2d-b55985de8a83','次韵子由岐下詩 桃花','蘇軾','宋','宋诗','song-poetry','','[]','爭開不待葉，密綴欲無條。',24,'全唐诗/poet.song.44000.json','["爭開不待葉，密綴欲無條。", "傍沼人窺鑑，驚魚水濺橋。"]'),
('92adcd2a-2ab1-4bf9-b4b3-f07260fd0fa9','次韵子由岐下詩 李','蘇軾','宋','宋诗','song-poetry','','[]','不及梨英軟，應慚梅萼紅。',24,'全唐诗/poet.song.44000.json','["不及梨英軟，應慚梅萼紅。", "西園有千葉，淡佇更纖濃。"]'),
('1f781c7a-4b42-48cc-8411-fdcf9649f1f2','次韵子由岐下詩 杏','蘇軾','宋','宋诗','song-poetry','','[]','開花送餘寒，結子及新火。',24,'全唐诗/poet.song.44000.json','["開花送餘寒，結子及新火。", "關中幸無梅，汝强充鼎和。"]'),
('b0ceb616-0e95-4ba6-992b-f3419c5d824b','次韵子由岐下詩 梨','蘇軾','宋','宋诗','song-poetry','','[]','霜降紅梨熟，柔柯已不勝。',24,'全唐诗/poet.song.44000.json','["霜降紅梨熟，柔柯已不勝。", "未嘗蠲夏渴，長見助春冰。"]'),
('f6873b7c-e3f6-425b-9b24-d35437bbe061','次韵子由岐下詩 棗','蘇軾','宋','宋诗','song-poetry','','[]','居人幾番老，棗樹未成槎。',24,'全唐诗/poet.song.44000.json','["居人幾番老，棗樹未成槎。", "汝長才堪軸，吾歸已及瓜。"]'),
('c8668ebd-f878-4604-9f96-2ee5fddf1f4e','次韵子由岐下詩 櫻桃','蘇軾','宋','宋诗','song-poetry','','[]','獨遶櫻桃樹，酒醒喉肺乾。',24,'全唐诗/poet.song.44000.json','["獨遶櫻桃樹，酒醒喉肺乾。", "莫除枝上露，從向口中漙。"]'),
('3a302375-1352-4689-b5fa-789c877e858a','次韵子由岐下詩 石榴','蘇軾','宋','宋诗','song-poetry','','[]','風流意不盡，獨自送殘芳。',24,'全唐诗/poet.song.44000.json','["風流意不盡，獨自送殘芳。", "色作裙腰染，名隨酒盞狂。"]'),
('895b5d88-2a8c-4042-863d-a05be6f3d15d','次韵子由岐下詩 樗','蘇軾','宋','宋诗','song-poetry','','[]','自昔爲神樹，空聞蜩鵙鳴。',24,'全唐诗/poet.song.44000.json','["自昔爲神樹，空聞蜩鵙鳴。", "社公煩見輟，爲爾致羊羹。"]'),
('3f4658da-0e13-4dd2-b33b-7b45f868de9f','次韵子由岐下詩 槐','蘇軾','宋','宋诗','song-poetry','','[]','采擷殊未厭，忽然已成陰。',24,'全唐诗/poet.song.44000.json','["采擷殊未厭，忽然已成陰。", "蟬鳴看不見，鶴立赴還深。"]'),
('d88a35c9-f0ed-44a9-935e-f40a8ced49a7','次韵子由岐下詩 檜','蘇軾','宋','宋诗','song-poetry','','[]','强致南山樹，來經渭水灘。',24,'全唐诗/poet.song.44000.json','["强致南山樹，來經渭水灘。", "生成未有意，鴉鵲莫相干。"]'),
('df556143-1ce4-4004-9c28-598cd95ac689','次韵子由岐下詩 松','蘇軾','宋','宋诗','song-poetry','','[]','依依古松子，鬰鬰綠毛身。',24,'全唐诗/poet.song.44000.json','["依依古松子，鬰鬰綠毛身。", "每長須成節，明年漸庇人。"]'),
('e1b53e79-b835-4b8a-b7be-3a6de860d116','次韵子由岐下詩 柳','蘇軾','宋','宋诗','song-poetry','','[]','今年手自栽，問我何年去。',24,'全唐诗/poet.song.44000.json','["今年手自栽，問我何年去。", "他年我復來，摇落傷人意。"]'),
('496abf8e-2dc7-4afd-a38a-87d9a82fbd7c','真興寺閣禱雨','蘇軾','宋','宋诗','song-poetry','','[]','太守親從千騎禱，神翁遠借一杯清。',64,'全唐诗/poet.song.44000.json','["太守親從千騎禱，神翁遠借一杯清。", "雲陰黯黯將噓遍，雨意昏昏欲醖成。", "已覺微風吹袂冷，不堪殘日傍山明。", "今年秋熟君知否，應向江南飽食粳。"]'),
('2090a9c8-6345-4f16-aa87-70bc7cc84f83','攓雲篇','蘇軾','宋','宋诗','song-poetry','','[]','物役會有時，星言從高駕。',108,'全唐诗/poet.song.44000.json','["物役會有時，星言從高駕。", "道逢南山雲，欻吸如電過。", "竟誰使令之，衮衮從空下。", "龍移相排拶，鳳舞或頹亞。", "散爲東郊霧，凍作枯樹稼。", "或飛入吾車，偪仄礙肘胯。", "摶取置笥中，提携返茅舍。", "開緘乃放之，掣去仍變化。", "雲兮汝歸山，無使達官怕。"]'),
('c37f7771-562a-4d4f-9ed4-2271f1391c60','讀開元天寶遺事三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','姚宋亡來事事生，一官銖重萬人輕。',32,'全唐诗/poet.song.44000.json','["姚宋亡來事事生，一官銖重萬人輕。", "朔方老將風流在，不取西蕃石堡城。"]'),
('4a213422-38cd-4469-a6c9-77597a2bf39f','讀開元天寶遺事三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','潭裏舟船百倍多，廣陵銅器越溪羅。',32,'全唐诗/poet.song.44000.json','["潭裏舟船百倍多，廣陵銅器越溪羅。", "三郎官爵如泥土，爭唱弘農得寶歌。"]'),
('0787204e-6cac-41ed-b27a-6a0362808aa4','讀開元天寶遺事三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','琵琶絃急衮梁州，羯鼓聲高舞臂韝。',32,'全唐诗/poet.song.44000.json','["琵琶絃急衮梁州，羯鼓聲高舞臂韝。", "破費八姨三百萬，大唐天子要纏頭。"]'),
('14c0d695-3015-4ac4-af78-5e6f2d633317','壬寅重九不預會獨遊普門寺僧閣有懷子由','蘇軾','宋','宋诗','song-poetry','','[]','花開酒美盍言歸，來看南山冷翠微。',64,'全唐诗/poet.song.44000.json','["花開酒美盍言歸，來看南山冷翠微。", "憶弟淚如雲不散，望鄉心與雁南飛。", "明年縱健人應老，昨日追歡意正違。", "不問秋風强吹帽，秦人不笑楚人譏。"]'),
('da95e316-bcbf-422d-a54f-9df185ab14cf','太白詞  其一','蘇軾','宋','宋诗','song-poetry','','[]','雷闐闐，山晝晦。',37,'全唐诗/poet.song.44000.json','["雷闐闐，山晝晦。", "風振野，神將駕。", "載雲䍐，從玉虬。", "旱既甚，蹷往救，道阻修兮。"]'),
('ade0eb51-dd17-4455-9fc3-4556914790aa','太白詞  其二','蘇軾','宋','宋诗','song-poetry','','[]','旌旂翻，疑有無。',37,'全唐诗/poet.song.44000.json','["旌旂翻，疑有無。", "日慘變，神在塗。", "飛赤篆，訴閶闔。", "走陰符，行羽檄，萬靈集兮。"]'),
('a586d996-215c-441f-aa0a-cb4b40f90ecf','太白詞  其三','蘇軾','宋','宋诗','song-poetry','','[]','風爲幄，雲爲蓋。',37,'全唐诗/poet.song.44000.json','["風爲幄，雲爲蓋。", "滿堂爛，神既至。", "紛醉飽，錫以雨。", "百川溢，施溝渠，歌且舞兮。"]'),
('864d9d69-bc8b-4a5f-9e72-b98c85e5e0d0','太白詞  其四','蘇軾','宋','宋诗','song-poetry','','[]','騎裔裔，車斑斑。',37,'全唐诗/poet.song.44000.json','["騎裔裔，車斑斑。", "鼓簫悲，神欲還。", "轟振凱，隠林谷。", "執妖厲，歸獻馘，千里肅兮。"]'),
('1af456e2-6f84-45bf-8de2-e50fbc34b952','太白詞  其五','蘇軾','宋','宋诗','song-poetry','','[]','神之來，悵何晚。',37,'全唐诗/poet.song.44000.json','["神之來，悵何晚。", "山重複，路幽遠。", "神之去，飄莫追。", "德未報，民之思，永萬祀兮。"]'),
('2f83923c-4493-4951-ab80-1ca3202a247e','九月二十日微雪懷子由弟二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','岐陽九月天微雪，已作蕭條歲暮心。',64,'全唐诗/poet.song.44000.json','["岐陽九月天微雪，已作蕭條歲暮心。", "短日送寒砧杵急，冷官無事屋廬深。", "愁腸別後能消酒，白髮秋來已上簪。", "近買貂裘堪出塞，忽思乘傳問西琛。"]'),
('02d25e67-7704-4847-b537-ecc3abcbb1ff','九月二十日微雪懷子由弟二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','江上同舟詩滿篋，鄭西分馬涕垂膺。',64,'全唐诗/poet.song.44000.json','["江上同舟詩滿篋，鄭西分馬涕垂膺。", "未成報國慚書劍，豈不懷歸畏友朋。", "官舍度秋驚歲晚，寺樓見雪與誰登。", "遥知讀易東窗下，車馬敲門定不譍。"]'),
('8ec53ff9-1f31-4cdf-bbfe-bcbadac04677','與李彭年同送崔岐歸二曲馬上口占','蘇軾','宋','宋诗','song-poetry','','[]','霜乾木落愛秦川，興發身輕逐鳥翩。',64,'全唐诗/poet.song.44000.json','["霜乾木落愛秦川，興發身輕逐鳥翩。", "貪看暮山忘遠近，强陪歸客更流連。", "貂裘犯雪觀形勝，駿馬隨鷹搏野鮮。", "爲問南溪李夫子，壯心應未逐流年。"]'),
('5d2c9a03-4b19-4754-b4e0-8d669c584d67','病中聞子由得告不赴商州三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','病中聞汝免來商，旅雁何時更著行。',64,'全唐诗/poet.song.44000.json','["病中聞汝免來商，旅雁何時更著行。", "遠別不知官爵好，思歸苦覺歲年長。", "著書多暇真良計，從宦無功漫去鄉。", "惟有王城最堪隠，萬人如海一身藏。"]'),
('f4b53215-d7b3-46c2-a7de-dbe22c4cb953','病中聞子由得告不赴商州三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','近從章子聞渠說，苦道商人望汝來。',64,'全唐诗/poet.song.44000.json','["近從章子聞渠說，苦道商人望汝來。", "說客有靈慚直道，逋翁久沒厭凡才。", "夷音僅可通名姓，癭俗無由辨頸顋。", "答策不堪宜落此，上書求免亦何哉。"]'),
('f157fe8a-98b3-40d2-9ae5-813dfcbd00ae','病中聞子由得告不赴商州三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','辭官不出意誰知，敢向清時怨位卑。',64,'全唐诗/poet.song.44000.json','["辭官不出意誰知，敢向清時怨位卑。", "萬事悠悠付杯酒，流年冉冉入霜髭。", "策曾忤世人嫌汝，易可忘憂家有師。", "此外知心更誰是，夢魂相覓苦參差。"]'),
('5d9e64d5-2656-4906-b7fb-92f588836510','病中大雪數日未嘗起觀虢令趙薦以詩相屬戲用其韵答之','蘇軾','宋','宋诗','song-poetry','','[]','經旬卧齋閣，終日親劑和。',192,'全唐诗/poet.song.44000.json','["經旬卧齋閣，終日親劑和。", "不知雪已深，但覺寒無那。", "飄蕭窗紙鳴，堆壓檐板墮。", "風飆助凝冽，幃幔困掀簸。", "惟思近醇醲，未敢窺璨瑳。", "何時反炎赫，却欲躬臼磨。", "誰云坐無氈，尚有裘充貨。", "西鄰歌吹發，促席寒威挫。", "崩騰踏成逕，繚繞飛入座。", "人歡瓦先融，飲雋瓶屢卧。", "嗟予獨愁寂，空室自困坷。", "欲爲後日賞，恐被遊塵涴。", "寒更報新霽，皎月懸半破。", "有客獨苦吟，清夜默自課。", "詩人例窮蹇，秀句出寒餓。", "何當暴雪霜，庶以躡郊賀。"]'),
('9e251b8b-44c0-42d5-b3ec-a0d0218e5b21','歲晚相與饋問爲饋歲酒食相邀呼問別歲至除夜達旦不眠爲守歲蜀之風俗如是余官於岐下歲暮思歸而不可得故爲此三詩以寄子由 饋歲','蘇軾','宋','宋诗','song-poetry','','[]','農功各已收，歲事得相佐。',96,'全唐诗/poet.song.44000.json','["農功各已收，歲事得相佐。", "爲歡恐無及，假物不論貨。", "山川隨出産，貧富稱小大。", "寘盤巨鯉橫，發籠雙兔卧。", "富人事華靡，綵繡光翻座。", "貧者愧不能，微摯出舂磨。", "官居故人少，里巷佳節過。", "亦欲舉鄉風，獨唱無人和。"]'),
('a985d465-d3d4-4fef-abe2-bf7a2f5b40e0','歲晚相與饋問爲饋歲酒食相邀呼問別歲至除夜達旦不眠爲守歲蜀之風俗如是余官於岐下歲暮思歸而不可得故爲此三詩以寄子由 別歲','蘇軾','宋','宋诗','song-poetry','','[]','故人適千里，臨別尚遲遲。',96,'全唐诗/poet.song.44000.json','["故人適千里，臨別尚遲遲。", "人行猶可復，歲行那可追。", "問歲安所之，遠在天一涯。", "已逐東流水，赴海歸無時。", "東鄰酒初熟，西舍彘亦肥。", "且爲一日歡，慰此窮年悲。", "勿嗟舊歲別，行與新歲辭。", "去去勿回顧，還君老與衰。"]'),
('1f703ae5-e398-4828-8851-dffca6870dcd','歲晚相與饋問爲饋歲酒食相邀呼問別歲至除夜達旦不眠爲守歲蜀之風俗如是余官於岐下歲暮思歸而不可得故爲此三詩以寄子由 守歲','蘇軾','宋','宋诗','song-poetry','','["\u52c9\u52b1", "\u60dc\u65f6", "\u6625\u8282"]','欲知垂盡歲，有似赴壑蛇。',96,'全唐诗/poet.song.44000.json','["欲知垂盡歲，有似赴壑蛇。", "修鱗半已沒，去意誰能遮。", "况欲繫其尾，雖勤知奈何。", "兒童强不睡，相守夜讙譁。", "晨鷄且勿唱，更鼓畏添撾。", "坐久燈燼落，起看北斗斜。", "明年豈無年，心事恐蹉跎。", "努力盡今夕，少年猶可誇。"]'),
('e0b559e8-0e7b-4be5-ab46-402280a4b30c','和子由踏青','蘇軾','宋','宋诗','song-poetry','','["\u6000\u4eba", "\u601d\u4e61", "\u56de\u5fc6"]','東風陌上驚微塵，遊人初樂歲華新。',128,'全唐诗/poet.song.44000.json','["東風陌上驚微塵，遊人初樂歲華新。", "人閑正好路傍飲，麥短未怕遊車輪。", "城中居人厭城郭，喧闐曉出空四鄰。", "歌鼓驚山草木動，簞瓢散野烏鳶馴。", "何人聚衆稱道人，遮道賣符色怒嗔。", "宜蠶使汝繭如甕，宜畜使汝羊如麇。", "路人未必信此語，强爲買服禳新春。", "道人得錢徑沽酒，醉倒自謂吾符神。"]'),
('2a352f65-3f37-4ea7-b1ab-d43bb5266274','和子由蠶市','蘇軾','宋','宋诗','song-poetry','','[]','蜀人衣食常苦艱，蜀人遊樂不知還。',128,'全唐诗/poet.song.44000.json','["蜀人衣食常苦艱，蜀人遊樂不知還。", "千人耕種萬人食，一年辛苦一春閑。", "閑時尚以蠶爲市，共忘辛苦逐欣歡。", "去年霜降斫秋荻，今年箔積如連山。", "破瓢爲輪土爲釜，爭買不啻金與紈。", "憶昔與子皆童丱，年年廢書走市觀。", "市人爭誇鬬巧智，野人喑啞遭欺謾。", "詩來使我感舊事，不悲去國悲流年。"]'),
('718295b0-35db-48f5-b80f-a56b7c71c138','客位假寐','蘇軾','宋','宋诗','song-poetry','','[]','謁入不得去，兀坐如枯株。',48,'全唐诗/poet.song.44000.json','["謁入不得去，兀坐如枯株。", "豈惟主忘客，今我亦忘吾。", "同僚不解事，慍色見髯鬚。", "雖無性命憂，且復忍須臾。"]'),
('dcbe2ede-84bc-49ab-98b3-9e0e2a24837a','和劉長安題薛周逸老亭周善飲酒未七十而致仕','蘇軾','宋','宋诗','song-poetry','','[]','近聞薛公子，早退驚常流。',144,'全唐诗/poet.song.44000.json','["近聞薛公子，早退驚常流。", "買園招野鶴，鑿井動潛虬。", "自言酒中趣，一斗勝凉州。", "翻然拂衣去，親愛挽不留。", "隠居亦何樂，素志庶可求。", "所亡嗟無幾，所得不啻酬。", "青春爲君好，白日爲君悠。", "山鳥奏琴筑，野花弄閑幽。", "雖辭功與名，其樂實素侯。", "至今清夜夢，尚驚冠壓頭。", "誰能載美酒，往以大白浮。", "之子雖不識，因公可與游。"]'),
('4637c574-1ebc-4f13-be7b-861f5fba3ee3','中隠堂詩  其一','蘇軾','宋','宋诗','song-poetry','','[]','去蜀初逃難，遊秦遂不歸。',48,'全唐诗/poet.song.44000.json','["去蜀初逃難，遊秦遂不歸。", "園荒喬木老，堂在昔人非。", "鑿石清泉激，開門野鶴飛。", "退居吾久念，長恐此心違。"]'),
('94a18e33-aac7-4fe1-8813-d257e0ee6154','中隠堂詩  其二','蘇軾','宋','宋诗','song-poetry','','[]','徑轉如修蟒，坡垂似伏鰲。',48,'全唐诗/poet.song.44000.json','["徑轉如修蟒，坡垂似伏鰲。", "樹從何代有，人與此堂高。", "好古嗟生晚，偷閑厭久勞。", "王孫早歸隠，塵土污君袍。"]'),
('6c7ef4fc-d30a-444f-8a34-ae869b25637c','中隠堂詩  其三','蘇軾','宋','宋诗','song-poetry','','[]','二月驚梅晚，幽香此地無。',48,'全唐诗/poet.song.44000.json','["二月驚梅晚，幽香此地無。", "依依慰遠客，皎皎似吳姝。", "不恨故園隔，空嗟芳歲徂。", "春深桃杏亂，笑汝益羈孤。"]'),
('300ad265-86d8-444b-b8a6-b98c4ca7c689','中隠堂詩  其四','蘇軾','宋','宋诗','song-poetry','','[]','翠石如鸚鵡，何年別海壖。',48,'全唐诗/poet.song.44000.json','["翠石如鸚鵡，何年別海壖。", "貢隨南使遠，載壓渭舟偏。", "已伴喬松老，那知故國遷。", "金人解辭漢，汝獨不潸然。"]'),
('594d689b-7d3e-4d76-8176-550fa76f9518','中隠堂詩  其五','蘇軾','宋','宋诗','song-poetry','','[]','都城更幾姓，到處有殘碑。',48,'全唐诗/poet.song.44000.json','["都城更幾姓，到處有殘碑。", "古隧埋蝌蚪，崩崖露伏龜。", "安排壯亭榭，收拾費金貲。", "岣嶁何須到，韓公浪自悲。"]'),
('905fb842-ddbf-440f-8f23-d5cf8d2ef543','題寶雞縣斯飛閣','蘇軾','宋','宋诗','song-poetry','','[]','西南歸路遠蕭條，倚檻魂飛不可招。',64,'全唐诗/poet.song.44000.json','["西南歸路遠蕭條，倚檻魂飛不可招。", "野闊牛羊同雁鶩，天長草樹接雲霄。", "昏昏水氣浮山麓，泛泛春風弄麥苗。", "誰使愛官輕去國，此身無計老漁樵。"]'),
('e22d42dd-acb6-4ccf-991d-28659cfc8851','重遊終南子由以詩見寄次韵','蘇軾','宋','宋诗','song-poetry','','[]','去年新柳報春回，今日殘花覆綠苔。',64,'全唐诗/poet.song.44000.json','["去年新柳報春回，今日殘花覆綠苔。", "溪上有堂還獨宿，誰人無事肯重來。", "古琴彈罷風吹座，山閣醒時月照杯。", "懶不作詩君錯料，舊逋應許過時陪。"]'),
('a8a7c0f0-cd2c-44be-b687-c6ce1ad141c6','和子由寒食','蘇軾','宋','宋诗','song-poetry','','[]','寒食今年二月晦，樹林深翠已生煙。',64,'全唐诗/poet.song.44000.json','["寒食今年二月晦，樹林深翠已生煙。", "遶城駿馬誰能借，到處名園意盡便。", "但掛酒壺那計盞，偶題詩句不須編。", "忽聞啼鵙驚羈旅，江上何人治廢田。"]'),
('b210ab83-7de8-4557-8c17-543a2ec49b69','記所見開元寺吳道子畫佛滅度以答子由題畫文殊普賢','蘇軾','宋','宋诗','song-poetry','','[]','西方真人誰所見，衣被七寶從雙狻。',176,'全唐诗/poet.song.44000.json','["西方真人誰所見，衣被七寶從雙狻。", "當時修道頗辛苦，柳生兩肘烏巢肩。", "初如濛濛隠山玉，漸如濯濯出水蓮。", "道成一旦就空滅，奔會四海悲人天。", "翔禽哀響動林谷，獸鬼躑躅淚迸泉。", "龐眉深目彼誰子，繞牀彈指性自圓。", "隠如寒月墮清晝，空有孤光留故躔。", "春遊古寺拂塵壁，遺像久此霾香煙。", "畫師不復寫姓名，皆云道子口所傳。", "縱橫固已蔑孫鄧，有如巨鰐吞小鮮。", "來詩所誇孰與此，安得携掛其傍觀。"]'),
('dd27ad79-4eff-4070-83cc-5dcdb3cea73d','妒佳月','蘇軾','宋','宋诗','song-poetry','','[]','狂雲妒佳月，怒飛千里黑。',120,'全唐诗/poet.song.44000.json','["狂雲妒佳月，怒飛千里黑。", "佳月了不嗔，曾何污潔白。", "爰有謫仙人，舉酒爲三客。", "今夕偶不見，汍瀾念風伯。", "毋煩風伯來，彼也易滅沒。", "支頤少待之，寒空浄無迹。", "粲粲黄金盤，獨照一天碧。", "玉繩慘無輝，玉露洗秋色。", "浩瀚玻璃盞，和光入胸臆。", "使我能永延，約君爲莫逆。"]'),
('e3a8b8d3-27e6-40ce-894f-8c16f9247dc1','次韵子由彈琴','蘇軾','宋','宋诗','song-poetry','','[]','琴上遺聲久不彈，琴中古義本長存。',64,'全唐诗/poet.song.44000.json','["琴上遺聲久不彈，琴中古義本長存。", "苦心欲記常迷舊，信指如歸自著痕。", "應有仙人依樹聽，空教瘦鶴舞風鶱。", "誰知千里溪堂夜，時引驚猿撼竹軒。"]'),
('6b3d111d-7a31-47b0-a569-925ac6724737','七月二十四日以久不雨出禱磻溪是日宿虢縣二十五日晚自虢縣渡渭宿於僧舍曾閣閣故曾氏所建也夜久不寐見壁間有前縣令趙薦留名有懷其人','蘇軾','宋','宋诗','song-poetry','','[]','龕燈明滅欲三更，敧枕無人夢自驚。',64,'全唐诗/poet.song.44000.json','["龕燈明滅欲三更，敧枕無人夢自驚。", "深谷留風終夜響，亂山銜月半床明。", "故人漸遠無消息，古寺空來看姓名。", "欲向磻溪問姜叟，僕夫屢報斗杓傾。"]'),
('ae676d24-f717-4ee2-aa82-d63f0f91e081','二十六日五更起行至磻溪天未明','蘇軾','宋','宋诗','song-poetry','','[]','夜入磻溪如入峽，照山炬火落驚猿。',64,'全唐诗/poet.song.44000.json','["夜入磻溪如入峽，照山炬火落驚猿。", "山頭孤月耿猶在，石上寒波曉更喧。", "至人舊隠白雲合，神物已化遺蹤蜿。", "安得夢隨霹靂駕，馬上傾倒天瓢翻。"]'),
('226df109-541f-4d28-91db-aa66155766fe','是日自磻溪將往陽平憩於麻田青峰寺之下院翠麓亭','蘇軾','宋','宋诗','song-poetry','','[]','不到峰前寺，空來渭上村。',96,'全唐诗/poet.song.44000.json','["不到峰前寺，空來渭上村。", "此亭聊可喜，修徑豈辭捫。", "谷映朱欄秀，山含古木尊。", "路窮驚石斷，林缺見河奔。", "馬困嘶青草，僧留薦晚飧。", "我來秋日午，旱久石床溫。", "安得雲如蓋，能令雨瀉盆。", "共看山下稻，凉葉晚翻翻。"]'),
('693dfd36-7d2c-4e75-b172-4bdde83d7921','二十七日自陽平至斜谷宿於南山中蟠龍寺','蘇軾','宋','宋诗','song-poetry','','[]','橫槎晚渡碧澗口，騎馬夜入南山谷。',160,'全唐诗/poet.song.44000.json','["橫槎晚渡碧澗口，騎馬夜入南山谷。", "谷中暗水響瀧瀧，嶺上疏星明煜煜。", "寺藏巌底千萬仞，路轉山腰三百曲。", "風生饑虎嘯空林，月黑驚麏竄修竹。", "入門突兀見深殿，照佛青熒有殘燭。", "愧無酒食待遊人，旋斫杉松煮溪蔌。", "板閣獨眠驚旅枕，木魚曉動隨僧粥。", "起觀萬瓦鬰參差，目亂千巌散紅綠。", "門前商賈負椒荈，山後咫尺連巴蜀。", "何時歸耕江上田，一夜心逐南飛鵠。"]'),
('3ab23965-87ac-45a7-922a-44d7209d9486','是日至下馬磧憩於北山僧舍有閣曰懷賢南直斜谷西臨五丈原諸葛孔明所從出師也','蘇軾','宋','宋诗','song-poetry','','[]','南望斜谷口，三山如犬牙。',120,'全唐诗/poet.song.44000.json','["南望斜谷口，三山如犬牙。", "西觀五丈原，鬰屈如長蛇。", "有懷諸葛公，萬騎出漢巴。", "吏士寂如水，蕭蕭聞馬檛。", "公才與曹丕，豈止十倍加。", "顧瞻三輔間，勢若風捲沙。", "一朝長星墜，竟使蜀婦髽。", "山僧豈知此，一室老煙霞。", "往事逐雲散，故山依渭斜。", "客來空弔古，清淚落悲笳。"]'),
('e252375d-fbab-45e8-95e7-732672475de8','和子由聞子瞻將如終南太平宮溪堂讀書','蘇軾','宋','宋诗','song-poetry','','[]','役名則已勤，徇身則已媮。',240,'全唐诗/poet.song.44000.json','["役名則已勤，徇身則已媮。", "我誠愚且拙，身名兩無謀。", "始者學書判，近亦知問囚。", "但知今當爲，敢問向所由。", "士方其未得，惟以不得憂。", "既得又憂失，此心浩難收。", "譬如倦行客，中路逢清流。", "塵埃雖未脫，暫憩得一漱。", "我欲走南澗，春禽始嚶呦。", "鞅掌久不决，爾來已徂秋。", "橋山日月追，府縣煩差抽。", "王事誰敢愬，民勞吏宜羞。", "中間罹旱暵，欲學喚雨鳩。", "千夫挽一木，十步八九休。", "渭水涸無泥，菑堰旋插修。", "對之食不飽，餘事更遑求。", "近日秋雨足，公餘試新篘。", "劬勞幸已過，朽鈍不任鎪。", "秋風迫吹帽，西阜可縱游。", "聊爲一日樂，慰此百年愁。"]'),
('c7a6cb36-eb77-40d3-98a0-ad2a806081dc','將往終南和子由見寄','蘇軾','宋','宋诗','song-poetry','','[]','人生百年寄鬢鬚，富貴何啻葭中莩。',144,'全唐诗/poet.song.44000.json','["人生百年寄鬢鬚，富貴何啻葭中莩。", "惟將翰墨留染濡，絕勝醉倒蛾眉扶。", "我今廢學如寒竽，久不吹之澀欲無。", "歲云暮矣嗟幾餘，欲往南溪侶禽魚。", "秋風吹雨凉生膚，夜長耿耿添漏壺。", "窮年弄筆衫袖烏，古人有之我願如。", "終朝危坐學僧趺，閉門不出閑履鳬。", "下視官爵如泥淤，嗟我何爲久踟躕。", "歲月豈肯與汝居，僕夫起餐秣吾駒。"]'),
('0afb4f15-e8e4-4bc3-a4e0-2c840fec1b57','讀道藏','蘇軾','宋','宋诗','song-poetry','','[]','嗟余亦何幸，偶此琳宮居。',120,'全唐诗/poet.song.44000.json','["嗟余亦何幸，偶此琳宮居。", "宮中復何有，戢戢千函書。", "盛以丹錦囊，冒以青霞裾。", "王喬掌關籥，蚩尤守其廬。", "乘閑竊掀攪，涉獵豈暇徐。", "至人悟一言，道集由中虛。", "心閑反自照，皎皎如芙蕖。", "千歲厭世去，此言乃籧篨。", "人皆忽其身，治之用土苴。", "何暇及天下，幽憂吾未除。"]'),
('8a8e2a1c-bc61-44e7-a8ca-7c886ca84594','南溪有會景亭處衆亭之間無所見甚不稱其名予欲遷之少西臨斷岸西向可以遠望而力未暇特爲製名曰招隠仍爲詩以告來者庶幾遷之','蘇軾','宋','宋诗','song-poetry','','[]','飛簷臨古道，高榜觀遊人。',96,'全唐诗/poet.song.44000.json','["飛簷臨古道，高榜觀遊人。", "未即令公隠，聊須濯路塵。", "茅茨分聚落，煙火傍城闉。", "林缺湖光漏，窗明野意新。", "居民惟白帽，過客漫朱輪。", "山好留歸屐，風迴落醉巾。", "他年誰改築，舊製不須因。", "再到吾雖老，猶堪作坐賓。"]'),
('69c6dddb-e07c-423f-91f9-565ea1bfbf90','扶風天和寺','蘇軾','宋','宋诗','song-poetry','','[]','遠望若可愛，朱欄碧瓦溝。',48,'全唐诗/poet.song.44000.json','["遠望若可愛，朱欄碧瓦溝。", "聊爲一駐足，且慰百回頭。", "水落見山石，塵高昏市樓。", "臨風莫長嘯，遺響浩難收。"]'),
('6e63ec33-6284-44f1-81d5-794b07cfffd1','十二月十四日夜微雪明日早往南溪小酌至晚','蘇軾','宋','宋诗','song-poetry','','[]','南溪得雪真無價，走馬來看及未消。',64,'全唐诗/poet.song.44000.json','["南溪得雪真無價，走馬來看及未消。", "獨自披榛尋履迹，最先犯曉過朱橋。", "誰憐屋破眠無處，坐覺村饑語不囂。", "惟有暮鴉知客意，驚飛千片落寒條。"]'),
('a849aaf7-4c7c-4b4c-8371-f8bcc77627bd','九月中曾題二小詩於南溪竹上既而忘之昨日再遊見而錄之  其一','蘇軾','宋','宋诗','song-poetry','','[]','湖上蕭蕭疏雨過，山頭靄靄暮雲橫。',32,'全唐诗/poet.song.44000.json','["湖上蕭蕭疏雨過，山頭靄靄暮雲橫。", "陂塘水落荷將盡，城市人歸虎欲行。"]'),
('094df5c4-79ac-44a8-a3a3-ada8dfac554e','九月中曾題二小詩於南溪竹上既而忘之昨日再遊見而錄之  其二','蘇軾','宋','宋诗','song-poetry','','[]','誰謂江湖居，而爲虎豹宅。',24,'全唐诗/poet.song.44000.json','["誰謂江湖居，而爲虎豹宅。", "焚山豈不能，愛此千竿碧。"]'),
('a8338cbe-f216-40d3-8cdc-c4fc94f2f452','南溪之南竹林中新構一茅堂予以其所處最爲深邃故名之曰避世堂','蘇軾','宋','宋诗','song-poetry','','[]','猶恨溪堂淺，更穿修竹林。',96,'全唐诗/poet.song.44000.json','["猶恨溪堂淺，更穿修竹林。", "高人不畏虎，避世已無心。", "隠几頹如病，忘言兀似瘖。", "茅茨追上古，冠蓋謝當今。", "曉夢猿呼覺，秋懷鳥伴吟。", "暫來聊解带，屢去欲携衾。", "湖上行人絕，階前暮靄深。", "應逢綠毛叟，扣戶夜抽簪。"]'),
('2be194be-7bb9-40de-8e60-ac098936df6b','溪堂留題','蘇軾','宋','宋诗','song-poetry','','[]','三徑縈回草樹蒙，忽驚初日上千峰。',64,'全唐诗/poet.song.44000.json','["三徑縈回草樹蒙，忽驚初日上千峰。", "平湖種稻如西蜀，高閣連雲似渚宮。", "殘雪照山光耿耿，輕冰籠水暗溶溶。", "溪邊野鶴衝人起，飛入南山第幾重。"]'),
('16e85129-ff45-4deb-abc7-69c3d7ec65b9','次韵子由種菜久旱不生','蘇軾','宋','宋诗','song-poetry','','[]','新春階下筍芽生，厨裏霜虀倒舊罌。',64,'全唐诗/poet.song.44000.json','["新春階下筍芽生，厨裏霜虀倒舊罌。", "時繞麥田求野薺，强爲僧舍煮山羹。", "園無雨潤何須歎，身與時違合退耕。", "欲看年華自有處，鬢間秋色兩三莖。"]'),
('b2dbccb0-da34-4594-be76-3a3184e3cca2','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 樓觀','蘇軾','宋','宋诗','song-poetry','','[]','鳥噪猿呼晝閉門，寂寥誰識古皇尊。',64,'全唐诗/poet.song.44000.json','["鳥噪猿呼晝閉門，寂寥誰識古皇尊。", "青牛久已辭轅軛，白鶴時來訪子孫。", "山近朔風吹積雪，天寒落日淡孤村。", "道人應怪遊人衆，汲盡階前井水渾。"]'),
('14d7f557-7b47-4c6b-8c12-9ba7da8c32e9','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 五郡','蘇軾','宋','宋诗','song-poetry','','[]','古觀正依林麓斷，居民來就水泉甘。',64,'全唐诗/poet.song.44000.json','["古觀正依林麓斷，居民來就水泉甘。", "亂溪赴渭爭趨北，飛鳥迎山不復南。", "羽客衣冠朝上象，野人香火祝春蠶。", "汝師豈解言符命，山鬼何知托老聃。"]'),
('a5891974-7aee-4b41-bd13-b8d943a8dcb7','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 授經臺','蘇軾','宋','宋诗','song-poetry','','[]','劍舞有神通草聖，海山無事化琴工。',32,'全唐诗/poet.song.44000.json','["劍舞有神通草聖，海山無事化琴工。", "此臺一覽秦川小，不待傳經意已空。"]'),
('5637b04e-e74b-4bd6-aa47-d52bc7368f6d','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 大秦寺','蘇軾','宋','宋诗','song-poetry','','[]','晃蕩平川盡，坡陀翠麓橫。',48,'全唐诗/poet.song.44000.json','["晃蕩平川盡，坡陀翠麓橫。", "忽逢孤塔迥，獨向亂山明。", "信足幽尋遠，臨風却立驚。", "原田浩如海，滾滾盡東傾。"]'),
('89308ea1-528a-4590-bb0a-028ae9ebc0fa','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 仙遊潭','蘇軾','宋','宋诗','song-poetry','','[]','翠壁下無路，何年雷雨穿。',48,'全唐诗/poet.song.44000.json','["翠壁下無路，何年雷雨穿。", "光摇巌上寺，深到影中天。", "我欲然犀看，龍應抱寶眠。", "誰能孤石上，危坐試僧禪。"]'),
('075500d8-8508-4203-a393-7490e31e2294','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 南寺','蘇軾','宋','宋诗','song-poetry','','[]','東去愁攀石，西來怯渡橋。',48,'全唐诗/poet.song.44000.json','["東去愁攀石，西來怯渡橋。", "碧潭如見試，白塔苦相招。", "野饋慚微薄，村沽慰寂寥。", "路窮斤斧絕，松桂得干霄。"]'),
('bb763211-003c-497e-952d-be5e95d0a9c8','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 北寺','蘇軾','宋','宋诗','song-poetry','','[]','唐初傳有此，亂後不留碑。',48,'全唐诗/poet.song.44000.json','["唐初傳有此，亂後不留碑。", "畏虎關門早，無村得米遲。", "山泉自入甕，野桂不勝炊。", "信美那能久，應先學忍饑。"]'),
('23a386cd-9a8a-4e0f-9b4a-d5229727a382','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 馬融石室','蘇軾','宋','宋诗','song-poetry','','[]','未應將軍聘，初從季直游。',48,'全唐诗/poet.song.44000.json','["未應將軍聘，初從季直游。", "絳紗生不識，蒼石尚能留。", "豈害依梁冀，何須困李侯。", "吾詩慎勿刻，猿鶴爲君羞。"]'),
('44a0db68-c474-4258-b45c-5b5a94a5a261','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 玉女洞','蘇軾','宋','宋诗','song-poetry','','[]','洞裏吹簫子，終年守獨幽。',48,'全唐诗/poet.song.44000.json','["洞裏吹簫子，終年守獨幽。", "石泉爲曉鏡，山月當簾鉤。", "歲晚杉楓盡，人歸霧雨愁。", "送迎應鄙陋，誰繼楚臣謳。"]'),
('46662dca-54f0-426d-a5c7-a7ac9262de8c','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 愛玉女洞中水既致兩瓶恐後復取而爲使者見紿因破竹爲契使寺僧藏其一以爲往來之信戲謂之調水符','蘇軾','宋','宋诗','song-poetry','','[]','欺謾久成俗，關市有契繻。',72,'全唐诗/poet.song.44000.json','["欺謾久成俗，關市有契繻。", "誰知南山下，取水亦置符。", "古人辨淄澠，皎若鶴與鳬。", "吾今既謝此，但視符有無。", "常恐汲水人，智出符之餘。", "多防竟無及，棄置爲長吁。"]'),
('b339e38d-c2c1-4db9-8867-1a17ffeb7214','自清平鎮遊樓觀五郡大秦延生仙遊往返四日得十一詩寄子由同作 自仙遊回至黑水見居民姚氏山亭高絕可愛復憩其上','蘇軾','宋','宋诗','song-poetry','','[]','山鴉曉辭谷，似報遊人起。',120,'全唐诗/poet.song.44000.json','["山鴉曉辭谷，似報遊人起。", "出門猶屢顧，慘若去吾里。", "道途險且迂，繼此復能幾。", "溪邊有危構，歸駕聊復柅。", "愛此山中人，縹緲如仙子。", "平生慕獨往，官爵同一屣。", "胡爲此溪邊，眷眷若有俟。", "國恩久未報，念此慚且泚。", "臨風浩悲叱，萬世同一軌。", "何年謝簪紱，丹砂留迅晷。"]'),
('230f2858-3c04-4221-8f6c-ba8c0b74244b','二月十六日與張李二君遊南溪醉後相與解衣濯足因詠韓公山石之篇慨然知其所以樂而忘其在數百年之外也次其韵','蘇軾','宋','宋诗','song-poetry','','[]','終南太白橫翠微，自我不見心南飛。',160,'全唐诗/poet.song.44000.json','["終南太白橫翠微，自我不見心南飛。", "行穿古縣並山麓，野水清滑溪魚肥。", "須臾渡溪踏亂石，山光漸近行人稀。", "窮探愈好去愈銳，意未滿足枵如饑。", "忽聞奔泉響巨碓，隠隠百步摇窗扉。", "跳波濺沫不可嚮，散爲白霧紛霏霏。", "醉中相與棄拘束，顧勸二子解带圍。", "褰裳試入插兩足，飛浪激起衝人衣。", "君看麋鹿隠豐草，豈羨玉勒黄金鞿。", "人生何以易此樂，天下誰肯從我歸。"]'),
('c83e4076-e463-4d80-b400-d21622d8c898','大老寺竹間閣子','蘇軾','宋','宋诗','song-poetry','','[]','殘花带葉暗，新筍出林香。',48,'全唐诗/poet.song.44000.json','["殘花带葉暗，新筍出林香。", "但見竹陰綠，不知汧水黄。", "樹高傾隴鳥，池浚落河魴。", "栽種良辛苦，孤僧瘦欲尪。"]'),
('acd81366-f3fa-4601-ac75-2599ee608ad2','周公廟廟在岐山西北八九里廟後百許步有泉依山湧冽異常國史所謂潤德泉世亂則竭者也','蘇軾','宋','宋诗','song-poetry','','[]','吾今那復夢周公，尚喜秋來過故宮。',64,'全唐诗/poet.song.44000.json','["吾今那復夢周公，尚喜秋來過故宮。", "翠鳳舊依山硉兀，清泉長與世窮通。", "至今游客傷離黍，故國諸生詠雨濛。", "牛酒不來烏鳥散，白楊無數暮號風。"]'),
('b6f38a9d-1315-4eec-b27a-bfb022dae7a6','和子由記園中草木十一首  其一','蘇軾','宋','宋诗','song-poetry','','[]','煌煌帝王都，赫赫走羣彥。',108,'全唐诗/poet.song.44000.json','["煌煌帝王都，赫赫走羣彥。", "嗟汝獨何爲，閉門觀物變。", "微物豈足觀，汝獨觀不倦。", "牽牛與葵蓼，采摘入詩卷。", "吾聞東山傅，置酒携燕婉。", "富貴未能忘，聲色聊自遣。", "汝今又不然，時節看瓜蔓。", "懷寶自足珍，藝蘭那計畹。", "吾歸於汝處，慎勿嗟歲晚。"]'),
('d1b7c88a-a8a0-4d05-b10b-8666403eb193','和子由記園中草木十一首  其二','蘇軾','宋','宋诗','song-poetry','','[]','荒園無數畝，草木動成林。',96,'全唐诗/poet.song.44000.json','["荒園無數畝，草木動成林。", "春陽一以敷，妍醜各自矜。", "蒲萄雖滿架，囷倒不能任。", "可憐病石榴，花如破紅襟。", "葵花雖粲粲，蒂淺不勝簪。", "叢蓼晚可喜，輕紅隨秋深。", "物生感時節，此理等廢興。", "飄零不自由，盛亦非汝能。"]'),
('3a27d731-5fb3-4a66-9779-1c6bd256b3bf','和子由記園中草木十一首  其三','蘇軾','宋','宋诗','song-poetry','','[]','種柏待其成，柏成人已老。',72,'全唐诗/poet.song.44000.json','["種柏待其成，柏成人已老。", "不如種叢篲，春種秋可倒。", "陰陽不擇物，美惡隨意造。", "柏生何苦艱，似亦費天巧。", "天工巧有幾，肯盡爲汝耗。", "君看藜與藿，生意常草草。"]'),
('bf710b8d-518a-4a44-af12-fdad79aaee95','和子由記園中草木十一首  其四','蘇軾','宋','宋诗','song-poetry','','[]','萱草雖微花，孤秀能自拔。',72,'全唐诗/poet.song.44000.json','["萱草雖微花，孤秀能自拔。", "亭亭亂葉中，一一勞心插。", "牽牛獨何畏，詰曲自芽蘗。", "走尋荆與榛，如有夙昔約。", "南齋讀書處，亂翠曉如潑。", "偏工貯秋雨，歲歲壞籬落。"]'),
('e1e6618c-70f0-4021-accd-4f5a250d0fc3','和子由記園中草木十一首  其五','蘇軾','宋','宋诗','song-poetry','','[]','蘆筍初似竹，稍開葉如蒲。',72,'全唐诗/poet.song.44000.json','["蘆筍初似竹，稍開葉如蒲。", "方春節抱甲，漸老根生鬚。", "不愛當夏綠，愛此及秋枯。", "黄葉倒風雨，白花摇江湖。", "江湖不可到，移植苦勤劬。", "安得雙野鴨，飛來成畫圖。"]'),
('b69a1167-1ad8-43be-bf40-61e500a984ee','和子由記園中草木十一首  其六','蘇軾','宋','宋诗','song-poetry','','[]','行樂惜芳辰，秋風常苦早。',72,'全唐诗/poet.song.44000.json','["行樂惜芳辰，秋風常苦早。", "誰知念離別，喜見秋瓜老。", "秋瓜感霜霰，莖葉颯已槁。", "宦遊歸無時，身若馬繫皁。", "悲鳴念千里，耿耿志空抱。", "多憂竟何爲，使汝玄髮縞。"]'),
('60447cbe-1e3b-4710-a5dc-8e24b6a7668f','和子由記園中草木十一首  其七','蘇軾','宋','宋诗','song-poetry','','[]','官舍有叢竹，結根問囚廳。',72,'全唐诗/poet.song.44000.json','["官舍有叢竹，結根問囚廳。", "下爲人所徑，土密不容釘。", "殷勤戒吏卒，插棘護中庭。", "遶砌忽墳裂，走鞭瘦竛竮。", "我常携枕簟，來此蔭寒青。", "日暮不能去，卧聽窗風泠。"]'),
('0dfe832b-b54e-49c2-b006-2594cbe94aef','和子由記園中草木十一首  其八','蘇軾','宋','宋诗','song-poetry','','[]','芎藭生蜀道，白芷來江南。',72,'全唐诗/poet.song.44000.json','["芎藭生蜀道，白芷來江南。", "漂流到關輔，猶不失芳甘。", "濯濯翠莖滿，愔愔清露涵。", "及其未花實，可以資筐籃。", "秋節忽已老，苦寒非所堪。", "劚根取其實，對此微物慚。"]'),
('60768763-8ca3-428f-94e6-283ba19abdf8','和子由記園中草木十一首  其九','蘇軾','宋','宋诗','song-poetry','','[]','自我來關輔，南山得再遊。',72,'全唐诗/poet.song.44000.json','["自我來關輔，南山得再遊。", "山中亦何有，草木媚深幽。", "菖蒲人不識，生此亂石溝。", "山高霜雪苦，苗葉不得抽。", "下有千歲根，蹙縮如蟠虬。", "長爲鬼神守，德薄安敢偷。"]'),
('02554f93-46a5-4399-b896-7e2b8269160b','和子由記園中草木十一首  其一○','蘇軾','宋','宋诗','song-poetry','','[]','我歸自南山，山翠猶在目。',84,'全唐诗/poet.song.44000.json','["我歸自南山，山翠猶在目。", "心隨白雲去，夢繞山之麓。", "汝從何方來，笑齒粲如玉。", "探懷出新詩，秀語奪山綠。", "覺來已茫昧，但記說秋菊。", "有如採樵人，入洞聽琴筑。", "歸來寫遺聲，猶勝人間曲。"]'),
('040bd1e7-93a0-4716-b8d5-24f46a80cac9','和子由記園中草木十一首  其一一','蘇軾','宋','宋诗','song-poetry','','[]','野菊生秋澗，芳心空自知。',72,'全唐诗/poet.song.44000.json','["野菊生秋澗，芳心空自知。", "無人驚歲晚，惟有暗蛩悲。", "花開澗水上，花落澗水湄。", "菊衰蛩亦蟄，與汝歲相期。", "楚客方多感，秋風詠江蘺。", "落英不滿掬，何以慰朝饑。"]'),
('afa50ce1-181a-47f3-82d5-6be2eab6235d','次韵和子由聞予善射','蘇軾','宋','宋诗','song-poetry','','[]','中朝鸞鷺自振振，豈信邊隅事執鼖。',64,'全唐诗/poet.song.44000.json','["中朝鸞鷺自振振，豈信邊隅事執鼖。", "共怪書生能破的，也如驍將解論文。", "穿楊自笑非猿臂，射隼長思逐馬軍。", "觀汝長身最堪學，定如髯羽便超羣。"]'),
('c5e452bc-8f1a-48d2-83aa-36bbf0cac4fc','次韵子由論書','蘇軾','宋','宋诗','song-poetry','','[]','吾雖不善書，曉書莫如我。',168,'全唐诗/poet.song.44000.json','["吾雖不善書，曉書莫如我。", "苟能通其意，常謂不學可。", "貌妍容有矉，璧美何妨橢。", "端莊雜流麗，剛健含婀娜。", "好之每自譏，不獨子亦頗。", "書成輒棄去，謬被傍人裹。", "體勢本闊落，結束入細麽。", "子詩亦見推，語重未敢荷。", "爾來又學射，力薄愁官笴。", "多好竟無成，不精安用夥。", "何當盡屏去，萬事付懶惰。", "吾聞古書法，守駿莫如跛。", "世俗筆苦驕，衆中强嵬騀。", "鍾張忽已遠，此語與時左。"]'),
('c73cd108-0263-4242-96d7-87b63db914b3','次韵和子由欲得驪山澄泥硯','蘇軾','宋','宋诗','song-poetry','','[]','舉世爭稱鄴瓦堅，一枚不換百金頒。',64,'全唐诗/poet.song.44000.json','["舉世爭稱鄴瓦堅，一枚不換百金頒。", "豈知好事王夫子，自採臨潼繡嶺山。", "經火尚含泉脈暖，弔秦應有淚痕潸。", "封題寄去吾無用，近日從戎擬學班。"]'),
('6a95f48f-e500-497b-a66b-82fd9cd4d326','竹𪕋','蘇軾','宋','宋诗','song-poetry','','[]','野人獻竹𪕋，腰腹大如盎。',96,'全唐诗/poet.song.44000.json','["野人獻竹𪕋，腰腹大如盎。", "自言道傍得，采不費罝網。", "鴟夷讓圓滑，混沌慚瘦爽。", "兩牙雖有餘，四足僅能仿。", "逢人自驚蹶，悶若兒脫襁。", "念此微陋質，刀几安足枉。", "就擒太倉卒，羞愧不能饗。", "南山有孤熊，擇獸行舐掌。"]'),
('77da6d04-abd0-4f13-9851-3f5b9f650b3e','渼陂魚','蘇軾','宋','宋诗','song-poetry','','[]','霜筠細破爲雙掩，中有長魚如卧劍。',160,'全唐诗/poet.song.44000.json','["霜筠細破爲雙掩，中有長魚如卧劍。", "紫荇穿腮氣慘悽，紅鱗照座光磨閃。", "携來雖遠鬣尚動，烹不待熟指先染。", "坐客相看爲解顔，香粳飽送如填塹。", "早歲嘗爲荆渚客，黄魚屢食沙頭店。", "濱江易採不復珍，盈尺輒棄無乃僭。", "自從西征復何有，欲致南烹嗟久欠。", "游鯈瑣細空自腥，亂骨縱橫動遭砭。", "故人遠饋何以報，客俎久空驚忽贍。", "東道無辭信使頻，西鄰幸有庖虀釅。"]'),
('b0020732-c255-4b91-90b1-e0af471830d3','淩虛臺','蘇軾','宋','宋诗','song-poetry','','[]','才高多感激，道直無往還。',120,'全唐诗/poet.song.44000.json','["才高多感激，道直無往還。", "不如此臺上，舉酒邀青山。", "青山雖云遠，似亦識公顔。", "崩騰赴幽賞，披豁露天慳。", "落日銜翠壁，暮雲點煙鬟。", "浩歌清興發，放意末禮刪。", "是時歲云暮，微雪灑袍斑。", "吏退迹如掃，賓來勇躋攀。", "臺前飛雁過，臺上雕弓彎。", "聯翩向空墜，一笑驚塵寰。"]'),
('250f3fb0-3f4e-4c78-9073-b8700866863f','和子由苦寒見寄','蘇軾','宋','宋诗','song-poetry','','["\u8d60\u53cb", "\u6218\u4e89", "\u6292\u6000", "\u613f\u671b"]','人生不滿百，一別費三年。',156,'全唐诗/poet.song.44000.json','["人生不滿百，一別費三年。", "三年吾有幾，棄擲理無還。", "長恐別離中，摧我鬢與顔。", "念昔喜著書，別來不成篇。", "細思平時樂，乃爲憂所緣。", "吾從天下士，莫如與子歡。", "羨子久不出，讀書蝨生氈。", "丈夫重出處，不退要當前。", "西羌解仇隙，猛士憂塞壖。", "廟謨雖不戰，虜意久欺天。", "山西良家子，錦緣貂裘鮮。", "千金買戰馬，百寶粧刀鐶。", "何時逐汝去，與虜試周旋。"]'),
('5613730b-a54a-4c94-aeaf-3a96708d21f9','司竹監燒葦園因召都巡檢柴貽勖左藏以其徒會獵園下','蘇軾','宋','宋诗','song-poetry','','[]','官園刈葦留枯槎，深冬放火如紅霞。',320,'全唐诗/poet.song.44000.json','["官園刈葦留枯槎，深冬放火如紅霞。", "枯槎燒盡有根在，春雨一洗皆萌芽。", "黄狐老兔最狡捷，賣侮百獸常矜誇。", "年年此厄竟不悟，但愛蒙密爭來家。", "風迴焰卷毛尾熱，欲出已被蒼鷹遮。", "野人來言此最樂，徒手曉出歸滿車。", "巡邊將軍在近邑，呼來颯颯從矛叉。", "戍兵久閑可小試，戰鼓雖凍猶堪撾。", "雄心欲搏南澗虎，陣勢頗學常山蛇。", "霜乾火烈聲暴野，飛走無路號且呀。", "迎人截來砉逢箭，避犬逸去窮投罝。", "擊鮮走馬殊未厭，但恐落日催棲鴉。", "弊旗仆鼓坐數獲，鞍掛雉兔肩分麚。", "主人置酒聚狂客，紛紛醉語晚更譁。", "燎毛燔肉不暇割，飲啖直欲追羲媧。", "青丘雲夢古所咤，與此何啻百倍加。", "苦遭諫疏說夷羿，又被詞客嘲淫奢。", "豈如閑官走山邑，放曠不與趨朝衙。", "農工已畢歲云暮，車騎雖少賓殊嘉。", "酒酣上馬去不告，獵獵霜風吹帽斜。"]'),
('9acb2c77-a8dd-4454-a85e-70a711a1d9ec','亡伯提刑郎中挽詩二首甲辰十二月八日鳳翔官舍書  其一','蘇軾','宋','宋诗','song-poetry','','[]','才賢世有幾，廊廟忍輕遺。',48,'全唐诗/poet.song.44000.json','["才賢世有幾，廊廟忍輕遺。", "公在不早用，人今方見思。", "故山松鬰鬰，舊史印纍纍。", "惟有同鄉老，聞名尚涕洟。"]'),
('2b8dc79f-9e45-4d9b-8d25-b19ae694b3db','亡伯提刑郎中挽詩二首甲辰十二月八日鳳翔官舍書  其二','蘇軾','宋','宋诗','song-poetry','','[]','揮手都門別，朱顔鬢未霜。',48,'全唐诗/poet.song.44000.json','["揮手都門別，朱顔鬢未霜。", "至今如夢寐，未信有存亡。", "後事書千紙，新墳天一方。", "誰能悲楚相，抵掌悟君王。"]'),
('0347f9fe-59da-4f51-be59-81501dc60016','和子由木山引水二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','蜀江久不見滄浪，江上枯槎遠可將。',64,'全唐诗/poet.song.44000.json','["蜀江久不見滄浪，江上枯槎遠可將。", "去國尚能三犢載，汲泉何愛一夫忙。", "崎嶇好事人應笑，冷淡爲歡意自長。", "遥想納凉清夜永，窗前微月照汪汪。"]'),
('7c615f00-b022-4f93-88f3-409d632adbd5','和子由木山引水二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','千年古木卧無梢，浪捲沙翻去似瓢。',64,'全唐诗/poet.song.44000.json','["千年古木卧無梢，浪捲沙翻去似瓢。", "幾度過秋生蘚暈，至今流潤應江潮。", "泫然疑有蛟龍吐，斷處人言霹靂焦。", "材大古來無適用，不須鬰鬰慕山苗。"]'),
('e25f84ec-653b-4647-a4eb-cc26c1e6a84a','寄題興州晁太守新開古東池','蘇軾','宋','宋诗','song-poetry','','[]','百畝清池傍郭斜，居人行樂路人誇。',64,'全唐诗/poet.song.44000.json','["百畝清池傍郭斜，居人行樂路人誇。", "自言官長如靈運，能使江山似永嘉。", "縱飲座中遺白帢，幽尋盡處見桃花。", "不堪山鳥號歸去，長遣王孫苦憶家。"]'),
('015afdc6-ba39-45f0-972e-096ae84cca57','和董傳留別','蘇軾','宋','宋诗','song-poetry','','["\u8bae\u8bba", "\u5199\u4eba", "\u9001\u522b", "\u4fee\u517b", "\u8bfb\u4e66"]','粗繒大布裹生涯，腹有詩書氣自華。',64,'全唐诗/poet.song.44000.json','["粗繒大布裹生涯，腹有詩書氣自華。", "厭伴老儒烹瓠葉，强隨舉子踏槐花。", "囊空不辦尋春馬，眼亂行看擇婿車。", "得意猶堪誇世俗，詔黄新濕字如鴉。"]'),
('830f8433-ad4d-4209-a121-1611d8969f1e','驪山三絕句  其一','蘇軾','宋','宋诗','song-poetry','','[]','功成惟欲善持盈，可歎前王恃太平。',32,'全唐诗/poet.song.44000.json','["功成惟欲善持盈，可歎前王恃太平。", "辛苦驪山山下土，阿房纔廢又華清。"]'),
('c1e324e1-5a9f-480b-b802-c032571ca516','驪山三絕句  其二','蘇軾','宋','宋诗','song-poetry','','[]','幾變雕牆幾變灰，舉烽指鹿事悠哉。',32,'全唐诗/poet.song.44000.json','["幾變雕牆幾變灰，舉烽指鹿事悠哉。", "上皇不念前車戒，却怨驪山是禍胎。"]'),
('4e49f21d-90d4-4cda-9084-bc9057b761d5','驪山三絕句  其三','蘇軾','宋','宋诗','song-poetry','','[]','海中方士覓三山，萬古明知去不還。',32,'全唐诗/poet.song.44000.json','["海中方士覓三山，萬古明知去不還。", "咫尺秦陵是商鑑，朝元何必苦躋攀。"]'),
('68e94062-f868-49b6-b2ea-3e0596065bfe','華陰寄子由','蘇軾','宋','宋诗','song-poetry','','[]','三年無日不思歸，夢裏還家旋覺非。',64,'全唐诗/poet.song.44000.json','["三年無日不思歸，夢裏還家旋覺非。", "臘酒送寒催去國，東風吹雪滿征衣。", "三峰已過天浮翠，四扇行看日照扉。", "里堠消磨不禁盡，速携家餉勞驂騑。"]'),
('9f08ecd4-293f-4876-be37-5883d98505ae','夜直祕閣呈王敏甫','蘇軾','宋','宋诗','song-poetry','','[]','蓬瀛宮闕隔埃氛，帝樂天香似許聞。',64,'全唐诗/poet.song.44000.json','["蓬瀛宮闕隔埃氛，帝樂天香似許聞。", "瓦弄寒暉鴛卧月，樓生晴靄鳳盤雲。", "共誰交臂論今古，只有閑心對此君。", "大隠本來無境界，北山猿鶴漫移文。"]'),
('8eef6705-e99c-4b65-87d5-111d7b7d981f','謝蘇自之惠酒','蘇軾','宋','宋诗','song-poetry','','[]','高士例須憐麴糵，此語常聞退之說。',224,'全唐诗/poet.song.44000.json','["高士例須憐麴糵，此語常聞退之說。", "我今有說殆不然，麴糵未必高士憐。", "醉者墜車莊生言，全酒未若全於天。", "達人本是不虧缺，何暇更求全處全。", "景山沉迷阮籍傲，畢卓盜竊劉伶顛。", "貪狂嗜怪無足取，世俗喜異矜其賢。", "杜陵詩客尤可笑，羅列八子參羣仙。", "流涎露頂置不說，爲問底處能逃禪。", "我今不飲非不飲，心月皎皎常孤圓。", "有時客至亦爲酌，琴雖未去聊忘絃。", "吾宗先生有深意，百里雙罌遠將寄。", "且言不飲固亦高，舉世皆同吾獨異。", "不如同異兩俱冥，得鹿亡羊等嬉戲。", "决須飲此勿復辭，何用區區較醒醉。"]'),
('8ca0d214-23c6-4003-bf73-3776147bbd3c','入館','蘇軾','宋','宋诗','song-poetry','','[]','黄省文書分道山，靜傳鐘鼓建章閑。',32,'全唐诗/poet.song.44000.json','["黄省文書分道山，靜傳鐘鼓建章閑。", "天邊玉樹西風起，知有新秋到世間。"]'),
('a97e7cbc-4b5b-4641-b209-cb72aac05894','贈蔡茂先','蘇軾','宋','宋诗','song-poetry','','[]','京城三日雨留人，吳市門前訪子真。',64,'全唐诗/poet.song.44000.json','["京城三日雨留人，吳市門前訪子真。", "赤脚長鬚俱好事，新詩軟語坐生春。", "鄴侯久有牙籤富，太史猶探禹穴新。", "不惜爲君揮尺素，却憂善守備三鄰。"]'),
('02a37af1-417a-4f30-8224-9706c2213e12','送任伋通判黄州兼寄其兄孜','蘇軾','宋','宋诗','song-poetry','','[]','吾州之豪任公子，少年盛壯日千里。',128,'全唐诗/poet.song.44000.json','["吾州之豪任公子，少年盛壯日千里。", "無媒自進誰識之，有才不用今老矣。", "別來十年學不厭，讀破萬卷詩愈美。", "黄州小郡夾溪谷，茅屋數家依竹葦。", "知命無憂子何病，見賢不薦誰當恥。", "平泉老令更可悲，六十青衫貧欲死。", "桐鄉遺老至今泣，潁川大姓誰能箠。", "因君寄聲問消息，莫對黄鷂矜爪觜。"]'),
('e60d2134-e2e6-4bc3-a393-9321d20d65f9','秀州僧本瑩靜照堂','蘇軾','宋','宋诗','song-poetry','','[]','鳥囚不忘飛，馬繫常念馳。',96,'全唐诗/poet.song.44000.json','["鳥囚不忘飛，馬繫常念馳。", "靜中不自勝，不若聽所之。", "君看厭事人，無事乃更悲。", "貧賤苦形勞，富貴嗟神疲。", "作堂名靜照，此語子爲誰。", "江湖隠淪士，豈無適時賢。", "老死不自惜，扁舟自娛嬉。", "從之恐莫見，況肯從我爲。"]'),
('51d7e91e-e0b2-40ec-80b1-f98538ade55e','石蒼舒醉墨堂','蘇軾','宋','宋诗','song-poetry','','[]','人生識字憂患始，姓名粗記可以休。',192,'全唐诗/poet.song.44000.json','["人生識字憂患始，姓名粗記可以休。", "何用草書誇神速，開卷惝怳令人愁。", "我嘗好之每自笑，君有此病何能瘳。", "自言其中有至樂，適意無異逍遥遊。", "近者作堂名醉墨，如飲美酒消百憂。", "乃知柳子語不妄，病嗜土炭如珍羞。", "君於此藝亦云至，堆牆敗筆如山丘。", "興來一揮百紙盡，駿馬倏忽踏九州。", "我書意造本無法，點畫信手煩推求。", "胡爲議論獨見假，隻字片紙皆藏收。", "不減鍾張君自足，下方羅趙我亦優。", "不須臨池更苦學，完取絹素充衾裯。"]'),
('5a69b22c-7c56-4015-a64e-bf403e04ee76','王頤赴建州錢監求詩及草書','蘇軾','宋','宋诗','song-poetry','','[]','我昔識子自武功，寒廳夜語樽酒同。',160,'全唐诗/poet.song.44000.json','["我昔識子自武功，寒廳夜語樽酒同。", "酒闌燭盡語不盡，倦僕立寐僵屏風。", "丁寧勸學不死訣，自言親受方瞳翁。", "嗟予聞道不早悟，醉夢顛倒隨盲聾。", "邇來憂患苦摧剝，意思蕭索如霜蓬。", "羨君顔色愈少壯，外慕漸少由中充。", "河車挽水灌腦黑，丹砂伏火入頰紅。", "大梁相逢又東去，但道何日辭樊籠。", "未能便乞勾漏令，官曹似是錫與銅。", "留詩河上慰離別，草書未暇緣匆匆。"]');
